  1ŌåÆimport * as Sentry from "@sentry/node";
  2ŌåÆimport { serve } from "@hono/node-server";
  3ŌåÆimport { createApp } from "./app";
  4ŌåÆimport { initDatabase, closeDatabase, DB_PATH } from "./lib/database";
  5ŌåÆimport { closeAll as closeAllWsConnections } from "./services/ws.service";
  6ŌåÆimport { ensureRelayConnected, disconnectFromRelay } from "./services/relay.service";
  7ŌåÆimport { getSetting } from "./services/settings.service";
  8ŌåÆimport * as agentService from "./services/agent";
  9ŌåÆimport { destroyAllPtySessions } from "./services/pty.service";
 10ŌåÆimport { destroyAllWatchers } from "./services/fs-watcher.service";
 11ŌåÆimport { setApp } from "./services/route-delegate";
 12ŌåÆimport { invalidate } from "./services/query-engine";
 13ŌåÆ
 14ŌåÆ// Initialize Sentry before anything else.
 15ŌåÆ// DSN passed as env var from Electron main process (not hardcoded ŌĆö open source repo).
 16ŌåÆif (process.env.SENTRY_DSN) {
 17ŌåÆ  Sentry.init({
 18ŌåÆ    dsn: process.env.SENTRY_DSN,
 19ŌåÆ    environment: process.env.NODE_ENV === "production" ? "production" : "development",
 20ŌåÆ    sendDefaultPii: false,
 21ŌåÆ    initialScope: { tags: { process: "backend" } },
 22ŌåÆ  });
 23ŌåÆ}
 24ŌåÆ
 25ŌåÆ/**
 26ŌåÆ * Deus Backend Server
 27ŌåÆ *
 28ŌåÆ * Handles workspace CRUD, sessions, repos, config, and stats.
 29ŌåÆ * Agent runtime (Claude SDK) is managed by the agent-server.
 30ŌåÆ */
 31ŌåÆ
 32ŌåÆ// Initialize database
 33ŌåÆconst db = initDatabase();
 34ŌåÆ
 35ŌåÆ// Backfill git_origin_url for repos added before we tracked origin URLs.
 36ŌåÆ// Runs once at startup (fire-and-forget) so WS subscribers get the data
 37ŌåÆ// on their first snapshot instead of waiting for GET /repos.
 38ŌåÆasync function backfillGitOriginUrls(): Promise<void> {
 39ŌåÆ  const { execFile } = await import("child_process");
 40ŌåÆ  const { promisify } = await import("util");
 41ŌåÆ  const execFileAsync = promisify(execFile);
 42ŌåÆ
 43ŌåÆ  try {
 44ŌåÆ    const nullUrlRepos = db
 45ŌåÆ      .prepare("SELECT id, root_path FROM repositories WHERE git_origin_url IS NULL")
 46ŌåÆ      .all() as { id: string; root_path: string }[];
 47ŌåÆ    if (nullUrlRepos.length === 0) return;
 48ŌåÆ
 49ŌåÆ    let updated = 0;
 50ŌåÆ    // Process in batches of 5 to cap concurrent git subprocesses
 51ŌåÆ    const BATCH_SIZE = 5;
 52ŌåÆ    for (let i = 0; i < nullUrlRepos.length; i += BATCH_SIZE) {
 53ŌåÆ      const batch = nullUrlRepos.slice(i, i + BATCH_SIZE);
 54ŌåÆ      const results = await Promise.allSettled(
 55ŌåÆ        batch.map(async (repo) => {
 56ŌåÆ          const { stdout } = await execFileAsync("git", ["remote", "get-url", "origin"], {
 57ŌåÆ            cwd: repo.root_path,
 58ŌåÆ            encoding: "utf-8",
 59ŌåÆ            timeout: 2000,
 60ŌåÆ          });
 61ŌåÆ          const url = stdout.trim();
 62ŌåÆ          if (url) {
 63ŌåÆ            db.prepare("UPDATE repositories SET git_origin_url = ? WHERE id = ?").run(url, repo.id);
 64ŌåÆ            return true;
 65ŌåÆ          }
 66ŌåÆ          return false;
 67ŌåÆ        })
 68ŌåÆ      );
 69ŌåÆ      updated += results.filter((r) => r.status === "fulfilled" && r.value).length;
 70ŌåÆ    }
 71ŌåÆ
 72ŌåÆ    // Push fresh data to WS subscribers so sidebar shows GitHub icons immediately
 73ŌåÆ    if (updated > 0) {
 74ŌåÆ      invalidate(["workspaces"]);
 75ŌåÆ    }
 76ŌåÆ  } catch {
 77ŌåÆ    // Backfill failed ŌĆö not critical, icons will appear after next workspace creation
 78ŌåÆ  }
 79ŌåÆ}
 80ŌåÆvoid backfillGitOriginUrls();
 81ŌåÆ
 82ŌåÆ// Create Hono app + WebSocket injector
 83ŌåÆconst { app, injectWebSocket } = createApp();
 84ŌåÆ
 85ŌåÆ// Register the Hono app for in-process route delegation (q:request/q:mutate ŌåÆ Hono routes)
 86ŌåÆsetApp(app);
 87ŌåÆ
 88ŌåÆ// Global variable to store actual port (used by health endpoint)
 89ŌåÆlet actualServerPort: number | null = null;
 90ŌåÆ
 91ŌåÆexport function getServerPort() {
 92ŌåÆ  return actualServerPort;
 93ŌåÆ}
 94ŌåÆ
 95ŌåÆ// Start server with dynamic port allocation
 96ŌåÆconst PORT = process.env.PORT ? parseInt(process.env.PORT) : 0;
 97ŌåÆ
 98ŌåÆ// Bind 0.0.0.0 to accept connections from all interfaces.
 99ŌåÆ// Remote access is gated by remoteGateMiddleware (rejects non-localhost when disabled).
100ŌåÆconst server = serve(
101ŌåÆ  {
102ŌåÆ    fetch: app.fetch,
103ŌåÆ    port: PORT,
104ŌåÆ    hostname: "0.0.0.0",
105ŌåÆ  },
106ŌåÆ  (info) => {
107ŌåÆ    actualServerPort = info.port;
108ŌåÆ
109ŌåÆ    // CRITICAL: Machine-readable port output for Electron main process and dev.sh
110ŌåÆ    console.log(`[BACKEND_PORT]${info.port}`);
111ŌåÆ
112ŌåÆ    console.log("\nDeus Backend Server");
113ŌåÆ    console.log(`API Server: http://0.0.0.0:${info.port}`);
114ŌåÆ    console.log(`Database: ${DB_PATH}`);
115ŌåÆ    console.log("Server ready!\n");
116ŌåÆ  }
117ŌåÆ);
118ŌåÆ
119ŌåÆ// Inject WebSocket support into the HTTP server
120ŌåÆinjectWebSocket(server);
121ŌåÆ
122ŌåÆconst remoteEnabled = getSetting("remote_access_enabled");
123ŌåÆif (remoteEnabled === true) {
124ŌåÆ  ensureRelayConnected();
125ŌåÆ}
126ŌåÆ
127ŌåÆ// Connect to agent-server.
128ŌåÆ//
129ŌåÆ// Two bootstrap paths:
130ŌåÆ// 1. AGENT_SERVER_URL is set (dev.sh): agent-server already running, connect directly.
131ŌåÆ// 2. AGENT_SERVER_BUNDLE_PATH is set (Electron): spawn agent-server as child process,
132ŌåÆ//    parse LISTEN_URL from its stdout, then connect.
133ŌåÆconst agentServerUrl = process.env.AGENT_SERVER_URL;
134ŌåÆconst agentServerBundlePath = process.env.AGENT_SERVER_BUNDLE_PATH;
135ŌåÆ
136ŌåÆif (agentServerUrl) {
137ŌåÆ  // Path 1: Direct connection (dev.sh spawned the agent-server externally)
138ŌåÆ  agentService.init(agentServerUrl);
139ŌåÆ} else if (agentServerBundlePath) {
140ŌåÆ  // Path 2: Spawn agent-server and connect (Electron desktop mode)
141ŌåÆ  void spawnAgentServerAndConnect(agentServerBundlePath);
142ŌåÆ}
143ŌåÆ
144ŌåÆ// Track agent-server child process for cleanup on shutdown
145ŌåÆlet agentServerChild: import("child_process").ChildProcess | null = null;
146ŌåÆ
147ŌåÆfunction killAgentServer(): void {
148ŌåÆ  if (agentServerChild && !agentServerChild.killed) {
149ŌåÆ    agentServerChild.kill("SIGTERM");
150ŌåÆ    agentServerChild = null;
151ŌåÆ  }
152ŌåÆ}
153ŌåÆ
154ŌåÆ/** Spawn the agent-server bundle as a child process and connect to its WebSocket. */
155ŌåÆasync function spawnAgentServerAndConnect(bundlePath: string): Promise<void> {
156ŌåÆ  const { spawn } = await import("child_process");
157ŌåÆ  const fs = await import("fs");
158ŌåÆ
159ŌåÆ  if (!fs.existsSync(bundlePath)) {
160ŌåÆ    console.error(`[server] Agent-server bundle not found: ${bundlePath}`);
161ŌåÆ    return;
162ŌåÆ  }
163ŌåÆ
164ŌåÆ  agentServerChild = spawn(process.execPath, [bundlePath], {
165ŌåÆ    stdio: ["ignore", "pipe", "pipe"],
166ŌåÆ    env: {
167ŌåÆ      ...process.env,
168ŌåÆ      // Forward database path so agent-server can pass it to agents
169ŌåÆ      DATABASE_PATH: process.env.DATABASE_PATH,
170ŌåÆ      // Forward notebook server path
171ŌåÆ      NOTEBOOK_SERVER_BUNDLE_PATH: process.env.NOTEBOOK_SERVER_BUNDLE_PATH,
172ŌåÆ    },
173ŌåÆ  });
174ŌåÆ
175ŌåÆ  const agentServer = agentServerChild!;
176ŌåÆ  let stdoutBuffer = "";
177ŌåÆ
178ŌåÆ  agentServer.stdout?.on("data", (data: Buffer) => {
179ŌåÆ    stdoutBuffer += data.toString();
180ŌåÆ    const lines = stdoutBuffer.split("\n");
181ŌåÆ    stdoutBuffer = lines.pop() ?? "";
182ŌåÆ
183ŌåÆ    for (const line of lines) {
184ŌåÆ      const trimmed = line.trim();
185ŌåÆ      if (!trimmed) continue;
186ŌåÆ      console.log("[agent-server]", trimmed);
187ŌåÆ
188ŌåÆ      // Capture the LISTEN_URL and connect
189ŌåÆ      if (trimmed.startsWith("LISTEN_URL=")) {
190ŌåÆ        const url = trimmed.slice("LISTEN_URL=".length);
191ŌåÆ        console.log(`[server] Agent-server spawned and listening at ${url}`);
192ŌåÆ        agentService.init(url);
193ŌåÆ      }
194ŌåÆ    }
195ŌåÆ  });
196ŌåÆ
197ŌåÆ  agentServer.stderr?.on("data", (data: Buffer) => {
198ŌåÆ    for (const line of data.toString().split("\n")) {
199ŌåÆ      if (line.trim()) console.error("[agent-server:stderr]", line.trim());
200ŌåÆ    }
201ŌåÆ  });
202ŌåÆ
203ŌåÆ  agentServer.on("exit", (code, signal) => {
204ŌåÆ    console.log(`[agent-server] Exited with code=${code} signal=${signal}`);
205ŌåÆ    agentServerChild = null;
206ŌåÆ  });
207ŌåÆ}
208ŌåÆ
209ŌåÆ// Global error handlers
