  1ŌåÆ/**
  2ŌåÆ * API Configuration
  3ŌåÆ * Central configuration for API endpoints and settings
  4ŌåÆ *
  5ŌåÆ * Port resolution:
  6ŌåÆ * - Electron app: Uses preload bridge via window.electronAPI.getBackendPort()
  7ŌåÆ * - Web dev: Uses VITE_BACKEND_PORT environment variable from dev.sh
  8ŌåÆ */
  9ŌåÆ
 10ŌåÆ// Import directly from the source module (not the barrel) to avoid circular
 11ŌåÆ// dependency: client.ts ŌåÆ api.config.ts ŌåÆ platform/electron/index.ts ŌåÆ ... ŌåÆ client.ts
 12ŌåÆimport { isElectronEnv } from "@/platform/electron/invoke";
 13ŌåÆ
 14ŌåÆlet cachedPort: number | null = null;
 15ŌåÆlet portPromise: Promise<number> | null = null;
 16ŌåÆ
 17ŌåÆ// IPC retry config for backend port resolution.
 18ŌåÆ// The backend may not have emitted its [BACKEND_PORT] marker yet during early
 19ŌåÆ// startup ŌĆö the main process waits for it before returning the port.
 20ŌåÆ// 30 attempts ├Ś 200ms = 6s covers the startup timeout with margin.
 21ŌåÆconst PORT_MAX_RETRIES = 30;
 22ŌåÆconst PORT_RETRY_DELAY_MS = 200;
 23ŌåÆ
 24ŌåÆ/**
 25ŌåÆ * Get the backend port (cached after first call).
 26ŌåÆ *
 27ŌåÆ * In Electron mode, retries the IPC call with backoff because the backend may
 28ŌåÆ * still be starting when the renderer first loads. Without retries, a single
 29ŌåÆ * failed invoke permanently caches port 3333, causing all API requests to
 30ŌåÆ * hit the wrong port and leaving the window hidden.
 31ŌåÆ */
 32ŌåÆexport async function getBackendPort(): Promise<number> {
 33ŌåÆ  if (cachedPort !== null) {
 34ŌåÆ    return cachedPort;
 35ŌåÆ  }
 36ŌåÆ
 37ŌåÆ  // If there's already a pending request, return it
 38ŌåÆ  if (portPromise !== null) {
 39ŌåÆ    return portPromise;
 40ŌåÆ  }
 41ŌåÆ
 42ŌåÆ  portPromise = (async () => {
 43ŌåÆ    // 1. Check if running in web dev mode with dynamic port
 44ŌåÆ    if (import.meta.env.VITE_BACKEND_PORT) {
 45ŌåÆ      const port = parseInt(import.meta.env.VITE_BACKEND_PORT as string, 10);
 46ŌåÆ      if (!isNaN(port)) {
 47ŌåÆ        if (import.meta.env.DEV) console.log(`[API] Using web dev backend port: ${port}`);
 48ŌåÆ        cachedPort = port;
 49ŌåÆ        return port;
 50ŌåÆ      }
 51ŌåÆ    }
 52ŌåÆ
 53ŌåÆ    // 2. Electron: use the dedicated preload API (bypasses generic invoke bridge).
 54ŌåÆ    // The backend is spawned by the main process before the window is created,
 55ŌåÆ    // so the port should be available immediately via native:getBackendPort.
 56ŌåÆ    // Retry with backoff for the rare case where the renderer loads before the
 57ŌåÆ    // backend has emitted its [BACKEND_PORT] marker.
 58ŌåÆ    if (isElectronEnv) {
 59ŌåÆ      for (let attempt = 0; attempt < PORT_MAX_RETRIES; attempt++) {
 60ŌåÆ        try {
 61ŌåÆ          const port = await window.electronAPI!.getBackendPort();
 62ŌåÆ          if (import.meta.env.DEV)
 63ŌåÆ            console.log(`[API] Using Electron backend port: ${port} (attempt ${attempt + 1})`);
 64ŌåÆ          cachedPort = port;
 65ŌåÆ          return port;
 66ŌåÆ        } catch {
 67ŌåÆ          if (attempt < PORT_MAX_RETRIES - 1) {
 68ŌåÆ            await new Promise((resolve) => setTimeout(resolve, PORT_RETRY_DELAY_MS));
 69ŌåÆ          }
 70ŌåÆ        }
 71ŌåÆ      }
 72ŌåÆ      // All retries exhausted ŌĆö don't cache a wrong port. Throw so TanStack Query
 73ŌåÆ      // retries the entire fetch later, giving the backend more time to start.
 74ŌåÆ      console.error("[API] getBackendPort failed after retries ŌĆö backend may not have started");
 75ŌåÆ      throw new Error("Backend port not available after retries");
 76ŌåÆ    }
 77ŌåÆ
 78ŌåÆ    // 3. Dev mode: fetch port from Vite middleware (Electron writes it to temp file).
 79ŌåÆ    // This enables Chrome tabs at localhost:1420 to work during `bun run dev`.
 80ŌåÆ    if (import.meta.env.DEV) {
 81ŌåÆ      try {
 82ŌåÆ        const res = await fetch("/__backend_port");
 83ŌåÆ        if (res.ok) {
 84ŌåÆ          const data = await res.json();
 85ŌåÆ          if (data.port && typeof data.port === "number") {
 86ŌåÆ            console.log(`[API] Using backend port from dev server: ${data.port}`);
 87ŌåÆ            cachedPort = data.port;
 88ŌåÆ            return data.port;
 89ŌåÆ          }
 90ŌåÆ        }
 91ŌåÆ      } catch {
 92ŌåÆ        // Vite middleware not available
 93ŌåÆ      }
 94ŌåÆ    }
 95ŌåÆ
 96ŌåÆ    // 4. Last resort fallback ŌĆö do NOT cache so retries re-resolve
 97ŌåÆ    // (e.g. user clicks Retry after backend finishes starting)
 98ŌåÆ    console.warn("[API] No port source available, falling back to default port 3333");
 99ŌåÆ    return 3333;
100ŌåÆ  })();
101ŌåÆ
102ŌåÆ  // Clear promise when done (success or failure)
103ŌåÆ  portPromise.finally(() => {
104ŌåÆ    portPromise = null;
