#!/usr/bin/env node

/**
 * Deus CLI ŌĆö run Deus IDE from the command line.
 *
 * Usage:
 *   deus                    Start headless server (backend + agent-server + web UI)
 *   deus serve              Same as above (explicit)
 *   deus serve --port 8080  Run on a specific port
 *   deus desktop            Download and install the desktop Electron app
 */

import { parseArgs } from "node:util";
import { serve } from "./serve.js";
import { installDesktop } from "./desktop.js";

const HELP = `
  Deus IDE ŌĆö AI-powered IDE for managing multiple parallel coding agents

  Usage:
    deus [command] [options]

  Commands:
    serve       Start headless server with web UI (default)
    desktop     Download and install the desktop app

  Options (serve):
    --port, -p <port>     Port for the web UI (default: 3000)
    --host <host>         Host to bind to (default: localhost)
    --open                Open browser after starting
    --data-dir <path>     Directory for database and data files

  Options (desktop):
    --version <version>   Specific version to install (default: latest)

  Examples:
    deus                  Start server on http://localhost:3000
    deus serve -p 8080    Start server on port 8080
    deus desktop          Install the desktop app
`;

async function main() {
  const args = process.argv.slice(2);
  const command = args[0] && !args[0].startsWith("-") ? args[0] : "serve";
  const commandArgs = command === args[0] ? args.slice(1) : args;

  if (command === "help" || args.includes("--help") || args.includes("-h")) {
    console.log(HELP);
    process.exit(0);
  }

  if (args.includes("--version") && command !== "desktop") {
    const pkg = await import("../package.json", { with: { type: "json" } });
    console.log(pkg.default.version);
    process.exit(0);
  }

  switch (command) {
    case "serve": {
      const { values } = parseArgs({
        args: commandArgs,
        options: {
          port: { type: "string", short: "p", default: "3000" },
          host: { type: "string", default: "localhost" },
          open: { type: "boolean", default: false },
          "data-dir": { type: "string" },
        },
        strict: false,
      });

      await serve({
        port: parseInt(values.port as string, 10),
        host: values.host as string,
        open: values.open as boolean,
        dataDir: values["data-dir"] as string | undefined,
      });
      break;
    }

    case "desktop": {
      const { values } = parseArgs({
        args: commandArgs,
        options: {
          version: { type: "string", default: "latest" },
        },
        strict: false,
      });

      await installDesktop({ version: values.version as string });
      break;
    }

    default:
      console.error(`Unknown command: ${command}`);
      console.log(HELP);
      process.exit(1);
  }
}

main().catch((err) => {
  console.error("Fatal error:", err);
  process.exit(1);
});

