      name: "agent-server bundle",
      required: true,
    },
    {
      src: join(monorepoRoot, "apps/backend/dist/server.bundled.cjs"),
      dest: join(bundlesDir, "server.bundled.cjs"),
      name: "backend bundle",
      required: true,
    },
    {
      src: join(monorepoRoot, "apps/web/dist/web"),
      dest: join(bundlesDir, "web"),
      name: "frontend build",
      required: false,
    },
  ];

  let hasErrors = false;
  for (const copy of copies) {
    if (existsSync(copy.src)) {
      cpSync(copy.src, copy.dest, { recursive: true });
      console.log(`   Ō£ō ${copy.name}`);
    } else if (copy.required) {
      console.error(`   Ō£Ś ${copy.name} not found: ${copy.src}`);
      hasErrors = true;
    } else {
      console.log(`   - ${copy.name} not found (optional, server will work without UI)`);
    }
  }

  if (hasErrors) {
    console.error("\nMissing required bundles. Run these first:");
    console.error("  bun run build:agent-server");
    console.error("  bun run build:backend");
    console.error("  bun run build:web  (optional, for web UI)");
    process.exit(1);
  }

  // Step 4: Generate a standalone package.json for the published CLI
  console.log("\n4. Generating publish-ready package.json...");
  const pkg = JSON.parse(readFileSync(join(cliDir, "package.json"), "utf-8"));
  // Ensure we don't ship "private: true" or monorepo-specific fields
  delete pkg.scripts;
  pkg.main = "dist/cli.js";
  pkg.type = "module";
  // Note: we don't overwrite ŌĆö the original is fine for publishing

  console.log("\nŌ£ō Build complete!");
  console.log(`  CLI: ${join(cliDir, "dist/cli.js")}`);
  console.log(`  Bin: ${join(cliDir, "bin/deus.js")}`);
  console.log(`  Bundles: ${bundlesDir}`);
  console.log("\nTo test locally:");
  console.log("  node packages/cli/bin/deus.js serve");
  console.log("\nTo publish:");
  console.log("  cd packages/cli && npm publish");
}

main().catch((err) => {
  console.error("Build failed:", err);
  process.exit(1);
});

