 35ŌåÆ// Backfill git_origin_url for repos added before we tracked origin URLs.
 36ŌåÆ// Runs once at startup (fire-and-forget) so WS subscribers get the data
 37ŌåÆ// on their first snapshot instead of waiting for GET /repos.
 38ŌåÆasync function backfillGitOriginUrls(): Promise<void> {
 39ŌåÆ  const { execFile } = await import("child_process");
 40ŌåÆ  const { promisify } = await import("util");
 41ŌåÆ  const execFileAsync = promisify(execFile);
 42ŌåÆ
 43ŌåÆ  try {
 44ŌåÆ    const nullUrlRepos = db
 45ŌåÆ      .prepare("SELECT id, root_path FROM repositories WHERE git_origin_url IS NULL")
 46ŌåÆ      .all() as { id: string; root_path: string }[];
 47ŌåÆ    if (nullUrlRepos.length === 0) return;
 48ŌåÆ
 49ŌåÆ    let updated = 0;
 50ŌåÆ    // Process in batches of 5 to cap concurrent git subprocesses
 51ŌåÆ    const BATCH_SIZE = 5;
 52ŌåÆ    for (let i = 0; i < nullUrlRepos.length; i += BATCH_SIZE) {
 53ŌåÆ      const batch = nullUrlRepos.slice(i, i + BATCH_SIZE);
 54ŌåÆ      const results = await Promise.allSettled(
 55ŌåÆ        batch.map(async (repo) => {
 56ŌåÆ          const { stdout } = await execFileAsync("git", ["remote", "get-url", "origin"], {
 57ŌåÆ            cwd: repo.root_path,
 58ŌåÆ            encoding: "utf-8",
 59ŌåÆ            timeout: 2000,
 60ŌåÆ          });
 61ŌåÆ          const url = stdout.trim();
 62ŌåÆ          if (url) {
 63ŌåÆ            db.prepare("UPDATE repositories SET git_origin_url = ? WHERE id = ?").run(url, repo.id);
 64ŌåÆ            return true;
 65ŌåÆ          }
 66ŌåÆ          return false;
 67ŌåÆ        })
 68ŌåÆ      );
 69ŌåÆ      updated += results.filter((r) => r.status === "fulfilled" && r.value).length;
 70ŌåÆ    }
 71ŌåÆ
 72ŌåÆ    // Push fresh data to WS subscribers so sidebar shows GitHub icons immediately
 73ŌåÆ    if (updated > 0) {
 74ŌåÆ      invalidate(["workspaces"]);
 75ŌåÆ    }
 76ŌåÆ  } catch {
 77ŌåÆ    // Backfill failed ŌĆö not critical, icons will appear after next workspace creation
 78ŌåÆ  }
 79ŌåÆ}
