 47ŌåÆexport const logFilePath = `/tmp/deus-${process.pid}.log`;
 48ŌåÆconst originalLog = console.log;
 49ŌåÆ
 50ŌåÆconst LOG_LEVEL = (process.env.LOG_LEVEL || "info") as "debug" | "info" | "error";
 51ŌåÆconst LOG_LEVELS = { debug: 0, info: 1, error: 2 };
 52ŌåÆ
 53ŌåÆfunction shouldLog(level: "debug" | "info" | "error"): boolean {
 54ŌåÆ  return LOG_LEVELS[level] >= LOG_LEVELS[LOG_LEVEL];
 55ŌåÆ}
 56ŌåÆ
 57ŌåÆfunction formatLogArgs(args: any[]): string {
 58ŌåÆ  return args
 59ŌåÆ    .map((arg) => {
 60ŌåÆ      if (typeof arg === "string") return arg;
 61ŌåÆ      if (arg instanceof Error) return `${arg.message}\n${arg.stack || ""}`;
 62ŌåÆ      return util.inspect(arg, { depth: 4, breakLength: Infinity });
 63ŌåÆ    })
 64ŌåÆ    .join(" ");
 65ŌåÆ}
 66ŌåÆ
 67ŌåÆ// Buffered log writer -- avoids synchronous appendFileSync on every log call
 68ŌåÆlet logBuffer = "";
 69ŌåÆlet flushTimer: NodeJS.Timeout | null = null;
 70ŌåÆ
 71ŌåÆfunction flushLogs(): void {
 72ŌåÆ  if (logBuffer) {
 73ŌåÆ    fs.appendFileSync(logFilePath, logBuffer);
 74ŌåÆ    logBuffer = "";
 75ŌåÆ  }
 76ŌåÆ  flushTimer = null;
 77ŌåÆ}
 78ŌåÆ
 79ŌåÆfunction writeLog(line: string): void {
 80ŌåÆ  logBuffer += line;
 81ŌåÆ  if (!flushTimer) {
 82ŌåÆ    flushTimer = setTimeout(flushLogs, 100);
 83ŌåÆ  }
 84ŌåÆ  if (logBuffer.length > 8192) {
 85ŌåÆ    flushLogs();
 86ŌåÆ  }
 87ŌåÆ}
 88ŌåÆ
 89ŌåÆ// Ensure logs are flushed on shutdown
 90ŌåÆprocess.on("exit", flushLogs);
 91ŌåÆ
 92ŌåÆconsole.log = (...args: any[]) => {
 93ŌåÆ  if (!shouldLog("info")) return;
 94ŌåÆ  const timestamp = new Date().toISOString();
 95ŌåÆ  writeLog(`[${timestamp}] ${formatLogArgs(args)}\n`);
 96ŌåÆ};
 97ŌåÆ
 98ŌåÆconsole.error = (...args: any[]) => {
 99ŌåÆ  const timestamp = new Date().toISOString();
100ŌåÆ  writeLog(`[${timestamp}] ERROR: ${formatLogArgs(args)}\n`);
101ŌåÆ};
102ŌåÆ
103ŌåÆconsole.debug = (...args: any[]) => {
104ŌåÆ  if (!shouldLog("debug")) return;
105ŌåÆ  const timestamp = new Date().toISOString();
106ŌåÆ  writeLog(`[${timestamp}] DEBUG: ${formatLogArgs(args)}\n`);
107ŌåÆ};
