113ŌåÆclass AgentServer {
114ŌåÆ  private initializedAgents = new Set<string>();
115ŌåÆ  private httpServer: ReturnType<typeof createHttpServer> | null = null;
116ŌåÆ  private wss: WebSocketServer | null = null;
117ŌåÆ
118ŌåÆ  constructor() {
119ŌåÆ    console.log("AgentServer: Initializing...");
120ŌåÆ
121ŌåÆ    // Graceful shutdown handlers ŌĆö drain in-flight turns before exiting
122ŌåÆ    const gracefulShutdown = async (signal: string) => {
123ŌåÆ      console.log(`\n[SIGNAL] Received ${signal}, shutting down gracefully...`);
124ŌåÆ
125ŌåÆ      // 1. Stop accepting new turn/start requests
126ŌåÆ      setShuttingDown(true);
127ŌåÆ
128ŌåÆ      // 2. Stop accepting new WS connections (close the HTTP listener)
129ŌåÆ      if (this.httpServer) {
130ŌåÆ        this.httpServer.close();
131ŌåÆ        console.log("[SHUTDOWN] HTTP server closed to new connections");
132ŌåÆ      }
133ŌåÆ
134ŌåÆ      // 3. Wait for in-flight turns to drain (default 30s timeout)
135ŌåÆ      console.log("[SHUTDOWN] Waiting for in-flight turns to drain...");
136ŌåÆ      const drained = await waitForDrain();
137ŌåÆ      if (drained) {
138ŌåÆ        console.log("[SHUTDOWN] All turns drained successfully");
139ŌåÆ      } else {
140ŌåÆ        console.log("[SHUTDOWN] Drain timeout reached, cancelling remaining sessions");
141ŌåÆ        await cancelRemainingSessions();
142ŌåÆ      }
143ŌåÆ
144ŌåÆ      // 4. Full cleanup (kill child processes, close WS clients)
145ŌåÆ      try {
146ŌåÆ        await this.cleanup();
147ŌåÆ        console.log("[SIGNAL] Cleanup complete, exiting process");
148ŌåÆ      } catch (error) {
149ŌåÆ        console.error("[SIGNAL] Cleanup failed:", error);
150ŌåÆ      } finally {
151ŌåÆ        process.exit(0);
152ŌåÆ      }
153ŌåÆ    };
154ŌåÆ    process.on("SIGINT", () => gracefulShutdown("SIGINT"));
155ŌåÆ    process.on("SIGTERM", () => gracefulShutdown("SIGTERM"));
156ŌåÆ  }
