158ŌåÆ  /**
159ŌåÆ   * Wires up all JSON-RPC methods and notifications on a new connection.
160ŌåÆ   */
161ŌåÆ  private setupJsonRpc(rpcTunnel: RpcConnection): void {
162ŌåÆ    EventBroadcaster.attachTunnel(rpcTunnel);
163ŌåÆ
164ŌåÆ    // --- Initialize handshake (backend agent-client sends this) ---
165ŌåÆ    rpcTunnel.addMethod("initialize", () => {
166ŌåÆ      const agents = [];
167ŌåÆ      for (const [agentType, handler] of [
168ŌåÆ        ["claude", getAgent("claude")],
169ŌåÆ        ["codex", getAgent("codex")],
170ŌåÆ      ] as const) {
171ŌåÆ        if (handler && this.initializedAgents.has(agentType)) {
172ŌåÆ          agents.push({
173ŌåÆ            type: agentType,
174ŌåÆ            capabilities: handler.capabilities,
175ŌåÆ            initialized: true,
176ŌåÆ          });
177ŌåÆ        }
178ŌåÆ      }
179ŌåÆ      return { version: "1.0", agents };
180ŌåÆ    });
181ŌåÆ
182ŌåÆ    // --- Initialized notification (backend confirms handshake) ---
183ŌåÆ    rpcTunnel.addMethod("initialized", () => {
184ŌåÆ      console.log("[RPC] Backend handshake complete (initialized)");
185ŌåÆ      return undefined;
186ŌåÆ    });
187ŌåÆ
188ŌåÆ    // --- turn/start (new wire protocol method, maps to query dispatch) ---
189ŌåÆ    rpcTunnel.addMethod("turn/start", async (params: any) => {
190ŌåÆ      const sessionId = params?.sessionId;
191ŌåÆ      const agentType = params?.agentType || "claude";
192ŌåÆ      const prompt = params?.prompt;
193ŌåÆ      const options = params?.options || {};
194ŌåÆ
195ŌåÆ      // Reject new turns during shutdown
196ŌåÆ      if (isShuttingDown()) {
197ŌåÆ        return { accepted: false, reason: "shutting down" };
198ŌåÆ      }
199ŌåÆ
200ŌåÆ      if (!sessionId || !prompt) {
201ŌåÆ        return { accepted: false, reason: "turn/start requires sessionId and prompt" };
202ŌåÆ      }
203ŌåÆ
204ŌåÆ      const agent = getAgent(agentType);
205ŌåÆ      if (!agent) {
206ŌåÆ        return { accepted: false, reason: `No agent registered for type: ${agentType}` };
207ŌåÆ      }
208ŌåÆ
209ŌåÆ      // Track this session for graceful shutdown draining
210ŌåÆ      trackSession(sessionId, agentType);
211ŌåÆ
212ŌåÆ      agent
213ŌåÆ        .query(sessionId, prompt, options)
214ŌåÆ        .catch((err) => {
215ŌåÆ          console.error(`[turn/start] Unhandled error in ${agentType} query:`, err);
216ŌåÆ          const classified = classifyError(err);
217ŌåÆ          EventBroadcaster.sendError({
218ŌåÆ            id: sessionId,
219ŌåÆ            type: "error",
220ŌåÆ            error: classified.message,
221ŌåÆ            agentType,
222ŌåÆ            category: classified.category,
223ŌåÆ          });
224ŌåÆ          EventBroadcaster.emitSessionError(
225ŌåÆ            sessionId,
226ŌåÆ            agentType,
227ŌåÆ            classified.message,
228ŌåÆ            classified.category
229ŌåÆ          );
230ŌåÆ        })
231ŌåÆ        .finally(() => {
232ŌåÆ          // Untrack when the turn completes (success, error, or cancel)
233ŌåÆ          untrackSession(sessionId);
234ŌåÆ        });
235ŌåÆ
236ŌåÆ      EventBroadcaster.emitSessionStarted(sessionId, agentType);
237ŌåÆ
238ŌåÆ      console.log(`[TIMING][turn/start] DISPATCHED session=${sessionId}`);
239ŌåÆ      return { accepted: true };
240ŌåÆ    });
241ŌåÆ
242ŌåÆ    // --- turn/respond (tool relay response from backend) ---
243ŌåÆ    // Currently a stub: the agent-server tools use direct JSON-RPC requests
244ŌåÆ    // (EventBroadcaster.requestBrowserXxx) rather than the canonical
245ŌåÆ    // tool.request notification path. When tools migrate to the canonical
246ŌåÆ    // path, this handler will resolve pending promises by requestId.
247ŌåÆ    rpcTunnel.addMethod("turn/respond", (params: any) => {
248ŌåÆ      const { requestId } = params ?? {};
249ŌåÆ      console.log(`[AgentServer] turn/respond received (requestId=${requestId})`);
250ŌåÆ    });
251ŌåÆ
252ŌåÆ    // --- turn/cancel (new wire protocol method, maps to cancel dispatch) ---
253ŌåÆ    rpcTunnel.addMethod("turn/cancel", async (params: any) => {
254ŌåÆ      const sessionId = params?.sessionId;
255ŌåÆ      if (!sessionId) return;
256ŌåÆ
257ŌåÆ      // Try all registered agents ŌĆö the backend may not send agentType for cancel
258ŌåÆ      for (const agentType of ["claude", "codex"] as const) {
259ŌåÆ        const agent = getAgent(agentType);
260ŌåÆ        if (agent) void agent.cancel(sessionId);
261ŌåÆ      }
262ŌåÆ    });
263ŌåÆ
264ŌåÆ    // --- session/reset (new wire protocol method) ---
265ŌåÆ    rpcTunnel.addMethod("session/reset", (params: any) => {
266ŌåÆ      const sessionId = params?.sessionId;
267ŌåÆ      if (!sessionId) return;
268ŌåÆ
269ŌåÆ      for (const agentType of ["claude", "codex"] as const) {
270ŌåÆ        const agent = getAgent(agentType);
271ŌåÆ        if (agent) agent.reset(sessionId);
272ŌåÆ      }
273ŌåÆ    });
274ŌåÆ
275ŌåÆ    // --- session/stop (stop a running session) ---
276ŌåÆ    rpcTunnel.addMethod("session/stop", async (params: any) => {
277ŌåÆ      const sessionId = params?.sessionId;
278ŌåÆ      if (!sessionId) return;
279ŌåÆ
280ŌåÆ      for (const agentType of ["claude", "codex"] as const) {
281ŌåÆ        const agent = getAgent(agentType);
282ŌåÆ        if (agent) void agent.cancel(sessionId);
283ŌåÆ      }
284ŌåÆ    });
285ŌåÆ
286ŌåÆ    // --- provider/auth (check agent authentication) ---
287ŌåÆ    rpcTunnel.addMethod("provider/auth", async (params: any) => {
288ŌåÆ      const agentType = params?.agentType || "claude";
289ŌåÆ      const agent = getAgent(agentType);
290ŌåÆ      if (!agent?.auth) throw new Error(`Agent "${agentType}" does not support auth`);
291ŌåÆ      return agent.auth({ cwd: params?.cwd });
292ŌåÆ    });
293ŌåÆ
294ŌåÆ    // --- provider/initWorkspace (slash commands, MCP servers) ---
295ŌåÆ    rpcTunnel.addMethod("provider/initWorkspace", async (params: any) => {
296ŌåÆ      const agentType = params?.agentType || "claude";
297ŌåÆ      const agent = getAgent(agentType);
298ŌåÆ      if (!agent?.initWorkspace)
299ŌåÆ        throw new Error(`Agent "${agentType}" does not support workspace init`);
300ŌåÆ      return agent.initWorkspace({
301ŌåÆ        cwd: params?.cwd,
302ŌåÆ        ghToken: params?.ghToken,
303ŌåÆ        providerEnvVars: params?.providerEnvVars,
304ŌåÆ      });
305ŌåÆ    });
306ŌåÆ
307ŌåÆ    // --- provider/contextUsage (token usage stats) ---
308ŌåÆ    rpcTunnel.addMethod("provider/contextUsage", async (params: any) => {
309ŌåÆ      const agentType = params?.agentType || "claude";
310ŌåÆ      const agent = getAgent(agentType);
311ŌåÆ      if (!agent?.getContextUsage)
312ŌåÆ        throw new Error(`Agent "${agentType}" does not support context usage`);
313ŌåÆ      return agent.getContextUsage({
314ŌåÆ        options: {
315ŌåÆ          cwd: params?.cwd ?? "",
316ŌåÆ          agentSessionId: params?.agentSessionId ?? "",
317ŌåÆ        },
318ŌåÆ      });
319ŌåÆ    });
320ŌåÆ
321ŌåÆ    // --- provider/updateMode (runtime permission mode change) ---
322ŌåÆ    rpcTunnel.addMethod("provider/updateMode", (params: any) => {
323ŌåÆ      const agentType = params?.agentType || "claude";
324ŌåÆ      const agent = getAgent(agentType);
325ŌåÆ      if (agent?.updatePermissionMode) {
326ŌåÆ        void agent.updatePermissionMode(params?.sessionId, params?.permissionMode);
327ŌåÆ      }
328ŌåÆ    });
329ŌåÆ
330ŌåÆ    // --- agent/list (introspection: list available agents) ---
331ŌåÆ    rpcTunnel.addMethod("agent/list", () => {
332ŌåÆ      const agents = [];
333ŌåÆ      for (const [agentType, handler] of [
334ŌåÆ        ["claude", getAgent("claude")],
335ŌåÆ        ["codex", getAgent("codex")],
336ŌåÆ      ] as const) {
337ŌåÆ        if (handler && this.initializedAgents.has(agentType)) {
338ŌåÆ          agents.push({ type: agentType, capabilities: handler.capabilities });
339ŌåÆ        }
340ŌåÆ      }
341ŌåÆ      return { agents };
342ŌåÆ    });
343ŌåÆ  }
344ŌåÆ
345ŌåÆ  /**
346ŌåÆ   * Handles a new WebSocket connection.
347ŌåÆ   * Each WS text frame is a complete JSON-RPC message (no line splitting needed).
348ŌåÆ   */
349ŌåÆ  private handleWsConnection(ws: WebSocket): void {
350ŌåÆ    console.log("Client connected (ws)");
351ŌåÆ    const transport = wsTransport(ws);
352ŌåÆ    const rpcTunnel = new RpcConnection(transport);
353ŌåÆ    this.setupJsonRpc(rpcTunnel);
354ŌåÆ
355ŌåÆ    ws.on("message", (data: Buffer | string) => {
356ŌåÆ      const message = typeof data === "string" ? data : data.toString("utf8");
357ŌåÆ      console.debug("Received WS message with length", message.length);
358ŌåÆ      rpcTunnel.handleMessage(message);
359ŌåÆ    });
360ŌåÆ
361ŌåÆ    ws.on("error", (error: Error) => {
362ŌåÆ      console.error("WebSocket error:", error);
363ŌåÆ    });
364ŌåÆ
365ŌåÆ    ws.on("close", (code: number, reason: Buffer) => {
366ŌåÆ      console.log(`Client disconnected (ws), code=${code} reason=${reason.toString()}`);
367ŌåÆ      rpcTunnel.stop();
368ŌåÆ      EventBroadcaster.detachTunnel(rpcTunnel);
369ŌåÆ    });
370ŌåÆ  }
