372ŌåÆ  // ==========================================================================
373ŌåÆ  // Lifecycle
374ŌåÆ  // ==========================================================================
375ŌåÆ
376ŌåÆ  /**
377ŌåÆ   * Kills any remaining Claude child processes spawned by this agent-server.
378ŌåÆ   */
379ŌåÆ  private async killRemainingChildProcesses(): Promise<void> {
380ŌåÆ    return new Promise((resolve) => {
381ŌåÆ      const command = `/usr/bin/pgrep -P ${process.pid}`;
382ŌåÆ      exec(command, (error, stdout) => {
383ŌåÆ        if (error) {
384ŌåÆ          console.log("[CLEANUP] No child processes found");
385ŌåÆ          resolve();
386ŌåÆ          return;
387ŌåÆ        }
388ŌåÆ        const childPids = stdout
389ŌåÆ          .trim()
390ŌåÆ          .split("\n")
391ŌåÆ          .filter((pid) => pid);
392ŌåÆ        if (childPids.length === 0) {
393ŌåÆ          console.log("[CLEANUP] No child processes to kill");
394ŌåÆ          resolve();
395ŌåÆ          return;
396ŌåÆ        }
397ŌåÆ        console.log(`[CLEANUP] Found ${childPids.length} child processes: ${childPids.join(", ")}`);
398ŌåÆ        childPids.forEach((pid) => {
399ŌåÆ          try {
400ŌåÆ            process.kill(Number(pid), "SIGTERM");
401ŌåÆ            console.log(`[CLEANUP] Sent SIGTERM to child PID ${pid}`);
402ŌåÆ          } catch (e) {
403ŌåÆ            const errorMsg = getErrorMessage(e);
404ŌåÆ            console.log(`[CLEANUP] Failed to kill child PID ${pid}: ${errorMsg}`);
405ŌåÆ          }
406ŌåÆ        });
407ŌåÆ        resolve();
408ŌåÆ      });
409ŌåÆ    });
410ŌåÆ  }
411ŌåÆ
412ŌåÆ  private async cleanup(): Promise<void> {
413ŌåÆ    await this.killRemainingChildProcesses();
414ŌåÆ
415ŌåÆ    if (this.wss) {
416ŌåÆ      for (const client of this.wss.clients) {
417ŌåÆ        client.close(1001, "Server shutting down");
