 50ŌåÆ  const agentServerPath = app.isPackaged
 51ŌåÆ    ? join(process.resourcesPath, "bin", "index.bundled.cjs")
 52ŌåÆ    : join(projectRoot, "apps/agent-server/dist/index.bundled.cjs");
 53ŌåÆ
 54ŌåÆ  // Notebook server bundle path
 55ŌåÆ  const notebookPath = app.isPackaged
 56ŌåÆ    ? join(process.resourcesPath, "bin", "notebook-server.bundled.cjs")
 57ŌåÆ    : join(projectRoot, "packages/mcp-notebook/dist/notebook-server.bundled.cjs");
 58ŌåÆ
 59ŌåÆ  return new Promise((resolve, reject) => {
 60ŌåÆ    backendProcess = spawn(backendRuntime, [backendEntry], {
 61ŌåÆ      cwd: app.isPackaged ? process.resourcesPath : join(projectRoot, "apps/backend"),
 62ŌåÆ      env: {
 63ŌåÆ        ...process.env,
 64ŌåÆ        ELECTRON_RUN_AS_NODE: "1",
 65ŌåÆ        DATABASE_PATH: dbPath,
 66ŌåÆ        AGENT_SERVER_BUNDLE_PATH: agentServerPath,
 67ŌåÆ        NOTEBOOK_SERVER_BUNDLE_PATH: notebookPath,
 68ŌåÆ        AUTH_TOKEN: authToken,
 69ŌåÆ        PORT: "0", // Dynamic port allocation
 70ŌåÆ        CDP_PORT, // Chrome DevTools Protocol port for agent-browser integration
 71ŌåÆ      },
 72ŌåÆ      stdio: ["ignore", "pipe", "pipe"],
 73ŌåÆ    });
 74ŌåÆ
 75ŌåÆ    let resolved = false;
