 84ŌåÆ        const trimmed = line.trim();
 85ŌåÆ        if (!trimmed) continue;
 86ŌåÆ
 87ŌåÆ        // Log backend stdout in dev mode
 88ŌåÆ        if (!app.isPackaged) {
 89ŌåÆ          console.log("[backend]", trimmed);
 90ŌåÆ        }
 91ŌåÆ
 92ŌåÆ        const portMatch = trimmed.match(/^\[BACKEND_PORT\](\d+)$/);
 93ŌåÆ        if (portMatch && !resolved) {
 94ŌåÆ          resolved = true;
 95ŌåÆ          restartAttempt = 0;
 96ŌåÆ          const port = parseInt(portMatch[1], 10);
 97ŌåÆ
