100ŌåÆ          if (!app.isPackaged) {
101ŌåÆ            try {
102ŌåÆ              const portFile = join(app.getPath("temp"), "deus-backend-port");
103ŌåÆ              writeFileSync(portFile, String(port));
104ŌåÆ            } catch {
105ŌåÆ              // Non-critical ŌĆö only used for Chrome tab port discovery
106ŌåÆ            }
107ŌåÆ          }
108ŌåÆ
109ŌåÆ          resolve({ port, authToken });
110ŌåÆ        }
111ŌåÆ
112ŌåÆ        // Relay workspace init progress events to the renderer.
113ŌåÆ        // Backend emits: DEUS_WORKSPACE_PROGRESS:{"workspaceId":"...","step":"...","label":"..."}
114ŌåÆ        // We parse the JSON and forward it as an IPC event to the renderer.
115ŌåÆ        // SYNC: Event name must match shared/events.ts (AppEventMap["workspace:progress"])
116ŌåÆ        if (trimmed.startsWith("DEUS_WORKSPACE_PROGRESS:")) {
117ŌåÆ          const jsonStr = trimmed.slice("DEUS_WORKSPACE_PROGRESS:".length);
118ŌåÆ          try {
119ŌåÆ            const payload = JSON.parse(jsonStr);
120ŌåÆ            const win = BrowserWindow.getAllWindows()[0];
121ŌåÆ            if (win) {
122ŌåÆ              win.webContents.send("workspace:progress", payload);
123ŌåÆ            }
124ŌåÆ          } catch {
125ŌåÆ            // Ignore malformed progress lines
126ŌåÆ          }
127ŌåÆ        }
128ŌåÆ      }
129ŌåÆ    });
130ŌåÆ
131ŌåÆ    backendProcess.stderr?.on("data", (data: Buffer) => {
132ŌåÆ      console.error("[backend:stderr]", data.toString().trim());
133ŌåÆ    });
134ŌåÆ
135ŌåÆ    backendProcess.on("exit", (code, signal) => {
136ŌåÆ      console.log(`[backend] Exited with code=${code} signal=${signal}`);
137ŌåÆ      backendProcess = null;
138ŌåÆ
139ŌåÆ      if (!resolved) {
140ŌåÆ        reject(new Error(`Backend exited before starting (code=${code})`));
141ŌåÆ        return;
142ŌåÆ      }
143ŌåÆ
144ŌåÆ      // Restart with exponential backoff (unless app is quitting)
145ŌåÆ      if (!isQuitting && restartAttempt < MAX_RESTART_ATTEMPTS) {
146ŌåÆ        restartAttempt++;
147ŌåÆ        const delay = Math.min(1000 * Math.pow(2, restartAttempt - 1), 30_000);
148ŌåÆ        console.log(`[backend] Restart attempt ${restartAttempt} in ${delay}ms`);
