151ŌåÆ          spawnBackend()
152ŌåÆ            .then(({ port, authToken: newAuthToken }) => {
153ŌåÆ              // Update env vars so IPC handlers (native:getBackendPort) return the new port
154ŌåÆ              process.env.DEUS_BACKEND_PORT = String(port);
155ŌåÆ              process.env.DEUS_AUTH_TOKEN = newAuthToken;
156ŌåÆ
157ŌåÆ              // Notify all renderer windows so they can invalidate their cached port
158ŌåÆ              // and reconnect WebSocket to the new address.
159ŌåÆ              for (const win of BrowserWindow.getAllWindows()) {
160ŌåÆ                win.webContents.send("backend:port-changed", { port });
161ŌåÆ              }
162ŌåÆ              console.log(`[backend] Restarted on port ${port}, notified renderer`);
163ŌåÆ            })
164ŌåÆ            .catch((err) => {
165ŌåÆ              console.error("[backend] Restart failed:", err);
166ŌåÆ            });
