168ŌåÆ      }
169ŌåÆ    });
170ŌåÆ
171ŌåÆ    backendProcess.on("error", (err) => {
172ŌåÆ      console.error("[backend] Spawn error:", err);
173ŌåÆ      if (!resolved) {
174ŌåÆ        reject(err);
175ŌåÆ      }
176ŌåÆ    });
177ŌåÆ
178ŌåÆ    // Timeout if backend doesn't start
179ŌåÆ    setTimeout(() => {
180ŌåÆ      if (!resolved) {
