    console.error(`  Repo: ${GITHUB_REPO}`);
    console.error("  Make sure the repository has published releases.");
    process.exit(1);
  }

  console.log(`  Found release: ${release.tag_name}`);

  // Find matching asset
  const asset = release.assets.find((a) => assetPattern.matcher(a.name));
  if (!asset) {
