#!/usr/bin/env node

/**
 * Deus CLI ŌĆö run Deus IDE from the command line.
 *
 * Smart default:
 *   deus              On a desktop ŌåÆ launch app (install if needed)
 *                     On a server  ŌåÆ start headless with web UI
 *
 * Explicit commands:
 *   deus serve        Start headless server with web UI
 *   deus desktop      Download and install the desktop app
 */

import { parseArgs } from "node:util";
import { serve } from "./serve.js";
import { installDesktop, hasDisplay, findInstalledApp, launchDesktop } from "./desktop.js";

const HELP = `
  Deus IDE ŌĆö AI-powered IDE for managing multiple parallel coding agents

  Usage:
    deus [command] [options]

  Commands:
    (default)   Auto-detect: launch desktop app or start headless server
    serve       Start headless server with web UI
    desktop     Download and install the desktop app

  Options (serve):
    --port, -p <port>     Port for the web UI (default: 3000)
    --host <host>         Host to bind to (default: localhost)
    --open                Open browser after starting
    --data-dir <path>     Directory for database and data files

  Options (desktop):
    --version <version>   Specific version to install (default: latest)

  Examples:
    deus                  Auto-detect mode
    deus serve -p 8080    Start server on port 8080
    deus desktop          Install the desktop app
`;

async function main() {
  const args = process.argv.slice(2);
  const command = args[0] && !args[0].startsWith("-") ? args[0] : null;
  const commandArgs = command ? args.slice(1) : args;

  if (command === "help" || args.includes("--help") || args.includes("-h")) {
    console.log(HELP);
    process.exit(0);
  }

  if (args.includes("--version") && command !== "desktop") {
