  s1.succeed(`Agent server ${c.dim("ready")}`);

  // ŌöĆŌöĆ Step 2: Backend ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
  const s2 = createSpinner("Starting backend...");
  const backendPort = await startProcess({
    name: "backend",
    command: nodeCmd,
    args: [paths.backend],
    env: {
      AGENT_SERVER_URL: agentServerUrl,
      DATABASE_PATH: dbPath,
      PORT: "0",
    },
    waitFor: /\[BACKEND_PORT\](\d+)/,
    children,
  });

  if (!backendPort) {
    s2.fail("Backend failed to start");
    blank();
    process.exit(1);
  }
  s2.succeed(`Backend ${c.dim("ready")}`);

  // ŌöĆŌöĆ Step 3: Web server ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
  const hasFrontend = existsSync(paths.frontend) && existsSync(join(paths.frontend, "index.html"));

  const s3 = createSpinner("Starting web server...");
  const webServer = createWebServer(parseInt(backendPort, 10), paths.frontend);

  await new Promise<void>((resolve) => {
    webServer.listen(port, host, () => resolve());
  });

  if (hasFrontend) {
    s3.succeed(`Web UI ${c.dim("ready")}`);
  } else {
    s3.warn(`Web UI ${c.dim("ŌĆö frontend not built, API-only mode")}`);
  }

  // ŌöĆŌöĆ Ready! ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
  blank();

  const url = `http://${host === "0.0.0.0" ? "localhost" : host}:${port}`;
  box([c.bold(c.brightWhite(url))], { borderColor: c.cyan, width: 36 });

  blank();
  kv("Local", c.cyan(url), 10);

  // Show network URL if binding to all interfaces or a specific host
  const lanIp = getLanIp();
  if (lanIp && (host === "0.0.0.0" || host === "localhost")) {
