224ŌåÆ/**
225ŌåÆ * Resolve the Node.js binary for spawning child processes.
226ŌåÆ *
227ŌåÆ * In monorepo dev mode, native modules are compiled against Electron's Node ABI
228ŌåÆ * (via `electron-builder install-app-deps` in postinstall). Using system Node
229ŌåÆ * causes ERR_DLOPEN_FAILED. Detect and use Electron's embedded Node binary.
230ŌåÆ *
231ŌåÆ * When installed as an npm package, native modules are compiled for system Node.
232ŌåÆ */
233ŌåÆfunction resolveNodeBinary(): string {
234ŌåÆ  // If ELECTRON_RUN_AS_NODE is already set, we're being run via Electron's node
235ŌåÆ  if (process.env.ELECTRON_RUN_AS_NODE === "1") {
236ŌåÆ    return process.execPath;
237ŌåÆ  }
238ŌåÆ
239ŌåÆ  // Check if we're in a monorepo with electron installed
240ŌåÆ  try {
241ŌåÆ    const electronPath = execSync(
242ŌåÆ      'node -e "try { console.log(require(\'electron\')) } catch { process.exit(1) }"',
243ŌåÆ      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
244ŌåÆ    ).trim();
245ŌåÆ
246ŌåÆ    if (electronPath && existsSync(electronPath)) {
247ŌåÆ      // Test if system Node can actually use better-sqlite3 (load the .node binary)
248ŌåÆ      try {
249ŌåÆ        execSync(
250ŌåÆ          "node -e \"const D = require('better-sqlite3'); const d = new D(':memory:'); d.close()\"",
251ŌåÆ          { timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
252ŌåÆ        );
253ŌåÆ        // System Node works fine ŌĆö no need for Electron's node
254ŌåÆ        return process.execPath;
255ŌåÆ      } catch {
256ŌåÆ        // System Node can't use native modules ŌĆö use Electron's node
257ŌåÆ        return electronPath;
258ŌåÆ      }
259ŌåÆ    }
260ŌåÆ  } catch {
261ŌåÆ    // Electron not available ŌĆö use system node
262ŌåÆ  }
263ŌåÆ
264ŌåÆ  return process.execPath;
265ŌåÆ}
