267ŌåÆ/**
268ŌåÆ * Start a child process and wait for a pattern in stdout.
269ŌåÆ * Returns the first capture group from the pattern match.
270ŌåÆ */
271ŌåÆasync function startProcess(opts: {
272ŌåÆ  name: string;
273ŌåÆ  command: string;
274ŌåÆ  args: string[];
275ŌåÆ  env: Record<string, string>;
276ŌåÆ  waitFor: RegExp;
277ŌåÆ  children: ProcessInfo[];
278ŌåÆ  timeoutMs?: number;
279ŌåÆ}): Promise<string | null> {
280ŌåÆ  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;
281ŌåÆ
282ŌåÆ  return new Promise((resolve) => {
283ŌåÆ    // If using Electron's node binary, set ELECTRON_RUN_AS_NODE=1
284ŌåÆ    const extraEnv: Record<string, string> = {};
285ŌåÆ    if (command !== process.execPath && command.includes("Electron")) {
286ŌåÆ      extraEnv.ELECTRON_RUN_AS_NODE = "1";
287ŌåÆ    }
288ŌåÆ
289ŌåÆ    const child = spawn(command, args, {
290ŌåÆ      stdio: ["ignore", "pipe", "pipe"],
291ŌåÆ      env: { ...process.env, ...extraEnv, ...env },
292ŌåÆ    });
293ŌåÆ
294ŌåÆ    children.push({ process: child, name });
295ŌåÆ
296ŌåÆ    let buffer = "";
297ŌåÆ    let resolved = false;
298ŌåÆ
299ŌåÆ    const timeout = setTimeout(() => {
300ŌåÆ      if (!resolved) {
301ŌåÆ        resolved = true;
302ŌåÆ        console.error(`  Warning: ${name} did not produce expected output within ${timeoutMs}ms`);
303ŌåÆ        resolve(null);
304ŌåÆ      }
305ŌåÆ    }, timeoutMs);
306ŌåÆ
307ŌåÆ    child.stdout?.on("data", (data: Buffer) => {
308ŌåÆ      const text = data.toString();
309ŌåÆ      buffer += text;
310ŌåÆ
311ŌåÆ      // Log output with prefix
312ŌåÆ      for (const line of text.split("\n")) {
313ŌåÆ        const trimmed = line.trim();
314ŌåÆ        if (trimmed && !resolved) {
315ŌåÆ          // Don't spam ŌĆö only log important lines
316ŌåÆ        }
317ŌåÆ      }
318ŌåÆ
319ŌåÆ      // Check for the pattern
320ŌåÆ      const match = buffer.match(waitFor);
321ŌåÆ      if (match && !resolved) {
322ŌåÆ        resolved = true;
323ŌåÆ        clearTimeout(timeout);
324ŌåÆ        resolve(match[1]);
325ŌåÆ      }
326ŌåÆ    });
327ŌåÆ
328ŌåÆ    child.stderr?.on("data", (data: Buffer) => {
329ŌåÆ      for (const line of data.toString().split("\n")) {
330ŌåÆ        if (line.trim()) {
331ŌåÆ          console.error(`  [${name}:err] ${line.trim()}`);
332ŌåÆ        }
333ŌåÆ      }
334ŌåÆ    });
335ŌåÆ
336ŌåÆ    child.on("exit", (code, signal) => {
337ŌåÆ      if (!resolved) {
338ŌåÆ        resolved = true;
339ŌåÆ        clearTimeout(timeout);
340ŌåÆ        console.error(`  ${name} exited unexpectedly (code=${code}, signal=${signal})`);
341ŌåÆ        resolve(null);
342ŌåÆ      }
343ŌåÆ    });
344ŌåÆ  });
345ŌåÆ}
