382ŌåÆ        <html>
383ŌåÆ        <head><title>Deus IDE</title></head>
384ŌåÆ        <body style="font-family: system-ui; padding: 2rem; background: #0a0a0a; color: #e5e5e5;">
385ŌåÆ          <h1>Deus IDE Server</h1>
386ŌåÆ          <p>Backend API running on port ${backendPort}</p>
387ŌåÆ          <p>WebSocket: ws://localhost:${backendPort}/ws</p>
388ŌåÆ          <p style="color: #a3a3a3;">Frontend not built. Run <code>bun run build:web</code> to build the UI.</p>
389ŌåÆ        </body>
390ŌåÆ        </html>
391ŌåÆ      `);
392ŌåÆ    }
393ŌåÆ  });
394ŌåÆ
395ŌåÆ  // Handle WebSocket upgrade ŌĆö proxy to backend
396ŌåÆ  server.on("upgrade", (req, socket, head) => {
397ŌåÆ    const proxyReq = httpRequest({
398ŌåÆ      hostname: "localhost",
399ŌåÆ      port: backendPort,
400ŌåÆ      path: req.url,
401ŌåÆ      method: req.method,
402ŌåÆ      headers: req.headers,
403ŌåÆ    });
