193ŌåÆasync function fetchRelease(version: string): Promise<GithubRelease | null> {
194ŌåÆ  const endpoint =
195ŌåÆ    version === "latest"
196ŌåÆ      ? `https://api.github.com/repos/${GITHUB_REPO}/releases/latest`
197ŌåÆ      : `https://api.github.com/repos/${GITHUB_REPO}/releases/tags/${version}`;
