199ŌåÆ  return new Promise((resolve) => {
200ŌåÆ    get(
201ŌåÆ      endpoint,
202ŌåÆ      {
203ŌåÆ        headers: {
204ŌåÆ          "User-Agent": "deus-cli",
205ŌåÆ          Accept: "application/vnd.github.v3+json",
206ŌåÆ        },
207ŌåÆ      },
208ŌåÆ      (res) => {
209ŌåÆ        // Follow redirects
210ŌåÆ        if (res.statusCode === 302 || res.statusCode === 301) {
211ŌåÆ          const redirectUrl = res.headers.location;
212ŌåÆ          if (redirectUrl) {
213ŌåÆ            get(
214ŌåÆ              redirectUrl,
215ŌåÆ              { headers: { "User-Agent": "deus-cli" } },
216ŌåÆ              (redirectRes) => {
217ŌåÆ                collectBody(redirectRes).then((body) => {
218ŌåÆ                  try {
219ŌåÆ                    resolve(JSON.parse(body));
220ŌåÆ                  } catch {
221ŌåÆ                    resolve(null);
222ŌåÆ                  }
223ŌåÆ                });
224ŌåÆ              }
225ŌåÆ            ).on("error", () => resolve(null));
226ŌåÆ            return;
227ŌåÆ          }
228ŌåÆ        }
229ŌåÆ
230ŌåÆ        if (res.statusCode !== 200) {
231ŌåÆ          resolve(null);
232ŌåÆ          return;
233ŌåÆ        }
234ŌåÆ
235ŌåÆ        collectBody(res).then((body) => {
236ŌåÆ          try {
237ŌåÆ            resolve(JSON.parse(body));
238ŌåÆ          } catch {
239ŌåÆ            resolve(null);
240ŌåÆ          }
241ŌåÆ        });
242ŌåÆ      }
243ŌåÆ    ).on("error", () => resolve(null));
244ŌåÆ  });
