256ŌåÆasync function downloadFile(url: string, dest: string): Promise<void> {
257ŌåÆ  return new Promise((resolve, reject) => {
258ŌåÆ    const download = (downloadUrl: string) => {
259ŌåÆ      get(downloadUrl, { headers: { "User-Agent": "deus-cli" } }, (res) => {
260ŌåÆ        // Follow redirects (GitHub releases redirect to S3)
261ŌåÆ        if (res.statusCode === 302 || res.statusCode === 301) {
262ŌåÆ          const redirectUrl = res.headers.location;
263ŌåÆ          if (redirectUrl) {
264ŌåÆ            download(redirectUrl);
265ŌåÆ            return;
266ŌåÆ          }
267ŌåÆ        }
268ŌåÆ
269ŌåÆ        if (res.statusCode !== 200) {
270ŌåÆ          reject(new Error(`Download failed with status ${res.statusCode}`));
271ŌåÆ          return;
272ŌåÆ        }
273ŌåÆ
274ŌåÆ        const totalSize = parseInt(res.headers["content-length"] || "0", 10);
275ŌåÆ        let downloaded = 0;
276ŌåÆ
277ŌåÆ        const file = createWriteStream(dest);
278ŌåÆ        res.on("data", (chunk: Buffer) => {
