280ŌåÆ          if (totalSize > 0) {
281ŌåÆ            const pct = Math.round((downloaded / totalSize) * 100);
282ŌåÆ            process.stdout.write(`\r  Progress: ${pct}% (${formatBytes(downloaded)} / ${formatBytes(totalSize)})`);
