285ŌåÆ        res.pipe(file);
286ŌåÆ        file.on("finish", () => {
287ŌåÆ          file.close();
288ŌåÆ          process.stdout.write("\n");
289ŌåÆ          resolve();
290ŌåÆ        });
291ŌåÆ        file.on("error", reject);
292ŌåÆ      }).on("error", reject);
293ŌåÆ    };
294ŌåÆ
295ŌåÆ    download(url);
296ŌåÆ  });
297ŌåÆ}
