250ŌåÆfunction resolveNodeBinary(): string {
251ŌåÆ  if (process.env.ELECTRON_RUN_AS_NODE === "1") return process.execPath;
252ŌåÆ
253ŌåÆ  try {
254ŌåÆ    const electronPath = execSync(
255ŌåÆ      'node -e "try { console.log(require(\'electron\')) } catch { process.exit(1) }"',
256ŌåÆ      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
257ŌåÆ    ).trim();
258ŌåÆ
259ŌåÆ    if (electronPath && existsSync(electronPath)) {
260ŌåÆ      try {
261ŌåÆ        execSync(
262ŌåÆ          "node -e \"const D = require('better-sqlite3'); const d = new D(':memory:'); d.close()\"",
263ŌåÆ          { timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
264ŌåÆ        );
265ŌåÆ        return process.execPath;
266ŌåÆ      } catch {
267ŌåÆ        return electronPath;
268ŌåÆ      }
269ŌåÆ    }
270ŌåÆ  } catch {}
271ŌåÆ
272ŌåÆ  return process.execPath;
273ŌåÆ}
