277ŌåÆasync function startProcess(opts: {
278ŌåÆ  name: string;
279ŌåÆ  command: string;
280ŌåÆ  args: string[];
281ŌåÆ  env: Record<string, string>;
282ŌåÆ  waitFor: RegExp;
283ŌåÆ  children: ProcessInfo[];
284ŌåÆ  timeoutMs?: number;
285ŌåÆ}): Promise<string | null> {
286ŌåÆ  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;
287ŌåÆ
288ŌåÆ  return new Promise((resolve) => {
289ŌåÆ    const extraEnv: Record<string, string> = {};
290ŌåÆ    if (command !== process.execPath && command.includes("Electron")) {
291ŌåÆ      extraEnv.ELECTRON_RUN_AS_NODE = "1";
292ŌåÆ    }
293ŌåÆ
294ŌåÆ    const child = spawn(command, args, {
295ŌåÆ      stdio: ["ignore", "pipe", "pipe"],
296ŌåÆ      env: { ...process.env, ...extraEnv, ...env },
297ŌåÆ    });
298ŌåÆ
299ŌåÆ    children.push({ process: child, name });
300ŌåÆ
301ŌåÆ    let buffer = "";
302ŌåÆ    let resolved = false;
303ŌåÆ
304ŌåÆ    const timeout = setTimeout(() => {
305ŌåÆ      if (!resolved) {
306ŌåÆ        resolved = true;
307ŌåÆ        resolve(null);
308ŌåÆ      }
309ŌåÆ    }, timeoutMs);
310ŌåÆ
311ŌåÆ    child.stdout?.on("data", (data: Buffer) => {
312ŌåÆ      buffer += data.toString();
313ŌåÆ      const match = buffer.match(waitFor);
314ŌåÆ      if (match && !resolved) {
315ŌåÆ        resolved = true;
316ŌåÆ        clearTimeout(timeout);
317ŌåÆ        resolve(match[1]);
318ŌåÆ      }
319ŌåÆ    });
320ŌåÆ
321ŌåÆ    child.stderr?.on("data", () => {
322ŌåÆ      // Suppress stderr in normal mode
323ŌåÆ    });
324ŌåÆ
325ŌåÆ    child.on("exit", (code, signal) => {
326ŌåÆ      if (!resolved) {
327ŌåÆ        resolved = true;
328ŌåÆ        clearTimeout(timeout);
329ŌåÆ        resolve(null);
330ŌåÆ      }
331ŌåÆ    });
332ŌåÆ  });
333ŌåÆ}
