335ŌåÆ// ŌöĆŌöĆ Web server (static + proxy) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
336ŌåÆ
337ŌåÆfunction createWebServer(backendPort: number, frontendDir: string) {
338ŌåÆ  const hasFrontend = existsSync(frontendDir) && existsSync(join(frontendDir, "index.html"));
339ŌåÆ
340ŌåÆ  const server = createServer(async (req, res) => {
341ŌåÆ    const url = req.url || "/";
342ŌåÆ
343ŌåÆ    if (url.startsWith("/api/") || url.startsWith("/api")) {
344ŌåÆ      return proxyRequest(req, res, backendPort);
345ŌåÆ    }
346ŌåÆ
347ŌåÆ    if (url === "/__backend_port") {
348ŌåÆ      res.writeHead(200, {
349ŌåÆ        "Content-Type": "application/json",
350ŌåÆ        "Access-Control-Allow-Origin": "*",
351ŌåÆ      });
352ŌåÆ      res.end(JSON.stringify({ port: backendPort }));
353ŌåÆ      return;
354ŌåÆ    }
355ŌåÆ
356ŌåÆ    if (hasFrontend) {
357ŌåÆ      serveStaticFile(req, res, frontendDir);
358ŌåÆ    } else {
359ŌåÆ      res.writeHead(200, { "Content-Type": "text/html" });
360ŌåÆ      res.end(`<!DOCTYPE html><html><head><title>Deus IDE</title>
361ŌåÆ<style>body{font-family:system-ui;padding:3rem;background:#0a0a0a;color:#e5e5e5}
362ŌåÆcode{background:#1a1a1a;padding:2px 6px;border-radius:4px;font-size:14px}
363ŌåÆa{color:#22d3ee}</style></head><body>
364ŌåÆ<h1>Deus IDE Server</h1>
365ŌåÆ<p>Backend API: <code>http://localhost:${backendPort}/api</code></p>
366ŌåÆ<p>WebSocket: <code>ws://localhost:${backendPort}/ws</code></p>
367ŌåÆ<p style="color:#a3a3a3">Frontend not built. Run <code>bun run build:web</code> to enable the UI.</p>
368ŌåÆ</body></html>`);
369ŌåÆ    }
370ŌåÆ  });
371ŌåÆ
372ŌåÆ  server.on("upgrade", (req, socket, head) => {
373ŌåÆ    const proxyReq = httpRequest({
374ŌåÆ      hostname: "localhost",
375ŌåÆ      port: backendPort,
376ŌåÆ      path: req.url,
377ŌåÆ      method: req.method,
378ŌåÆ      headers: req.headers,
379ŌåÆ    });
380ŌåÆ
381ŌåÆ    proxyReq.on("upgrade", (_proxyRes: any, proxySocket: any, proxyHead: any) => {
382ŌåÆ      socket.write(
383ŌåÆ        "HTTP/1.1 101 Switching Protocols\r\n" +
384ŌåÆ          Object.entries(_proxyRes.headers)
385ŌåÆ            .map(([k, v]: [string, any]) => `${k}: ${v}`)
386ŌåÆ            .join("\r\n") +
387ŌåÆ          "\r\n\r\n"
388ŌåÆ      );
389ŌåÆ      if (proxyHead.length > 0) socket.write(proxyHead);
390ŌåÆ      proxySocket.pipe(socket);
391ŌåÆ      socket.pipe(proxySocket);
392ŌåÆ    });
393ŌåÆ
394ŌåÆ    proxyReq.on("error", () => socket.end());
395ŌåÆ    proxyReq.end();
396ŌåÆ  });
397ŌåÆ
398ŌåÆ  return server;
399ŌåÆ}
400ŌåÆ
401ŌåÆfunction proxyRequest(
402ŌåÆ  req: import("node:http").IncomingMessage,
403ŌåÆ  res: import("node:http").ServerResponse,
404ŌåÆ  backendPort: number
405ŌåÆ) {
406ŌåÆ  const proxyReq = httpRequest(
407ŌåÆ    {
408ŌåÆ      hostname: "localhost",
409ŌåÆ      port: backendPort,
410ŌåÆ      path: req.url,
411ŌåÆ      method: req.method,
412ŌåÆ      headers: { ...req.headers, host: `localhost:${backendPort}` },
413ŌåÆ    },
414ŌåÆ    (proxyRes) => {
415ŌåÆ      res.writeHead(proxyRes.statusCode || 502, proxyRes.headers);
416ŌåÆ      proxyRes.pipe(res);
417ŌåÆ    }
418ŌåÆ  );
419ŌåÆ
420ŌåÆ  proxyReq.on("error", () => {
421ŌåÆ    res.writeHead(502, { "Content-Type": "application/json" });
422ŌåÆ    res.end(JSON.stringify({ error: "Backend unavailable" }));
423ŌåÆ  });
424ŌåÆ
425ŌåÆ  req.pipe(proxyReq);
426ŌåÆ}
427ŌåÆ
428ŌåÆfunction serveStaticFile(
429ŌåÆ  req: import("node:http").IncomingMessage,
430ŌåÆ  res: import("node:http").ServerResponse,
431ŌåÆ  frontendDir: string
432ŌåÆ) {
433ŌåÆ  let pathname = (req.url || "/").split("?")[0];
434ŌåÆ  if (pathname === "/") pathname = "/index.html";
435ŌåÆ
436ŌåÆ  let filePath = join(frontendDir, pathname);
437ŌåÆ
438ŌåÆ  if (!existsSync(filePath) || statSync(filePath).isDirectory()) {
439ŌåÆ    filePath = join(frontendDir, "index.html");
440ŌåÆ  }
441ŌåÆ
442ŌåÆ  if (!existsSync(filePath)) {
443ŌåÆ    res.writeHead(404);
444ŌåÆ    res.end("Not found");
445ŌåÆ    return;
446ŌåÆ  }
447ŌåÆ
448ŌåÆ  const ext = extname(filePath);
449ŌåÆ  const contentType = MIME_TYPES[ext] || "application/octet-stream";
450ŌåÆ
451ŌåÆ  try {
452ŌåÆ    const content = readFileSync(filePath);
453ŌåÆ    res.writeHead(200, {
454ŌåÆ      "Content-Type": contentType,
455ŌåÆ      "Cache-Control": ext === ".html" ? "no-cache" : "public, max-age=31536000, immutable",
456ŌåÆ    });
457ŌåÆ    res.end(content);
458ŌåÆ  } catch {
459ŌåÆ    res.writeHead(500);
460ŌåÆ    res.end("Internal server error");
461ŌåÆ  }
462ŌåÆ}
