149ŌåÆ/** Color a logo row: block chars in main color, shadow chars in dim */
150ŌåÆfunction colorLogo(
151ŌåÆ  text: string,
152ŌåÆ  block: [number, number, number],
153ŌåÆ  shadow: [number, number, number]
154ŌåÆ): string {
155ŌåÆ  let result = "";
156ŌåÆ  let buf = "";
157ŌåÆ  let cur: "b" | "s" | " " | null = null;
158ŌåÆ
159ŌåÆ  function flush() {
160ŌåÆ    if (!buf) return;
161ŌåÆ    if (cur === "b") result += rgb(block[0], block[1], block[2], buf);
162ŌåÆ    else if (cur === "s") result += rgb(shadow[0], shadow[1], shadow[2], buf);
163ŌåÆ    else result += buf;
164ŌåÆ    buf = "";
165ŌåÆ  }
166ŌåÆ
167ŌåÆ  for (const ch of text) {
168ŌåÆ    const t = ch === " " ? " " : SHADOW_CHARS.has(ch) ? "s" : "b";
169ŌåÆ    if (t !== cur) {
170ŌåÆ      flush();
171ŌåÆ      cur = t;
172ŌåÆ    }
173ŌåÆ    buf += ch;
174ŌåÆ  }
175ŌåÆ  flush();
176ŌåÆ  return result;
177ŌåÆ}
