218ŌåÆconst SPINNER_FRAMES = isUnicode
219ŌåÆ  ? ["ŌĀŗ", "ŌĀÖ", "ŌĀ╣", "ŌĀĖ", "ŌĀ╝", "ŌĀ┤", "ŌĀ”", "ŌĀ¦", "ŌĀć", "ŌĀÅ"]
220ŌåÆ  : ["-", "\\", "|", "/"];
221ŌåÆ
222ŌåÆconst SPINNER_INTERVAL = 80;
223ŌåÆ
224ŌåÆexport interface Spinner {
225ŌåÆ  /** Update the spinner text while it's running */
226ŌåÆ  update(text: string): void;
227ŌåÆ  /** Stop with a success message */
228ŌåÆ  succeed(text?: string): void;
229ŌåÆ  /** Stop with a failure message */
230ŌåÆ  fail(text?: string): void;
231ŌåÆ  /** Stop with a warning message */
232ŌåÆ  warn(text?: string): void;
233ŌåÆ  /** Stop with an info message */
234ŌåÆ  info(text?: string): void;
235ŌåÆ  /** Stop and clear the line */
236ŌåÆ  stop(): void;
237ŌåÆ}
238ŌåÆ
239ŌåÆexport function spinner(text: string): Spinner {
240ŌåÆ  let frameIdx = 0;
241ŌåÆ  let currentText = text;
242ŌåÆ  let stopped = false;
243ŌåÆ
244ŌåÆ  const stream = process.stderr;
245ŌåÆ
246ŌåÆ  function render() {
247ŌåÆ    if (stopped) return;
248ŌåÆ    const frame = c.cyan(SPINNER_FRAMES[frameIdx % SPINNER_FRAMES.length]);
249ŌåÆ    stream.write(`\r${ESC}2K  ${frame} ${currentText}`);
250ŌåÆ    frameIdx++;
251ŌåÆ  }
252ŌåÆ
253ŌåÆ  const interval = setInterval(render, SPINNER_INTERVAL);
254ŌåÆ  render();
255ŌåÆ
256ŌåÆ  function stop(symbol: string, finalText: string) {
257ŌåÆ    if (stopped) return;
258ŌåÆ    stopped = true;
259ŌåÆ    clearInterval(interval);
260ŌåÆ    stream.write(`\r${ESC}2K  ${symbol} ${finalText}\n`);
261ŌåÆ  }
262ŌåÆ
263ŌåÆ  return {
264ŌåÆ    update(t: string) {
265ŌåÆ      currentText = t;
266ŌåÆ    },
267ŌåÆ    succeed(t?: string) {
268ŌåÆ      stop(c.green(sym.tick), t ?? currentText);
269ŌåÆ    },
270ŌåÆ    fail(t?: string) {
271ŌåÆ      stop(c.red(sym.cross), t ?? currentText);
272ŌåÆ    },
273ŌåÆ    warn(t?: string) {
274ŌåÆ      stop(c.yellow(sym.warning), t ?? currentText);
275ŌåÆ    },
276ŌåÆ    info(t?: string) {
277ŌåÆ      stop(c.blue(sym.info), t ?? currentText);
278ŌåÆ    },
279ŌåÆ    stop() {
280ŌåÆ      if (stopped) return;
281ŌåÆ      stopped = true;
282ŌåÆ      clearInterval(interval);
283ŌåÆ      stream.write(`\r${ESC}2K`);
284ŌåÆ    },
285ŌåÆ  };
286ŌåÆ}
