/**
 * Terminal UI primitives for the Deus CLI.
 *
 * Zero dependencies ŌĆö uses raw ANSI escape codes so everything
 * bundles into a single file with esbuild. Inspired by Claude Code,
 * Vercel CLI, and create-next-app.
 */

// ŌöĆŌöĆ ANSI Colors ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

const ESC = "\x1b[";
const RESET = `${ESC}0m`;

// Check NO_COLOR / FORCE_COLOR env vars (respect user preference)
const noColor = !!process.env.NO_COLOR || process.argv.includes("--no-color");

function wrap(code: string, text: string): string {
  if (noColor) return text;
  return `${ESC}${code}m${text}${RESET}`;
}

export const c = {
  // Modifiers
  bold: (t: string) => wrap("1", t),
  dim: (t: string) => wrap("2", t),
  italic: (t: string) => wrap("3", t),
  underline: (t: string) => wrap("4", t),

  // Colors
  red: (t: string) => wrap("31", t),
  green: (t: string) => wrap("32", t),
  yellow: (t: string) => wrap("33", t),
  blue: (t: string) => wrap("34", t),
  magenta: (t: string) => wrap("35", t),
  cyan: (t: string) => wrap("36", t),
  white: (t: string) => wrap("37", t),
  gray: (t: string) => wrap("90", t),

  // Bright colors
  brightCyan: (t: string) => wrap("96", t),
  brightWhite: (t: string) => wrap("97", t),

  // Backgrounds
  bgCyan: (t: string) => wrap("46", t),
  bgBlue: (t: string) => wrap("44", t),

  // Combos
  success: (t: string) => wrap("32", t), // green
  error: (t: string) => wrap("31", t), // red
  warn: (t: string) => wrap("33", t), // yellow
  info: (t: string) => wrap("36", t), // cyan
  label: (t: string) => wrap("1;36", t), // bold cyan
};

// True-color (24-bit) foreground
function rgb(r: number, g: number, b: number, text: string): string {
  if (noColor) return text;
  return `\x1b[38;2;${r};${g};${b}m${text}${RESET}`;
}

// ŌöĆŌöĆ Symbols ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

// Unicode symbols with ASCII fallbacks for limited terminals
const isUnicode = process.platform !== "win32" || !!process.env.WT_SESSION;

export const sym = {
  tick: isUnicode ? "Ō£ō" : "ŌłÜ",
  cross: isUnicode ? "Ō£Ś" : "├Ś",
  dot: isUnicode ? "ŌŚÅ" : "*",
  dash: isUnicode ? "ŌöĆ" : "-",
  arrow: isUnicode ? "ŌåÆ" : "->",
  diamond: isUnicode ? "ŌŚå" : "*",
  pointer: isUnicode ? "ŌØ»" : ">",
  info: isUnicode ? "Ōä╣" : "i",
  warning: isUnicode ? "ŌÜĀ" : "!",
  bullet: isUnicode ? "ŌĆó" : "-",

  // Box drawing
  tl: isUnicode ? "ŌĢŁ" : "+",
  tr: isUnicode ? "ŌĢ«" : "+",
  bl: isUnicode ? "ŌĢ░" : "+",
  br: isUnicode ? "ŌĢ»" : "+",
  h: isUnicode ? "ŌöĆ" : "-",
  v: isUnicode ? "Ōöé" : "|",
};

// ŌöĆŌöĆ Logo / Banner ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

// DEUS in block characters (ANSI Shadow style), per-letter for gradient coloring
const LOGO_D = [
  "Ō¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌĢŚ ",
  "Ō¢łŌ¢łŌĢöŌĢÉŌĢÉŌ¢łŌ¢łŌĢŚ",
  "Ō¢łŌ¢łŌĢæ  Ō¢łŌ¢łŌĢæ",
  "Ō¢łŌ¢łŌĢæ  Ō¢łŌ¢łŌĢæ",
  "Ō¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌĢöŌĢØ",
  "ŌĢÜŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢØ ",
];
const LOGO_E = [
  "Ō¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌĢŚ",
  "Ō¢łŌ¢łŌĢöŌĢÉŌĢÉŌĢÉŌĢÉŌĢØ",
  "Ō¢łŌ¢łŌ¢łŌ¢łŌ¢łŌĢŚ  ",
  "Ō¢łŌ¢łŌĢöŌĢÉŌĢÉŌĢØ  ",
  "Ō¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌĢŚ",
  "ŌĢÜŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢØ",
];
const LOGO_U = [
  "Ō¢łŌ¢łŌĢŚ   Ō¢łŌ¢łŌĢŚ",
  "Ō¢łŌ¢łŌĢæ   Ō¢łŌ¢łŌĢæ",
  "Ō¢łŌ¢łŌĢæ   Ō¢łŌ¢łŌĢæ",
  "Ō¢łŌ¢łŌĢæ   Ō¢łŌ¢łŌĢæ",
  "ŌĢÜŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌĢöŌĢØ",
  " ŌĢÜŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢØ ",
];
const LOGO_S = [
  "Ō¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌĢŚ",
  "Ō¢łŌ¢łŌĢöŌĢÉŌĢÉŌĢÉŌĢÉŌĢØ",
  "Ō¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌĢŚ",
  "ŌĢÜŌĢÉŌĢÉŌĢÉŌĢÉŌ¢łŌ¢łŌĢæ",
  "Ō¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌ¢łŌĢæ",
  "ŌĢÜŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢØ",
];

// Gradient for block chars (Ō¢ł): violet ŌåÆ indigo ŌåÆ blue ŌåÆ cyan
const LOGO_BLOCK: [number, number, number][] = [
  [167, 139, 250],
  [129, 140, 248],
  [96, 165, 250],
  [34, 211, 238],
];

// Shadow for border chars (ŌĢöŌĢÉŌĢŚŌĢæŌĢÜŌĢØ) in rows 0-4
const LOGO_INNER: [number, number, number][] = [
  [100, 83, 150],
  [77, 84, 149],
  [58, 99, 150],
  [20, 127, 143],
];

// Extra-dim shadow for the bottom row (ŌĢÜŌĢÉŌĢØ)
const LOGO_FLOOR: [number, number, number][] = [
  [60, 50, 90],
  [46, 50, 89],
  [35, 59, 90],
  [12, 76, 86],
];

const SHADOW_CHARS = new Set("ŌĢöŌĢÉŌĢŚŌĢæŌĢÜŌĢØŌĢ¼ŌĢĀŌĢŻŌĢ”ŌĢ®ŌĢōŌĢ¢ŌĢÖŌĢ£ŌĢÆŌĢĢŌĢśŌĢøŌöīŌöÉŌööŌöśŌö¼Ōö┤Ōö£ŌöżŌö╝ŌöĆŌöé");

/** Color a logo row: block chars in main color, shadow chars in dim */
function colorLogo(
  text: string,
  block: [number, number, number],
  shadow: [number, number, number]
): string {
  let result = "";
  let buf = "";
  let cur: "b" | "s" | " " | null = null;

  function flush() {
    if (!buf) return;
    if (cur === "b") result += rgb(block[0], block[1], block[2], buf);
    else if (cur === "s") result += rgb(shadow[0], shadow[1], shadow[2], buf);
    else result += buf;
    buf = "";
  }

  for (const ch of text) {
    const t = ch === " " ? " " : SHADOW_CHARS.has(ch) ? "s" : "b";
    if (t !== cur) {
      flush();
      cur = t;
    }
    buf += ch;
  }
  flush();
  return result;
}

// ASCII fallback for limited terminals
const LOGO_ASCII = [
  "  DDDD   EEEEE  U   U  SSSS ",
  "  D   D  E      U   U  S    ",
  "  D   D  EEE    U   U   SS  ",
  "  D   D  E      U   U     S ",
  "  DDDD   EEEEE  UUUUU  SSSS ",
];

export function banner(version?: string): void {
  const letters = [LOGO_D, LOGO_E, LOGO_U, LOGO_S];

  console.log("");

  if (isUnicode) {
    for (let row = 0; row < 6; row++) {
      const shadow = row === 5 ? LOGO_FLOOR : LOGO_INNER;
      let line = "  ";
      for (let l = 0; l < letters.length; l++) {
        line += colorLogo(letters[l][row], LOGO_BLOCK[l], shadow[l]);
      }
      console.log(line);
    }
  } else {
    for (const line of LOGO_ASCII) {
      console.log(c.cyan(line));
    }
  }

  console.log("");

  const tag = c.dim("  Agentic Engineering");
  const ver = version ? `  ${c.dim("v" + version)}` : "";
  console.log(tag + ver);
  console.log("");
}

// ŌöĆŌöĆ Spinner ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

const SPINNER_FRAMES = isUnicode
  ? ["ŌĀŗ", "ŌĀÖ", "ŌĀ╣", "ŌĀĖ", "ŌĀ╝", "ŌĀ┤", "ŌĀ”", "ŌĀ¦", "ŌĀć", "ŌĀÅ"]
  : ["-", "\\", "|", "/"];

const SPINNER_INTERVAL = 80;

export interface Spinner {
  /** Update the spinner text while it's running */
  update(text: string): void;
  /** Stop with a success message */
  succeed(text?: string): void;
  /** Stop with a failure message */
  fail(text?: string): void;
  /** Stop with a warning message */
  warn(text?: string): void;
  /** Stop with an info message */
  info(text?: string): void;
  /** Stop and clear the line */
  stop(): void;
}

export function spinner(text: string): Spinner {
  let frameIdx = 0;
  let currentText = text;
  let stopped = false;

  const stream = process.stderr;

  function render() {
    if (stopped) return;
    const frame = c.cyan(SPINNER_FRAMES[frameIdx % SPINNER_FRAMES.length]);
    stream.write(`\r${ESC}2K  ${frame} ${currentText}`);
    frameIdx++;
  }

  const interval = setInterval(render, SPINNER_INTERVAL);
  render();

  function stop(symbol: string, finalText: string) {
    if (stopped) return;
    stopped = true;
    clearInterval(interval);
    stream.write(`\r${ESC}2K  ${symbol} ${finalText}\n`);
  }

  return {
    update(t: string) {
      currentText = t;
    },
    succeed(t?: string) {
      stop(c.green(sym.tick), t ?? currentText);
    },
    fail(t?: string) {
      stop(c.red(sym.cross), t ?? currentText);
    },
    warn(t?: string) {
      stop(c.yellow(sym.warning), t ?? currentText);
    },
    info(t?: string) {
      stop(c.blue(sym.info), t ?? currentText);
    },
    stop() {
      if (stopped) return;
      stopped = true;
      clearInterval(interval);
      stream.write(`\r${ESC}2K`);
    },
  };
}

// ŌöĆŌöĆ Box ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

/** Draw a rounded box around content lines */
export function box(
  lines: string[],
  opts?: { padding?: number; borderColor?: (s: string) => string; width?: number }
): void {
  const { padding = 1, borderColor = c.dim, width } = opts ?? {};
  const pad = " ".repeat(padding);

  // Calculate width from content (strip ANSI for measurement)
  const stripped = lines.map(stripAnsi);
  const contentWidth = width ?? Math.max(...stripped.map((l) => l.length));
  const innerWidth = contentWidth + padding * 2;

  const top = borderColor(`  ${sym.tl}${sym.h.repeat(innerWidth)}${sym.tr}`);
  const bot = borderColor(`  ${sym.bl}${sym.h.repeat(innerWidth)}${sym.br}`);
  const empty = borderColor(`  ${sym.v}`) + " ".repeat(innerWidth) + borderColor(sym.v);

  console.log(top);
  console.log(empty);
  for (let i = 0; i < lines.length; i++) {
    const visible = stripped[i].length;
    const rightPad = " ".repeat(Math.max(0, contentWidth - visible));
    console.log(
      borderColor(`  ${sym.v}`) + pad + lines[i] + rightPad + pad + borderColor(sym.v)
    );
  }
  console.log(empty);
  console.log(bot);
}

// ŌöĆŌöĆ Section / Divider ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

/** Print a labeled divider line */
export function divider(label?: string, width = 44): void {
  if (label) {
    const lineLen = Math.max(0, width - label.length - 3);
    console.log(c.dim(`  ${sym.h.repeat(2)} ${label} ${sym.h.repeat(lineLen)}`));
  } else {
    console.log(c.dim(`  ${sym.h.repeat(width)}`));
  }
}

// ŌöĆŌöĆ Key-Value Output ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

/** Print a labeled value with consistent alignment */
export function kv(label: string, value: string, labelWidth = 12): void {
  const paddedLabel = label.padEnd(labelWidth);
  console.log(`  ${c.dim(paddedLabel)} ${value}`);
}

// ŌöĆŌöĆ Messages ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export function success(text: string): void {
  console.log(`  ${c.green(sym.tick)} ${text}`);
}

export function error(text: string): void {
  console.log(`  ${c.red(sym.cross)} ${text}`);
}

export function warn(text: string): void {
  console.log(`  ${c.yellow(sym.warning)} ${text}`);
}

export function info(text: string): void {
  console.log(`  ${c.blue(sym.info)} ${text}`);
}

export function step(text: string): void {
  console.log(`  ${c.cyan(sym.diamond)} ${text}`);
}

export function hint(text: string): void {
  console.log(c.dim(`  ${text}`));
}

export function blank(): void {
  console.log("");
}

// ŌöĆŌöĆ Progress Bar ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

const BAR_WIDTH = 30;
const BAR_FILLED = isUnicode ? "Ō¢ł" : "#";
const BAR_EMPTY = isUnicode ? "Ō¢æ" : ".";

export function progressBar(current: number, total: number, label?: string): void {
  const pct = Math.min(1, current / total);
  const filled = Math.round(pct * BAR_WIDTH);
  const empty = BAR_WIDTH - filled;
  const bar = c.cyan(BAR_FILLED.repeat(filled)) + c.dim(BAR_EMPTY.repeat(empty));
  const pctStr = `${Math.round(pct * 100)}%`.padStart(4);
  const extra = label ? ` ${c.dim(label)}` : "";
  process.stderr.write(`\r${ESC}2K  ${bar} ${pctStr}${extra}`);
}

export function progressBarDone(text: string): void {
  process.stderr.write(`\r${ESC}2K`);
  success(text);
}

// ŌöĆŌöĆ Utilities ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

/** Strip ANSI escape codes for length calculation */
function stripAnsi(str: string): string {
  // eslint-disable-next-line no-control-regex
  return str.replace(/\x1b\[[0-9;]*m/g, "");
}

/** Sleep for ms */
export function sleep(ms: number): Promise<void> {
  return new Promise((r) => setTimeout(r, ms));
}

/** Get terminal width (with safe fallback) */
export function termWidth(): number {
  return process.stdout.columns || 80;
}

