288ŌåÆfunction resolveNodeBinary(): string {
289ŌåÆ  if (process.env.ELECTRON_RUN_AS_NODE === "1") return process.execPath;
290ŌåÆ
291ŌåÆ  try {
292ŌåÆ    const electronPath = execSync(
293ŌåÆ      'node -e "try { console.log(require(\'electron\')) } catch { process.exit(1) }"',
294ŌåÆ      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
295ŌåÆ    ).trim();
296ŌåÆ
297ŌåÆ    if (electronPath && existsSync(electronPath)) {
298ŌåÆ      try {
299ŌåÆ        execSync(
300ŌåÆ          "node -e \"const D = require('better-sqlite3'); const d = new D(':memory:'); d.close()\"",
301ŌåÆ          { timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
302ŌåÆ        );
303ŌåÆ        return process.execPath;
304ŌåÆ      } catch {
305ŌåÆ        return electronPath;
306ŌåÆ      }
307ŌåÆ    }
308ŌåÆ  } catch {}
309ŌåÆ
310ŌåÆ  return process.execPath;
311ŌåÆ}
