315ŌåÆasync function startProcess(opts: {
316ŌåÆ  name: string;
317ŌåÆ  command: string;
318ŌåÆ  args: string[];
319ŌåÆ  env: Record<string, string>;
320ŌåÆ  waitFor: RegExp;
321ŌåÆ  children: ProcessInfo[];
322ŌåÆ  timeoutMs?: number;
323ŌåÆ}): Promise<string | null> {
324ŌåÆ  const { name, command, args, env, waitFor, children, timeoutMs = 15_000 } = opts;
325ŌåÆ
326ŌåÆ  return new Promise((resolve) => {
327ŌåÆ    const extraEnv: Record<string, string> = {};
328ŌåÆ    if (command !== process.execPath && command.includes("Electron")) {
329ŌåÆ      extraEnv.ELECTRON_RUN_AS_NODE = "1";
330ŌåÆ    }
331ŌåÆ
332ŌåÆ    const child = spawn(command, args, {
333ŌåÆ      stdio: ["ignore", "pipe", "pipe"],
334ŌåÆ      env: { ...process.env, ...extraEnv, ...env },
335ŌåÆ    });
336ŌåÆ
337ŌåÆ    children.push({ process: child, name });
338ŌåÆ
339ŌåÆ    let buffer = "";
340ŌåÆ    let resolved = false;
341ŌåÆ
342ŌåÆ    const timeout = setTimeout(() => {
343ŌåÆ      if (!resolved) {
344ŌåÆ        resolved = true;
345ŌåÆ        resolve(null);
346ŌåÆ      }
347ŌåÆ    }, timeoutMs);
348ŌåÆ
349ŌåÆ    child.stdout?.on("data", (data: Buffer) => {
350ŌåÆ      buffer += data.toString();
351ŌåÆ      const match = buffer.match(waitFor);
352ŌåÆ      if (match && !resolved) {
353ŌåÆ        resolved = true;
354ŌåÆ        clearTimeout(timeout);
355ŌåÆ        resolve(match[1]);
356ŌåÆ      }
357ŌåÆ    });
358ŌåÆ
359ŌåÆ    child.stderr?.on("data", () => {
360ŌåÆ      // Suppress stderr in normal mode
361ŌåÆ    });
362ŌåÆ
363ŌåÆ    child.on("exit", (code, signal) => {
364ŌåÆ      if (!resolved) {
365ŌåÆ        resolved = true;
366ŌåÆ        clearTimeout(timeout);
367ŌåÆ        resolve(null);
368ŌåÆ      }
369ŌåÆ    });
370ŌåÆ  });
371ŌåÆ}
372ŌåÆ
373ŌåÆ// ŌöĆŌöĆ Web server (static + proxy) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
374ŌåÆ
375ŌåÆfunction createWebServer(backendPort: number, frontendDir: string) {
376ŌåÆ  const hasFrontend = existsSync(frontendDir) && existsSync(join(frontendDir, "index.html"));
377ŌåÆ
378ŌåÆ  const server = createServer(async (req, res) => {
379ŌåÆ    const url = req.url || "/";
380ŌåÆ
381ŌåÆ    if (url.startsWith("/api/") || url.startsWith("/api")) {
382ŌåÆ      return proxyRequest(req, res, backendPort);
383ŌåÆ    }
384ŌåÆ
385ŌåÆ    if (url === "/__backend_port") {
386ŌåÆ      res.writeHead(200, {
387ŌåÆ        "Content-Type": "application/json",
388ŌåÆ        "Access-Control-Allow-Origin": "*",
389ŌåÆ      });
390ŌåÆ      res.end(JSON.stringify({ port: backendPort }));
391ŌåÆ      return;
392ŌåÆ    }
393ŌåÆ
394ŌåÆ    if (hasFrontend) {
395ŌåÆ      serveStaticFile(req, res, frontendDir);
396ŌåÆ    } else {
397ŌåÆ      res.writeHead(200, { "Content-Type": "text/html" });
398ŌåÆ      res.end(`<!DOCTYPE html><html><head><title>Deus IDE</title>
399ŌåÆ<style>body{font-family:system-ui;padding:3rem;background:#0a0a0a;color:#e5e5e5}
400ŌåÆcode{background:#1a1a1a;padding:2px 6px;border-radius:4px;font-size:14px}
401ŌåÆa{color:#22d3ee}</style></head><body>
402ŌåÆ<h1>Deus IDE Server</h1>
403ŌåÆ<p>Backend API: <code>http://localhost:${backendPort}/api</code></p>
404ŌåÆ<p>WebSocket: <code>ws://localhost:${backendPort}/ws</code></p>
405ŌåÆ<p style="color:#a3a3a3">Frontend not built. Run <code>bun run build:web</code> to enable the UI.</p>
406ŌåÆ</body></html>`);
407ŌåÆ    }
408ŌåÆ  });
409ŌåÆ
410ŌåÆ  server.on("upgrade", (req, socket, head) => {
411ŌåÆ    const proxyReq = httpRequest({
412ŌåÆ      hostname: "localhost",
413ŌåÆ      port: backendPort,
414ŌåÆ      path: req.url,
415ŌåÆ      method: req.method,
416ŌåÆ      headers: req.headers,
417ŌåÆ    });
418ŌåÆ
419ŌåÆ    proxyReq.on("upgrade", (_proxyRes: any, proxySocket: any, proxyHead: any) => {
420ŌåÆ      socket.write(
421ŌåÆ        "HTTP/1.1 101 Switching Protocols\r\n" +
422ŌåÆ          Object.entries(_proxyRes.headers)
423ŌåÆ            .map(([k, v]: [string, any]) => `${k}: ${v}`)
424ŌåÆ            .join("\r\n") +
425ŌåÆ          "\r\n\r\n"
426ŌåÆ      );
427ŌåÆ      if (proxyHead.length > 0) socket.write(proxyHead);
428ŌåÆ      proxySocket.pipe(socket);
429ŌåÆ      socket.pipe(proxySocket);
430ŌåÆ    });
431ŌåÆ
432ŌåÆ    proxyReq.on("error", () => socket.end());
433ŌåÆ    proxyReq.end();
434ŌåÆ  });
435ŌåÆ
436ŌåÆ  return server;
437ŌåÆ}
438ŌåÆ
439ŌåÆfunction proxyRequest(
440ŌåÆ  req: import("node:http").IncomingMessage,
441ŌåÆ  res: import("node:http").ServerResponse,
442ŌåÆ  backendPort: number
443ŌåÆ) {
444ŌåÆ  const proxyReq = httpRequest(
445ŌåÆ    {
446ŌåÆ      hostname: "localhost",
447ŌåÆ      port: backendPort,
448ŌåÆ      path: req.url,
449ŌåÆ      method: req.method,
450ŌåÆ      headers: { ...req.headers, host: `localhost:${backendPort}` },
451ŌåÆ    },
452ŌåÆ    (proxyRes) => {
453ŌåÆ      res.writeHead(proxyRes.statusCode || 502, proxyRes.headers);
454ŌåÆ      proxyRes.pipe(res);
455ŌåÆ    }
456ŌåÆ  );
457ŌåÆ
458ŌåÆ  proxyReq.on("error", () => {
459ŌåÆ    res.writeHead(502, { "Content-Type": "application/json" });
460ŌåÆ    res.end(JSON.stringify({ error: "Backend unavailable" }));
461ŌåÆ  });
462ŌåÆ
463ŌåÆ  req.pipe(proxyReq);
464ŌåÆ}
465ŌåÆ
466ŌåÆfunction serveStaticFile(
467ŌåÆ  req: import("node:http").IncomingMessage,
468ŌåÆ  res: import("node:http").ServerResponse,
469ŌåÆ  frontendDir: string
470ŌåÆ) {
471ŌåÆ  let pathname = (req.url || "/").split("?")[0];
472ŌåÆ  if (pathname === "/") pathname = "/index.html";
473ŌåÆ
474ŌåÆ  let filePath = join(frontendDir, pathname);
475ŌåÆ
476ŌåÆ  if (!existsSync(filePath) || statSync(filePath).isDirectory()) {
477ŌåÆ    filePath = join(frontendDir, "index.html");
478ŌåÆ  }
479ŌåÆ
480ŌåÆ  if (!existsSync(filePath)) {
481ŌåÆ    res.writeHead(404);
482ŌåÆ    res.end("Not found");
483ŌåÆ    return;
484ŌåÆ  }
485ŌåÆ
486ŌåÆ  const ext = extname(filePath);
487ŌåÆ  const contentType = MIME_TYPES[ext] || "application/octet-stream";
488ŌåÆ
489ŌåÆ  try {
490ŌåÆ    const content = readFileSync(filePath);
491ŌåÆ    res.writeHead(200, {
492ŌåÆ      "Content-Type": contentType,
493ŌåÆ      "Cache-Control": ext === ".html" ? "no-cache" : "public, max-age=31536000, immutable",
494ŌåÆ    });
495ŌåÆ    res.end(content);
496ŌåÆ  } catch {
497ŌåÆ    res.writeHead(500);
498ŌåÆ    res.end("Internal server error");
499ŌåÆ  }
500ŌåÆ}
501ŌåÆ
502ŌåÆ// ŌöĆŌöĆ Utilities ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
