517ŌåÆ  const os = platform();
518ŌåÆ  const cmd = os === "darwin" ? "open" : os === "win32" ? "start" : "xdg-open";
519ŌåÆ  spawn(cmd, [url], { detached: true, stdio: "ignore" }).unref();
