345ŌåÆ/** Draw a rounded box around content lines */
346ŌåÆexport function box(
347ŌåÆ  lines: string[],
348ŌåÆ  opts?: { padding?: number; borderColor?: (s: string) => string; width?: number }
349ŌåÆ): void {
350ŌåÆ  const { padding = 1, borderColor = c.dim, width } = opts ?? {};
