212ŌåÆ      removeQuerySubs(connId);
213ŌåÆ      removeConnection(connId);
214ŌåÆ    }
215ŌåÆ    unlinkAll();
216ŌåÆ    if (relayUrl) scheduleReconnect();
217ŌåÆ  });
218ŌåÆ
219ŌåÆ  tunnelWs.on("error", (err) => {
