269ŌåÆ/**
270ŌåÆ * Parse simple YAML frontmatter from a SKILL.md file.
271ŌåÆ * Returns key-value pairs from the --- delimited block at the top.
272ŌåÆ */
273ŌåÆfunction parseFrontmatter(content: string): { frontmatter: Record<string, string>; body: string } {
274ŌåÆ  const match = content.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)$/);
275ŌåÆ  if (!match) return { frontmatter: {}, body: content };
276ŌåÆ
277ŌåÆ  const frontmatter: Record<string, string> = {};
278ŌåÆ  match[1].split("\n").forEach((line) => {
279ŌåÆ    const colonIdx = line.indexOf(":");
280ŌåÆ    if (colonIdx > 0) {
281ŌåÆ      const key = line.slice(0, colonIdx).trim();
282ŌåÆ      const value = line
283ŌåÆ        .slice(colonIdx + 1)
284ŌåÆ        .trim()
285ŌåÆ        .replace(/^["']|["']$/g, "");
286ŌåÆ      frontmatter[key] = value;
287ŌåÆ    }
288ŌåÆ  });
289ŌåÆ
290ŌåÆ  return { frontmatter, body: match[2] };
291ŌåÆ}
