 51ŌåÆ
 52ŌåÆ/**
 53ŌåÆ * Wraps an AsyncQueue of raw prompt strings into the async-iterable format
 54ŌåÆ * expected by the Claude Agent SDK. Handles both plain text and JSON-encoded
 55ŌåÆ * content blocks (when user attaches images).
 56ŌåÆ */
 57ŌåÆfunction buildPromptIterable(queue: AsyncQueue<string>, sessionId: string) {
 58ŌåÆ  return (async function* () {
 59ŌåÆ    for await (const message of queue) {
 60ŌåÆ      let content: string | unknown[] = message;
 61ŌåÆ      if (message && message.startsWith("[")) {
 62ŌåÆ        try {
 63ŌåÆ          const parsed = JSON.parse(message);
 64ŌåÆ          if (Array.isArray(parsed) && parsed.length > 0 && parsed[0]?.type) {
 65ŌåÆ            content = parsed;
 66ŌåÆ          }
 67ŌåÆ        } catch {
 68ŌåÆ          // Not valid JSON ŌĆö keep as plain text string
 69ŌåÆ        }
 70ŌåÆ      }
 71ŌåÆ
 72ŌåÆ      yield {
 73ŌåÆ        type: "user" as const,
 74ŌåÆ        message: { role: "user" as const, content },
 75ŌåÆ        parent_tool_use_id: null,
 76ŌåÆ        session_id: sessionId,
 77ŌåÆ      };
 78ŌåÆ    }
 79ŌåÆ  })();
 80ŌåÆ}
