 85ŌåÆ
 86ŌåÆexport class ClaudeAgentHandler implements AgentHandler {
 87ŌåÆ  readonly agentType = "claude" as const;
 88ŌåÆ  readonly capabilities: AgentCapabilities = {
 89ŌåÆ    auth: true,
 90ŌåÆ    workspaceInit: true,
 91ŌåÆ    contextUsage: true,
 92ŌåÆ    permissionMode: true,
 93ŌåÆ    modelSwitch: "in-session",
 94ŌåÆ    multiTurn: true,
 95ŌåÆ    sessionResume: true,
 96ŌåÆ  };
 97ŌåÆ
 98ŌåÆ  initialize(): { success: boolean; error?: string } {
 99ŌåÆ    return initializeClaude();
100ŌåÆ  }
101ŌåÆ
102ŌåÆ  async query(sessionId: string, prompt: string, options: QueryOptions): Promise<void> {
103ŌåÆ    const tQueryStart = Date.now();
104ŌåÆ    console.log(`[TIMING][query] START session=${sessionId} promptLength=${prompt.length}`);
105ŌåÆ    if (blockIfNotInitialized(sessionId)) return;
106ŌåÆ
107ŌåÆ    const session = claudeSessions.get(sessionId);
108ŌåÆ    const modelChanged = session?.currentModel !== options.model;
109ŌåÆ    const maxThinkingTokensChanged =
110ŌåÆ      session?.currentMaxThinkingTokens !== options.maxThinkingTokens;
111ŌåÆ    const settingsChangedFlag = settingsChanged(session?.currentSettings, options);
112ŌåÆ
113ŌåÆ    if (session) {
114ŌåÆ      session.turnId = options.turnId;
115ŌåÆ      session.cwd = options.cwd;
116ŌåÆ    }
117ŌåÆ
118ŌåÆ    const canReuse =
119ŌåÆ      isSessionActive(session) && options.shouldResetGenerator !== true && !settingsChangedFlag;
120ŌåÆ
121ŌåÆ    if (canReuse) {
122ŌåÆ      console.log(
123ŌåÆ        `[TIMING][query] REUSE session=${sessionId} decisionTime=${Date.now() - tQueryStart}ms`
124ŌåÆ      );
125ŌåÆ
126ŌåÆ      // Hot-swap model if it changed
127ŌåÆ      if (modelChanged && session) {
128ŌåÆ        const query = claudeQueries.get(sessionId);
129ŌåÆ        if (query) {
130ŌåÆ          const envVars = options.providerEnvVars ? parseEnvString(options.providerEnvVars) : {};
131ŌåÆ          const mappedModel = mapModelForProvider(options.model, envVars);
132ŌåÆ          console.log(
133ŌåÆ            `Model changed from ${session.currentModel} to ${options.model}, using setModel callback`
134ŌåÆ          );
135ŌåÆ          try {
136ŌåÆ            await query.setModel(mappedModel);
137ŌåÆ            const updatedSession = claudeSessions.get(sessionId);
138ŌåÆ            if (updatedSession) updatedSession.currentModel = options.model;
139ŌåÆ          } catch (error) {
140ŌåÆ            console.error(`Failed to update model: ${getErrorMessage(error)}`);
141ŌåÆ          }
142ŌåÆ        }
143ŌåÆ      }
144ŌåÆ
145ŌåÆ      // Hot-swap maxThinkingTokens if it changed
146ŌåÆ      const query = claudeQueries.get(sessionId);
147ŌåÆ      if (maxThinkingTokensChanged && session && query) {
148ŌåÆ        try {
149ŌåÆ          await query.setMaxThinkingTokens(options.maxThinkingTokens ?? null);
150ŌåÆ          session.currentMaxThinkingTokens = options.maxThinkingTokens;
151ŌåÆ        } catch (error) {
152ŌåÆ          console.error(`Failed to update maxThinkingTokens: ${getErrorMessage(error)}`);
153ŌåÆ        }
154ŌåÆ      }
155ŌåÆ
156ŌåÆ      // Update permission mode if provided
157ŌåÆ      if (query && options.permissionMode) {
158ŌåÆ        try {
159ŌåÆ          await query.setPermissionMode(options.permissionMode as PermissionMode);
160ŌåÆ        } catch (error) {
161ŌåÆ          console.error(`Failed to update permission mode: ${getErrorMessage(error)}`);
162ŌåÆ        }
163ŌåÆ      }
164ŌåÆ
165ŌåÆ      // Push the new prompt into the existing generator
166ŌåÆ      // isSessionActive type guard narrows sendMessage to be defined
167ŌåÆ      session.sendMessage(prompt);
168ŌåÆ    } else {
169ŌåÆ      const reason = !session
170ŌåÆ        ? "new session"
171ŌåÆ        : !isSessionActive(session)
172ŌåÆ          ? "no active generator"
173ŌåÆ          : options.shouldResetGenerator
174ŌåÆ            ? "should reset generator"
175ŌåÆ            : "settings changed";
176ŌåÆ      console.log(
177ŌåÆ        `[TIMING][query] NEW_GENERATOR session=${sessionId} reason="${reason}" decisionTime=${Date.now() - tQueryStart}ms`
178ŌåÆ      );
179ŌåÆ
180ŌåÆ      if (isSessionActive(session)) {
181ŌåÆ        terminateSession(sessionId);
182ŌåÆ      }
183ŌåÆ
184ŌåÆ      const newSession: SessionState = {
185ŌåÆ        currentSettings: {
186ŌåÆ          providerEnvVars: options.providerEnvVars,
187ŌåÆ          additionalDirectories: options.additionalDirectories,
188ŌåÆ          chromeEnabled: options.chromeEnabled,
189ŌåÆ          strictDataPrivacy: options.strictDataPrivacy,
190ŌåÆ        },
191ŌåÆ        currentModel: options.model,
192ŌåÆ        currentMaxThinkingTokens: options.maxThinkingTokens,
193ŌåÆ        turnId: options.turnId,
194ŌåÆ        cwd: options.cwd,
195ŌåÆ      };
196ŌåÆ      claudeSessions.set(sessionId, newSession);
197ŌåÆ
198ŌåÆ      void this.processWithGenerator(sessionId, prompt, options);
199ŌåÆ    }
200ŌåÆ  }
201ŌåÆ
202ŌåÆ  async cancel(sessionId: string): Promise<void> {
203ŌåÆ    console.log("Handling Claude cancel request for session:", sessionId);
204ŌåÆ    if (blockIfNotInitialized(sessionId)) return;
205ŌåÆ
206ŌåÆ    const existingQuery = claudeQueries.get(sessionId);
207ŌåÆ    const session = claudeSessions.get(sessionId);
208ŌåÆ
209ŌåÆ    if (isSessionActive(session) && existingQuery) {
210ŌåÆ      console.log(`Force-closing query for session ${sessionId}`);
211ŌåÆ
212ŌåÆ      // 1. Flag cancellation so the post-loop path persists the cancelled message
213ŌåÆ      session.cancelledByUser = true;
214ŌåÆ
215ŌåÆ      // 2. Create checkpoint before process dies
216ŌåÆ      if (session.turnId && session.cwd) {
217ŌåÆ        createCheckpoint(sessionId, session.turnId, "end", session.cwd, "claudeHandler");
218ŌåÆ      }
219ŌåÆ
220ŌåÆ      // 3. Force kill: close() terminates CLI subprocess + all children + MCP transports
221ŌåÆ      existingQuery.close();
222ŌåÆ
223ŌåÆ      // 4. Signal prompt generator to stop ŌĆö finally block owns cleanup
224ŌåÆ      terminateSession(sessionId);
225ŌåÆ    } else {
226ŌåÆ      console.log(`No active session found for ${sessionId} to cancel`);
227ŌåÆ    }
228ŌåÆ  }
