230ŌåÆ  reset(sessionId: string): void {
231ŌåÆ    console.log(`Handling reset generator request for session: ${sessionId}`);
232ŌåÆ    const session = claudeSessions.get(sessionId);
233ŌåÆ    if (session) {
234ŌåÆ      console.log(`Terminating generator for session ${sessionId} on reset request`);
235ŌåÆ      terminateSession(sessionId);
236ŌåÆ    }
237ŌåÆ  }
