389ŌåÆ  /**
390ŌåÆ   * Creates an async-generator-backed Claude SDK session.
391ŌåÆ   * Uses a message queue for multi-turn conversations.
392ŌåÆ   */
393ŌåÆ  private async processWithGenerator(
394ŌåÆ    sessionId: string,
395ŌåÆ    initialPrompt: string,
396ŌåÆ    options: QueryOptions
397ŌåÆ  ): Promise<void> {
398ŌåÆ    const tProcessStart = Date.now();
399ŌåÆ    const generatorId = `${sessionId}/${tProcessStart}`;
400ŌåÆ    const session = claudeSessions.get(sessionId);
401ŌåÆ    if (!session) {
402ŌåÆ      console.error(`[${generatorId}] Session ${sessionId} not found`);
403ŌåÆ      return;
404ŌåÆ    }
405ŌåÆ    console.log(`[TIMING][${generatorId}] processWithGenerator START`);
406ŌåÆ
407ŌåÆ    // --- Message queue for multi-turn conversations ---
408ŌåÆ    const promptQueue = new AsyncQueue<string>([initialPrompt]);
409ŌåÆ
410ŌåÆ    session.sendMessage = (message: string) => {
411ŌåÆ      console.log(`[${generatorId}] Pushing message to queue`);
412ŌåÆ      promptQueue.push(message);
413ŌåÆ    };
414ŌåÆ
415ŌåÆ    session.sendTerminate = () => {
416ŌåÆ      console.log(`[${generatorId}] Sending terminate signal`);
417ŌåÆ      promptQueue.close();
418ŌåÆ    };
419ŌåÆ
420ŌåÆ    // Mutable context accumulated during the streaming loop.
421ŌåÆ    const ctx = createStreamContext();
422ŌåÆ
423ŌåÆ    try {
424ŌåÆ      // Build environment using shared env-builder
425ŌåÆ      const tEnvStart = Date.now();
426ŌåÆ      const envForClaude = buildAgentEnvironment({
427ŌåÆ        providerEnvVars: options?.providerEnvVars,
428ŌåÆ        deusEnv: options?.deusEnv,
429ŌåÆ        ghToken: options?.ghToken,
430ŌåÆ        extraEnv: { CLAUDE_CODE_ENABLE_TASKS: "true" },
431ŌåÆ      });
432ŌåÆ      console.log(
433ŌåÆ        `[TIMING][${generatorId}] buildAgentEnvironment took ${Date.now() - tEnvStart}ms`
434ŌåÆ      );
435ŌåÆ
436ŌåÆ      // Resume is now passed in turn/start params from the backend (which owns the DB
437ŌåÆ      // and knows the agent_session_id). The agent-server is stateless ŌĆö no DB lookups.
438ŌåÆ      if (options.resume) {
439ŌåÆ        console.log(
440ŌåÆ          `[RESUME-DEBUG][${generatorId}] Attempting resume with agent_session_id=${options.resume} for session=${sessionId}`
441ŌåÆ        );
442ŌåÆ      }
443ŌåÆ
444ŌåÆ      // Build SDK options using the dedicated builder
445ŌåÆ      const tSdkOptsStart = Date.now();
446ŌåÆ      const sdkOptions = buildSdkOptions(sessionId, envForClaude, options);
447ŌåÆ      console.log(`[TIMING][${generatorId}] buildSdkOptions took ${Date.now() - tSdkOptsStart}ms`);
448ŌåÆ
449ŌåÆ      const promptInput = buildPromptIterable(promptQueue, sessionId);
450ŌåÆ
451ŌåÆ      // Start the SDK query
452ŌåÆ      console.log(
453ŌåÆ        `[TIMING][${generatorId}] SDK spawn starting (elapsed since processStart: ${Date.now() - tProcessStart}ms)`
454ŌåÆ      );
455ŌåÆ      console.log(
456ŌåÆ        `[RESUME-DEBUG][${generatorId}] SDK options: resume=${sdkOptions.resume ?? "none"} cwd=${sdkOptions.cwd} model=${sdkOptions.model} permissionMode=${sdkOptions.permissionMode}`
457ŌåÆ      );
458ŌåÆ      const tSdkSpawn = Date.now();
459ŌåÆ      const queryResult = claudeSDK({ prompt: promptInput, options: sdkOptions });
460ŌåÆ      console.log(
461ŌåÆ        `[TIMING][${generatorId}] claudeSDK() constructor returned in ${Date.now() - tSdkSpawn}ms`
462ŌåÆ      );
463ŌåÆ
464ŌåÆ      claudeQueries.set(sessionId, queryResult);
465ŌåÆ      session.generator = queryResult[Symbol.asyncIterator]();
466ŌåÆ
467ŌåÆ      // Per-message options (constant for the lifetime of this generator)
468ŌåÆ      const msgOpts: ProcessMessageOptions = {
469ŌåÆ        sessionId,
470ŌåÆ        generatorId,
471ŌåÆ        model: options.model || "opus",
472ŌåÆ        isResume: !!options.resume,
473ŌåÆ      };
474ŌåÆ
475ŌåÆ      // Stream messages back to the frontend and persist to DB.
476ŌåÆ      // IMPORTANT: Persist to DB BEFORE notifying frontend, so messages
477ŌåÆ      // are in the DB when the frontend receives the event and fetches them.
478ŌåÆ      const tStreamStart = Date.now();
479ŌåÆ      for await (const message of queryResult) {
480ŌåÆ        ctx.messageCount++;
481ŌåÆ        if (ctx.firstMessageTime === null) {
482ŌåÆ          ctx.firstMessageTime = Date.now();
483ŌåÆ          console.log(
484ŌåÆ            `[TIMING][${generatorId}] FIRST_MESSAGE received after ${ctx.firstMessageTime - tSdkSpawn}ms (type=${(message as any)?.type})`
485ŌåÆ          );
486ŌåÆ        }
487ŌåÆ        // Deserialize, persist, and forward to frontend.
488ŌåÆ        // See message-processor.ts for the critical side-effect ordering.
489ŌåÆ        if (message) {
490ŌåÆ          const cleanMessage = deserializeMessage(message, generatorId);
491ŌåÆ          if (!cleanMessage) continue;
492ŌåÆ
493ŌåÆ          processMessage(cleanMessage, ctx, session, msgOpts);
494ŌåÆ
495ŌåÆ          // Log per-message timing for first 5 messages, then every 10th
496ŌåÆ          if (ctx.messageCount <= 5 || ctx.messageCount % 10 === 0) {
497ŌåÆ            console.log(
498ŌåÆ              `[TIMING][${generatorId}] msg#${ctx.messageCount} type=${cleanMessage.type}${cleanMessage.type === "result" ? "/" + cleanMessage.subtype : ""} elapsed=${Date.now() - tStreamStart}ms`
499ŌåÆ            );
500ŌåÆ          }
501ŌåÆ        }
502ŌåÆ      }
503ŌåÆ
504ŌåÆ      console.log(
505ŌåÆ        `[TIMING][${generatorId}] STREAM_COMPLETE messages=${ctx.messageCount} totalStreamTime=${Date.now() - tStreamStart}ms totalProcessTime=${Date.now() - tProcessStart}ms`
506ŌåÆ      );
507ŌåÆ
508ŌåÆ      // Post-loop: stream ended cleanly (prompt queue closed or SDK finished).
509ŌåÆ      // Turn-level idle is already set by processMessage on result/success.
510ŌåÆ      // This handles conversation-end: cancel persistence only.
511ŌåÆ      if (
512ŌåÆ        handleCancellation(sessionId, "claude", options.model || "opus", !!session.cancelledByUser)
513ŌåÆ      ) {
514ŌåÆ        console.log(`[${generatorId}] Session cancelled by user: ${sessionId}`);
515ŌåÆ        return;
516ŌåÆ      }
517ŌåÆ      console.log(`[${generatorId}] Stream completed: ${sessionId}`);
518ŌåÆ    } catch (error) {
519ŌåÆ      // Cancel takes priority ŌĆö abort signal can surface as a thrown error.
520ŌåÆ      if (
521ŌåÆ        handleCancellation(sessionId, "claude", options.model || "opus", !!session.cancelledByUser)
522ŌåÆ      ) {
523ŌåÆ        console.log(`[${generatorId}] Session cancelled by user (catch): ${sessionId}`);
524ŌåÆ        return;
525ŌåÆ      }
526ŌåÆ
527ŌåÆ      // Post-success process exit: the CLI shuts down between turns and the
528ŌåÆ      // SDK reports the signal-based exit as an error. Expected cleanup, not failure.
529ŌåÆ      if (ctx.querySucceeded) {
530ŌåÆ        console.log(`[${generatorId}] Process exited after successful query (expected cleanup)`);
531ŌåÆ        return;
532ŌåÆ      }
533ŌåÆ
534ŌåÆ      // Genuine error ŌĆö check if this generator still owns the session.
535ŌåÆ      // A rapid re-query can replace the session before the catch runs.
536ŌåÆ      const errorName = error instanceof Error ? error.name : "non-Error";
537ŌåÆ      const errorStack =
538ŌåÆ        error instanceof Error ? error.stack?.split("\n").slice(0, 5).join("\n") : "no stack";
539ŌåÆ      const extraProps =
540ŌåÆ        error instanceof Error
541ŌåÆ          ? Object.getOwnPropertyNames(error)
542ŌåÆ              .filter((k) => !["message", "stack", "name"].includes(k))
543ŌåÆ              .map((k) => `${k}=${JSON.stringify((error as any)[k])}`)
544ŌåÆ              .join(" ")
545ŌåÆ          : "";
546ŌåÆ
547ŌåÆ      const classified = classifyError(error);
548ŌåÆ
549ŌåÆ      console.error(
550ŌåÆ        `[${generatorId}] Error in Claude query [${classified.category}]:`,
551ŌåÆ        classified.message
552ŌåÆ      );
553ŌåÆ      console.error(
554ŌåÆ        `[${generatorId}] Error details:`,
555ŌåÆ        `name=${errorName}`,
556ŌåÆ        `wasResume=${!!options.resume}`,
557ŌåÆ        `resumeId=${options.resume ?? "none"}`,
558ŌåÆ        `querySucceeded=${ctx.querySucceeded}`,
559ŌåÆ        `messageCount=${ctx.messageCount}`,
560ŌåÆ        extraProps ? `extraProps={${extraProps}}` : "extraProps={}"
561ŌåÆ      );
562ŌåÆ      console.error(`[${generatorId}] Stack (top 5):\n${errorStack}`);
563ŌåÆ
564ŌåÆ      if (claudeSessions.owns(sessionId, session)) {
565ŌåÆ        handleQueryError(sessionId, "claude", error, (c) => {
566ŌåÆ          if (c.category !== "process_exit") return c.message;
567ŌåÆ          const parts: string[] = [c.message];
568ŌåÆ          if (options.resume) parts.push("(resumed session)");
569ŌåÆ          if (ctx.messageCount > 0) {
570ŌåÆ            parts.push(`after ${ctx.messageCount} message${ctx.messageCount !== 1 ? "s" : ""}`);
571ŌåÆ          } else {
572ŌåÆ            parts.push("before receiving any messages");
573ŌåÆ          }
574ŌåÆ          if (ctx.lastResultError) parts.push(`ŌĆö ${ctx.lastResultError}`);
575ŌåÆ          if (extraProps) parts.push(`[${extraProps}]`);
576ŌåÆ          return parts.join(" ");
577ŌåÆ        });
578ŌåÆ      }
579ŌåÆ    } finally {
580ŌåÆ      // Only clean up if this generator still owns the session.
581ŌåÆ      // A rapid re-query can replace the session before this finally runs;
582ŌåÆ      // blindly deleting would wipe the new session's state.
583ŌåÆ      if (claudeSessions.owns(sessionId, session)) {
584ŌåÆ        claudeQueries.delete(sessionId);
585ŌåÆ        claudeSessions.delete(sessionId);
586ŌåÆ      }
587ŌåÆ    }
588ŌåÆ  }
589ŌåÆ}
