180ŌåÆ    try {
181ŌåÆ      EventBroadcaster.sendError({
182ŌåÆ        id: sessionId,
183ŌåÆ        type: "error",
184ŌåÆ        error: errorMsg,
185ŌåÆ        agentType,
186ŌåÆ        category: "internal",
187ŌåÆ      });
188ŌåÆ    } catch (error) {
189ŌåÆ      console.warn(`[CLI-DISCOVERY] Failed to emit init error to frontend:`, error);
190ŌåÆ    }
191ŌåÆ    // Emit canonical error event so the backend updates session status.
192ŌåÆ    // The backend set status='working' before forwarding turn/start to the agent-server.
193ŌåÆ    try {
