  2ŌåÆ// Shared environment construction for all agent handlers.
  3ŌåÆ// Builds the 6-layer environment: shell env ŌåÆ process.env ŌåÆ extra env ŌåÆ
  4ŌåÆ// deusEnv ŌåÆ providerEnvVars ŌåÆ ghToken.
  5ŌåÆ
  6ŌåÆimport { getShellEnvironment } from "./shell-env";
