  8ŌåÆ/**
  9ŌåÆ * Parses a multi-line "KEY=value" env string (supports export prefix, quoting).
 10ŌåÆ * Used to parse user-provided environment variable overrides.
 11ŌåÆ */
 12ŌåÆexport function parseEnvString(envString: string): Record<string, string> {
 13ŌåÆ  const result: Record<string, string> = {};
 14ŌåÆ  const lines = envString.split("\n");
 15ŌåÆ  let i = 0;
 16ŌåÆ
 17ŌåÆ  while (i < lines.length) {
 18ŌåÆ    let line = lines[i].trim();
 19ŌåÆ    if (!line || line.startsWith("#")) {
 20ŌåÆ      i++;
 21ŌåÆ      continue;
 22ŌåÆ    }
 23ŌåÆ    if (line.startsWith("export ")) {
 24ŌåÆ      line = line.substring(7).trim();
 25ŌåÆ    }
 26ŌåÆ
 27ŌåÆ    const equalIndex = line.indexOf("=");
 28ŌåÆ    if (equalIndex === -1) {
 29ŌåÆ      i++;
 30ŌåÆ      continue;
 31ŌåÆ    }
 32ŌåÆ
 33ŌåÆ    const key = line.substring(0, equalIndex).trim();
 34ŌåÆ    if (!key) {
 35ŌåÆ      i++;
 36ŌåÆ      continue;
 37ŌåÆ    }
 38ŌåÆ
 39ŌåÆ    let value = line.substring(equalIndex + 1).trim();
 40ŌåÆ
 41ŌåÆ    // Handle quoted values (may span multiple lines)
 42ŌåÆ    if ((value.startsWith('"') || value.startsWith("'")) && value.length > 1) {
 43ŌåÆ      const quote = value[0];
 44ŌåÆ      let endQuoteIndex = value.indexOf(quote, 1);
 45ŌåÆ      while (endQuoteIndex === -1 && i + 1 < lines.length) {
 46ŌåÆ        i++;
 47ŌåÆ        value += "\n" + lines[i];
 48ŌåÆ        endQuoteIndex = value.indexOf(quote, 1);
 49ŌåÆ      }
 50ŌåÆ      if (endQuoteIndex !== -1) {
 51ŌåÆ        value = value.substring(1, endQuoteIndex);
 52ŌåÆ      }
 53ŌåÆ    }
 54ŌåÆ
 55ŌåÆ    result[key] = value;
 56ŌåÆ    i++;
 57ŌåÆ  }
 58ŌåÆ  return result;
 59ŌåÆ}
