 61ŌåÆ/**
 62ŌåÆ * Builds the environment variable object for an agent session.
 63ŌåÆ *
 64ŌåÆ * Layer precedence (later layers override earlier):
 65ŌåÆ * 1. Shell environment (login shell capture)
 66ŌåÆ * 2. process.env (agent-server process environment)
 67ŌåÆ * 3. extraEnv (agent-specific static env vars, e.g. CLAUDE_CODE_ENABLE_TASKS)
 68ŌåÆ * 4. deusEnv (from frontend options)
 69ŌåÆ * 5. providerEnvVars (user-configured env string, empty values delete keys)
 70ŌåÆ * 6. ghToken (sets GH_TOKEN if provided)
 71ŌåÆ */
 72ŌåÆexport function buildAgentEnvironment(options?: {
 73ŌåÆ  providerEnvVars?: string;
 74ŌåÆ  deusEnv?: Record<string, string>;
 75ŌåÆ  ghToken?: string;
 76ŌåÆ  extraEnv?: Record<string, string>;
 77ŌåÆ}): Record<string, string> {
 78ŌåÆ  const env: Record<string, string> = {};
 79ŌåÆ
 80ŌåÆ  // Layer 1: Shell environment
 81ŌåÆ  try {
 82ŌåÆ    Object.assign(env, getShellEnvironment());
 83ŌåÆ  } catch (error) {
 84ŌåÆ    console.error("Failed to load shell environment, continuing without it:", error);
 85ŌåÆ  }
 86ŌåÆ
 87ŌåÆ  // Layer 2: process.env
 88ŌåÆ  for (const [key, value] of Object.entries(process.env)) {
 89ŌåÆ    if (value !== undefined) env[key] = value;
 90ŌåÆ  }
 91ŌåÆ
 92ŌåÆ  // Layer 3: Extra static env vars
 93ŌåÆ  if (options?.extraEnv) {
 94ŌåÆ    for (const [key, value] of Object.entries(options.extraEnv)) {
 95ŌåÆ      env[key] = value;
 96ŌåÆ    }
 97ŌåÆ  }
 98ŌåÆ
 99ŌåÆ  // Layer 4: Deus env (from frontend)
100ŌåÆ  if (options?.deusEnv) {

100ŌåÆ  if (options?.deusEnv) {
101ŌåÆ    for (const [key, value] of Object.entries(options.deusEnv)) {
102ŌåÆ      env[key] = value;
103ŌåÆ    }
104ŌåÆ  }
105ŌåÆ
106ŌåÆ  // Layer 5: User-configured env vars (empty values delete keys)
107ŌåÆ  if (options?.providerEnvVars) {
108ŌåÆ    const parsed = parseEnvString(options.providerEnvVars);
109ŌåÆ    for (const [key, value] of Object.entries(parsed)) {
110ŌåÆ      if (value === "") delete env[key];
111ŌåÆ      else env[key] = value;
112ŌåÆ    }
113ŌåÆ  }
114ŌåÆ
115ŌåÆ  // Layer 6: GitHub token
116ŌåÆ  if (options?.ghToken) env["GH_TOKEN"] = options.ghToken;
117ŌåÆ
118ŌåÆ  return env;
119ŌåÆ}
