 56ŌåÆexport function createCanUseTool(sessionId: string, workingDirectory: string | undefined) {
 57ŌåÆ  return async (toolName: string, input: any, _toolOptions: any) => {
 58ŌåÆ    // Handle plan mode exit approval
 59ŌåÆ    if (toolName === "ExitPlanMode") {
 60ŌåÆ      const currentSession = claudeSessions.get(sessionId);
 61ŌåÆ
 62ŌåÆ      let response: { approved: boolean; turnId?: string };
 63ŌåÆ      try {
 64ŌåÆ        response = await EventBroadcaster.requestExitPlanMode({
 65ŌåÆ          sessionId,
 66ŌåÆ          toolInput: input,
 67ŌåÆ        });
 68ŌåÆ      } catch (err) {
 69ŌåÆ        console.error("[canUseTool] ExitPlanMode request failed:", err);
 70ŌåÆ        return {
 71ŌåÆ          behavior: "deny",
 72ŌåÆ          message:
 73ŌåÆ            "Plan approval request failed (frontend may be unavailable or timed out). " +
 74ŌåÆ            "Please wait for the user to reconnect and try again.",
 75ŌåÆ          interrupt: true,
 76ŌåÆ        };
 77ŌåÆ      }
 78ŌåÆ
 79ŌåÆ      if (response.approved) {
 80ŌåÆ        if (response.turnId && currentSession?.cwd) {
 81ŌåÆ          const oldTurnId = currentSession.turnId;
 82ŌåÆ          const newTurnId = response.turnId;
 83ŌåÆ
 84ŌåÆ          if (oldTurnId) {
 85ŌåÆ            createCheckpoint(
 86ŌåÆ              sessionId,
 87ŌåÆ              oldTurnId,
 88ŌåÆ              "end",
 89ŌåÆ              currentSession.cwd,
 90ŌåÆ              "claudeHandler:exitPlanMode"
 91ŌåÆ            );
 92ŌåÆ          }
 93ŌåÆ          currentSession.turnId = newTurnId;
 94ŌåÆ          createCheckpoint(
 95ŌåÆ            sessionId,
 96ŌåÆ            newTurnId,
 97ŌåÆ            "start",
 98ŌåÆ            currentSession.cwd,
 99ŌåÆ            "claudeHandler:exitPlanMode"
100ŌåÆ          );
101ŌåÆ        }
102ŌåÆ
103ŌåÆ        return {
104ŌåÆ          behavior: "allow",
105ŌåÆ          updatedInput: input,
106ŌåÆ          updatedPermissions: [{ type: "setMode", mode: "default", destination: "session" }],
107ŌåÆ        };
108ŌåÆ      } else {
109ŌåÆ        return {
110ŌåÆ          behavior: "deny",
111ŌåÆ          message: "Plan denied by user. Please await a further message for an explanation.",
112ŌåÆ          interrupt: true,
