116ŌåÆ
117ŌåÆ    // Guard edit tools against writing outside allowed directories
118ŌåÆ    const editTools = ["Edit", "MultiEdit", "Write", "NotebookEdit"];
119ŌåÆ    if (editTools.includes(toolName)) {
120ŌåÆ      if (workingDirectory) {
121ŌåÆ        const filePath = input.file_path || input.notebook_path || "";
122ŌåÆ        if (filePath) {
123ŌåÆ          let normalizedFilePath: string;
124ŌåÆ          try {
125ŌåÆ            normalizedFilePath = fs.realpathSync(filePath);
126ŌåÆ          } catch {
127ŌåÆ            normalizedFilePath = path.resolve(filePath);
128ŌåÆ          }
129ŌåÆ          const additionalDirectories =
130ŌåÆ            claudeSessions.get(sessionId)?.currentSettings?.additionalDirectories ?? [];
131ŌåÆ          const allAllowedDirs = [workingDirectory, ...additionalDirectories].map((dir) => {
132ŌåÆ            try {
133ŌåÆ              return fs.realpathSync(dir);
134ŌåÆ            } catch {
135ŌåÆ              return path.resolve(dir);
136ŌåÆ            }
137ŌåÆ          });
138ŌåÆ
139ŌåÆ          if (
140ŌåÆ            !allAllowedDirs.some(
141ŌåÆ              (dir) => normalizedFilePath === dir || normalizedFilePath.startsWith(dir + path.sep)
142ŌåÆ            )
143ŌåÆ          ) {
144ŌåÆ            console.log(
145ŌåÆ              `[canUseTool] BLOCKED: ${toolName} on ${filePath} - outside: ${allAllowedDirs.join(", ")}`
146ŌåÆ            );
147ŌåÆ            return {
148ŌåÆ              behavior: "deny",
149ŌåÆ              message: `Cannot edit files outside allowed directories (${allAllowedDirs.join(", ")}). Attempted: ${filePath}`,
150ŌåÆ            };
151ŌåÆ          }
