  2ŌåÆimport Database from "better-sqlite3";
  3ŌåÆimport { existsSync, readdirSync } from "fs";
  4ŌåÆimport { homedir } from "os";
  5ŌåÆimport { join, basename } from "path";
  6ŌåÆimport type { RecentProject } from "@shared/types/onboarding";
  7ŌåÆ
  8ŌåÆconst app = new Hono();
