 10ŌåÆapp.get("/onboarding/recent-projects", (c) => {
 11ŌåÆ  const home = homedir();
 12ŌåÆ  const projects: RecentProject[] = [];
 13ŌåÆ  const seenPaths = new Set<string>();
 14ŌåÆ
 15ŌåÆ  // Read from Cursor state.vscdb
 16ŌåÆ  const cursorDbPath = join(
 17ŌåÆ    home,
 18ŌåÆ    "Library/Application Support/Cursor/User/globalStorage/state.vscdb"
 19ŌåÆ  );
 20ŌåÆ  readVscdbProjects(cursorDbPath, "cursor", projects, seenPaths);
 21ŌåÆ
 22ŌåÆ  // Read from VSCode state.vscdb
 23ŌåÆ  const vscodeDbPath = join(
 24ŌåÆ    home,
 25ŌåÆ    "Library/Application Support/Code/User/globalStorage/state.vscdb"
 26ŌåÆ  );
 27ŌåÆ  readVscdbProjects(vscodeDbPath, "vscode", projects, seenPaths);
 28ŌåÆ
 29ŌåÆ  // Read from Claude projects directory
 30ŌåÆ  readClaudeProjects(join(home, ".claude/projects"), projects, seenPaths);
 31ŌåÆ
 32ŌåÆ  return c.json({ projects: projects.slice(0, 30) });
 33ŌåÆ});
 34ŌåÆ
 35ŌåÆ// Worktree directories created by AI coding tools ŌĆö filter these from recent projects
 36ŌåÆ// so only root repos are shown, not individual worktree checkouts.
 37ŌåÆconst WORKTREE_SEGMENTS = [
 38ŌåÆ  "/.deus/", // Deus worktrees
 39ŌåÆ  "/.conductor/", // OpenDevs worktrees
 40ŌåÆ  "/.claude/worktrees/", // Claude Code worktrees
 41ŌåÆ  "/.cursor/worktrees/", // Cursor parallel agent worktrees
 42ŌåÆ  "/copilot-worktree/", // GitHub Copilot CLI worktrees
 43ŌåÆ];
 44ŌåÆ
 45ŌåÆfunction isWorktreePath(fsPath: string): boolean {
 46ŌåÆ  return WORKTREE_SEGMENTS.some((seg) => fsPath.includes(seg));
 47ŌåÆ}
 48ŌåÆ
 49ŌåÆfunction readVscdbProjects(
 50ŌåÆ  dbPath: string,
 51ŌåÆ  source: "cursor" | "vscode",
 52ŌåÆ  projects: RecentProject[],
 53ŌåÆ  seen: Set<string>
 54ŌåÆ) {
 55ŌåÆ  if (!existsSync(dbPath)) return;
 56ŌåÆ  let db: InstanceType<typeof Database> | undefined;
 57ŌåÆ  try {
 58ŌåÆ    db = new Database(dbPath, { readonly: true });
 59ŌåÆ    const row = db
 60ŌåÆ      .prepare("SELECT value FROM ItemTable WHERE key = 'history.recentlyOpenedPathsList'")
 61ŌåÆ      .get() as { value: string } | undefined;
 62ŌåÆ
 63ŌåÆ    if (!row?.value) return;
 64ŌåÆ    const data = JSON.parse(row.value);
 65ŌåÆ    const entries = data.entries || [];
 66ŌåÆ
 67ŌåÆ    for (const entry of entries) {
 68ŌåÆ      const uri = entry.folderUri;
 69ŌåÆ      if (!uri || !uri.startsWith("file://")) continue;
 70ŌåÆ      const fsPath = decodeURIComponent(uri.replace("file://", ""));
 71ŌåÆ      if (seen.has(fsPath) || isWorktreePath(fsPath) || !existsSync(fsPath)) continue;
 72ŌåÆ      seen.add(fsPath);
 73ŌåÆ      projects.push({ path: fsPath, name: basename(fsPath), source });
 74ŌåÆ    }
 75ŌåÆ  } catch {
 76ŌåÆ    // Silently skip if DB is locked or malformed
 77ŌåÆ  } finally {
 78ŌåÆ    db?.close();
 79ŌåÆ  }
 80ŌåÆ}
 81ŌåÆ
 82ŌåÆfunction readClaudeProjects(dir: string, projects: RecentProject[], seen: Set<string>) {
 83ŌåÆ  if (!existsSync(dir)) return;
 84ŌåÆ  try {
 85ŌåÆ    const entries = readdirSync(dir, { withFileTypes: true });
 86ŌåÆ    for (const entry of entries) {
 87ŌåÆ      if (!entry.isDirectory()) continue;
 88ŌåÆ      // Claude encodes paths: leading dash + dashes as path separators
 89ŌåÆ      // e.g., "-Users-zvada-Developer-myproject" -> "/Users/zvada/Developer/myproject"
 90ŌåÆ      const decoded = entry.name.replace(/-/g, "/");
 91ŌåÆ      if (!decoded.startsWith("/")) continue;
 92ŌåÆ      if (seen.has(decoded) || isWorktreePath(decoded) || !existsSync(decoded)) continue;
 93ŌåÆ      seen.add(decoded);
 94ŌåÆ      projects.push({ path: decoded, name: basename(decoded), source: "claude" });
 95ŌåÆ    }
 96ŌåÆ  } catch {
 97ŌåÆ    // Silently skip
 98ŌåÆ  }
 99ŌåÆ}
