 1ŌåÆ// agent-server/agents/environment/shell-env.ts
 2ŌåÆ// Captures the user's login-shell environment so child processes (Claude SDK)
 3ŌåÆ// inherit PATH, NVM, pyenv, etc. without manual configuration.
 4ŌåÆ
 5ŌåÆimport { execFileSync } from "child_process";
 6ŌåÆimport { stripVTControlCharacters } from "util";
 7ŌåÆ
 8ŌåÆlet shellEnvironment: Record<string, string> | null = null;
 9ŌåÆ
10ŌåÆconst DELIMITER = "_SHELL_ENV_DELIMITER_";
11ŌåÆ
12ŌåÆfunction parseEnv(output: string): Record<string, string> {
13ŌåÆ  const envSection = output.split(DELIMITER)[1];
14ŌåÆ  if (!envSection) {
15ŌåÆ    return {};
16ŌåÆ  }
17ŌåÆ
18ŌåÆ  const env: Record<string, string> = {};
19ŌåÆ  for (const line of stripVTControlCharacters(envSection).split("\n").filter(Boolean)) {
20ŌåÆ    const separatorIndex = line.indexOf("=");
21ŌåÆ    if (separatorIndex > 0) {
22ŌåÆ      const key = line.substring(0, separatorIndex);
23ŌåÆ      const value = line.substring(separatorIndex + 1);
24ŌåÆ      env[key] = value;
25ŌåÆ    }
26ŌåÆ  }
27ŌåÆ  return env;
28ŌåÆ}
29ŌåÆ
30ŌåÆ/**
31ŌåÆ * Keys stripped from the shell environment to prevent auth interference.
32ŌåÆ * These are provider-specific keys that the user may have set globally
33ŌåÆ * but that should not leak into the Deus-managed Claude session.
34ŌåÆ */
35ŌåÆconst STRIPPED_ENV_KEYS = [
36ŌåÆ  "ANTHROPIC_API_KEY",
37ŌåÆ  "OPENAI_API_KEY",
38ŌåÆ  "CLAUDE_CODE_USE_BEDROCK",
39ŌåÆ  "CLAUDE_CODE_USE_VERTEX",
40ŌåÆ];
41ŌåÆ
42ŌåÆ/**
43ŌåÆ * Lazily captures and returns the user's interactive login-shell environment.
44ŌåÆ * Results are cached after the first call.
45ŌåÆ */
46ŌåÆexport function getShellEnvironment(): Record<string, string> {
47ŌåÆ  if (shellEnvironment !== null) {
48ŌåÆ    return shellEnvironment;
49ŌåÆ  }
50ŌåÆ
51ŌåÆ  const shell = process.env.SHELL || "/bin/zsh";
52ŌåÆ  const command = `echo -n "${DELIMITER}"; env; echo -n "${DELIMITER}"; exit`;
53ŌåÆ
54ŌåÆ  const output = execFileSync(shell, ["-ilc", command], {
55ŌåÆ    encoding: "utf8",
56ŌåÆ    timeout: 5_000,
57ŌåÆ    env: {
58ŌåÆ      // Prevent Oh My Zsh from blocking with auto-update prompts
59ŌåÆ      DISABLE_AUTO_UPDATE: "true",
60ŌåÆ    },
61ŌåÆ  });
62ŌåÆ
63ŌåÆ  const env = parseEnv(output);
64ŌåÆ
65ŌåÆ  for (const key of STRIPPED_ENV_KEYS) {
66ŌåÆ    if (key in env) {
67ŌåÆ      console.log(`Stripped ${key} from shell environment to prevent auth interference`);
68ŌåÆ      delete env[key];
69ŌåÆ    }
70ŌåÆ  }
71ŌåÆ
72ŌåÆ  console.log(`Loaded ${Object.keys(env).length} environment variables from shell`);
73ŌåÆ
74ŌåÆ  shellEnvironment = env;
75ŌåÆ  return env;
76ŌåÆ}
