  1ŌåÆ// backend/src/services/agent/service.ts
  2ŌåÆ// Composition root for agent-server communication.
  3ŌåÆ//
  4ŌåÆ// Creates the AgentClient, wires the event handler with injected dependencies,
  5ŌåÆ// and exposes typed methods for other services to call. No circular imports ŌĆö
  6ŌåÆ// this module imports from its dependencies, none of them import back.
  7ŌåÆ//
  8ŌåÆ// Dependency graph (all arrows point down, no cycles):
  9ŌåÆ//
 10ŌåÆ//   service (this file)
 11ŌåÆ//       Ōö£ŌöĆŌöĆ client              (WebSocket transport)
 12ŌåÆ//       Ōö£ŌöĆŌöĆ event-handler       (factory: createAgentEventHandler)
 13ŌåÆ//       ŌööŌöĆŌöĆ tool-relay          (frontend RPC relay)
 14ŌåÆ//
 15ŌåÆ// Initialized once at startup in server.ts via agentService.init().
 16ŌåÆ
 17ŌåÆimport { AgentClient } from "./client";
 18ŌåÆimport { createAgentEventHandler } from "./event-handler";
 19ŌåÆimport { relay } from "./tool-relay";
 20ŌåÆimport {
 21ŌåÆ  persistSessionNeedsPlanResponse,
 22ŌåÆ  persistSessionNeedsResponse,
 23ŌåÆ  persistSessionBackToWorking,
 24ŌåÆ} from "./persistence";
 25ŌåÆimport { invalidate } from "../query-engine";
 26ŌåÆimport type {
 27ŌåÆ  TurnStartRequest,
 28ŌåÆ  TurnStartResponse,
 29ŌåÆ  TurnRespondRequest,
 30ŌåÆ  SessionStopRequest,
 31ŌåÆ  ProviderAuthRequest,
 32ŌåÆ} from "@shared/agent-events";
 33ŌåÆ
 34ŌåÆ// ---- Singleton ----
 35ŌåÆ
 36ŌåÆlet client: AgentClient | null = null;
 37ŌåÆ
 38ŌåÆ/** Initialize the agent service. Call once at startup. */
 39ŌåÆexport function init(agentServerUrl: string): void {
 40ŌåÆ  if (client) {
 41ŌåÆ    console.warn("[AgentService] Already initialized, skipping");
 42ŌåÆ    return;
 43ŌåÆ  }
 44ŌåÆ
 45ŌåÆ  client = new AgentClient({
 46ŌåÆ    url: agentServerUrl,
 47ŌåÆ
 48ŌåÆ    // Wire the event handler with respondToAgent injected ŌĆö breaks the
 49ŌåÆ    // circular dependency that previously existed between these modules.
 50ŌåÆ    onEvent: createAgentEventHandler({
 51ŌåÆ      respondToAgent: (params) => respondToAgent(params),
 52ŌåÆ    }),
 53ŌåÆ
 54ŌåÆ    onConnected: (agents) => {
 55ŌåÆ      console.log(`[AgentService] Connected, agents: [${agents.map((a) => a.type).join(", ")}]`);
 56ŌåÆ    },
 57ŌåÆ    onDisconnected: () => {
 58ŌåÆ      console.log("[AgentService] Disconnected from agent-server");
 59ŌåÆ    },
 60ŌåÆ
 61ŌåÆ    // Relay agent-server's frontend-facing RPC requests (browser, sim, diff, plan)
 62ŌåÆ    onFrontendRpc: async (requestId, sessionId, method, params) => {
 63ŌåÆ      const isUserFacing = method === "exitPlanMode" || method === "askUserQuestion";
 64ŌåÆ      const sessionResources = ["workspaces", "sessions", "session", "stats"] as const;
 65ŌåÆ
 66ŌåÆ      // User-facing methods: update session status so sidebar shows "needs input" instead of "working"
 67ŌåÆ      if (method === "exitPlanMode") {
 68ŌåÆ        const result = persistSessionNeedsPlanResponse(sessionId);
 69ŌåÆ        if (result.ok) invalidate([...sessionResources], { sessionIds: [sessionId] });
 70ŌåÆ      } else if (method === "askUserQuestion") {
 71ŌåÆ        const result = persistSessionNeedsResponse(sessionId);
 72ŌåÆ        if (result.ok) invalidate([...sessionResources], { sessionIds: [sessionId] });
 73ŌåÆ      }
 74ŌåÆ
 75ŌåÆ      try {
 76ŌåÆ        return await relay({
 77ŌåÆ          type: "tool.request",
 78ŌåÆ          requestId,
 79ŌåÆ          sessionId,
 80ŌåÆ          method,
 81ŌåÆ          params,
 82ŌåÆ          // User-facing methods wait indefinitely; auto-responding keep 2-min timeout
 83ŌåÆ          timeoutMs: isUserFacing ? 24 * 60 * 60 * 1000 : 120_000,
 84ŌåÆ        });
 85ŌåÆ      } finally {
 86ŌåÆ        if (isUserFacing) {
 87ŌåÆ          const result = persistSessionBackToWorking(sessionId);
 88ŌåÆ          if (result.ok) invalidate([...sessionResources], { sessionIds: [sessionId] });
 89ŌåÆ        }
 90ŌåÆ      }
 91ŌåÆ    },
 92ŌåÆ  });
 93ŌåÆ
 94ŌåÆ  client.connect();
 95ŌåÆ}
 96ŌåÆ
 97ŌåÆ/** Gracefully shut down the agent client. */
 98ŌåÆexport function shutdown(): void {
 99ŌåÆ  client?.disconnect();
100ŌåÆ  client = null;
101ŌåÆ}
102ŌåÆ
103ŌåÆ// ---- Public API (typed wrappers) ----
104ŌåÆ
105ŌåÆ/** Forward a turn/start request to the agent-server. */
106ŌåÆexport async function forwardTurn(params: TurnStartRequest): Promise<TurnStartResponse> {
107ŌåÆ  if (!client) throw new Error("Agent service not initialized");
108ŌåÆ  return client.sendTurnStart(params);
109ŌåÆ}
110ŌåÆ
111ŌåÆ/** Send a tool relay response back to the agent-server. */
112ŌåÆexport async function respondToAgent(params: TurnRespondRequest): Promise<void> {
113ŌåÆ  if (!client) throw new Error("Agent service not initialized");
114ŌåÆ  return client.sendTurnRespond(params);
115ŌåÆ}
116ŌåÆ
117ŌåÆ/** Stop a session on the agent-server. */
118ŌåÆexport async function stopSession(params: SessionStopRequest): Promise<void> {
119ŌåÆ  if (!client) throw new Error("Agent service not initialized");
120ŌåÆ  return client.sendSessionStop(params);
121ŌåÆ}
122ŌåÆ
123ŌåÆ/** Check if the agent service is connected. */
124ŌåÆexport function isConnected(): boolean {
125ŌåÆ  return client?.isConnected() ?? false;
126ŌåÆ}
127ŌåÆ
128ŌåÆ/** Check authentication status for an agent provider. */
129ŌåÆexport async function checkAuth(params: ProviderAuthRequest): Promise<unknown> {
130ŌåÆ  if (!client) throw new Error("Agent service not initialized");
131ŌåÆ  return client.sendProviderAuth(params);
132ŌåÆ}
133ŌåÆ
134ŌåÆ/** Returns the agents discovered during the initialize handshake. */
135ŌåÆexport function getAgents() {
136ŌåÆ  return client?.getAgents() ?? [];
137ŌåÆ}
