522ŌåÆfunction formatUptime(ms: number): string {
523ŌåÆ  const s = Math.floor(ms / 1000);
524ŌåÆ  if (s < 60) return `${s}s`;
525ŌåÆ  const m = Math.floor(s / 60);
526ŌåÆ  if (m < 60) return `${m}m ${s % 60}s`;
527ŌåÆ  const h = Math.floor(m / 60);
528ŌåÆ  return `${h}h ${m % 60}m`;
529ŌåÆ}
