   294ŌåÆ      { encoding: "utf-8", timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
   295ŌåÆ    ).trim();
   296ŌåÆ
   297ŌåÆ    if (electronPath && existsSync(electronPath)) {
   298ŌåÆ      try {
   299ŌåÆ        execSync(
   300ŌåÆ          "node -e \"const D = require('better-sqlite3'); const d = new D(':memory:'); d.close()\"",
   301ŌåÆ          { timeout: 5000, stdio: ["pipe", "pipe", "pipe"] }
   302ŌåÆ        );
   303ŌåÆ        return process.execPath;
