   373ŌåÆ// ŌöĆŌöĆ Web server (static + proxy) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
   374ŌåÆ
   375ŌåÆfunction createWebServer(backendPort: number, frontendDir: string) {
   376ŌåÆ  const hasFrontend = existsSync(frontendDir) && existsSync(join(frontendDir, "index.html"));
   377ŌåÆ
   378ŌåÆ  const server = createServer(async (req, res) => {
   379ŌåÆ    const url = req.url || "/";
   380ŌåÆ
   381ŌåÆ    if (url.startsWith("/api/") || url.startsWith("/api")) {
   382ŌåÆ      return proxyRequest(req, res, backendPort);
   383ŌåÆ    }
   384ŌåÆ
   385ŌåÆ    if (url === "/__backend_port") {
   386ŌåÆ      res.writeHead(200, {
   387ŌåÆ        "Content-Type": "application/json",
   388ŌåÆ        "Access-Control-Allow-Origin": "*",
   389ŌåÆ      });
   390ŌåÆ      res.end(JSON.stringify({ port: backendPort }));
   391ŌåÆ      return;
   392ŌåÆ    }
   393ŌåÆ
   394ŌåÆ    if (hasFrontend) {
   395ŌåÆ      serveStaticFile(req, res, frontendDir);
   396ŌåÆ    } else {
   397ŌåÆ      res.writeHead(200, { "Content-Type": "text/html" });
   398ŌåÆ      res.end(`<!DOCTYPE html><html><head><title>Deus IDE</title>
   399ŌåÆ<style>body{font-family:system-ui;padding:3rem;background:#0a0a0a;color:#e5e5e5}
   400ŌåÆcode{background:#1a1a1a;padding:2px 6px;border-radius:4px;font-size:14px}
   401ŌåÆa{color:#22d3ee}</style></head><body>
   402ŌåÆ<h1>Deus IDE Server</h1>
   403ŌåÆ<p>Backend API: <code>http://localhost:${backendPort}/api</code></p>
   404ŌåÆ<p>WebSocket: <code>ws://localhost:${backendPort}/ws</code></p>
   405ŌåÆ<p style="color:#a3a3a3">Frontend not built. Run <code>bun run build:web</code> to enable the UI.</p>
   406ŌåÆ</body></html>`);
   407ŌåÆ    }
   408ŌåÆ  });
   409ŌåÆ
   410ŌåÆ  server.on("upgrade", (req, socket, head) => {
   411ŌåÆ    const proxyReq = httpRequest({
   412ŌåÆ      hostname: "localhost",
   413ŌåÆ      port: backendPort,
   414ŌåÆ      path: req.url,
   415ŌåÆ      method: req.method,
   416ŌåÆ      headers: req.headers,
   417ŌåÆ    });
   418ŌåÆ
   419ŌåÆ    proxyReq.on("upgrade", (_proxyRes: any, proxySocket: any, proxyHead: any) => {
   420ŌåÆ      socket.write(
   421ŌåÆ        "HTTP/1.1 101 Switching Protocols\r\n" +
   422ŌåÆ          Object.entries(_proxyRes.headers)
   423ŌåÆ            .map(([k, v]: [string, any]) => `${k}: ${v}`)
   424ŌåÆ            .join("\r\n") +
   425ŌåÆ          "\r\n\r\n"
   426ŌåÆ      );
   427ŌåÆ      if (proxyHead.length > 0) socket.write(proxyHead);
   428ŌåÆ      proxySocket.pipe(socket);
   429ŌåÆ      socket.pipe(proxySocket);
   430ŌåÆ    });
   431ŌåÆ
   432ŌåÆ    proxyReq.on("error", () => socket.end());
   433ŌåÆ    proxyReq.end();
   434ŌåÆ  });
   435ŌåÆ
   436ŌåÆ  return server;
   437ŌåÆ}
   438ŌåÆ
   439ŌåÆfunction proxyRequest(
   440ŌåÆ  req: import("node:http").IncomingMessage,
   441ŌåÆ  res: import("node:http").ServerResponse,
   442ŌåÆ  backendPort: number
   443ŌåÆ) {
   444ŌåÆ  const proxyReq = httpRequest(
   445ŌåÆ    {
   446ŌåÆ      hostname: "localhost",
   447ŌåÆ      port: backendPort,
   448ŌåÆ      path: req.url,
   449ŌåÆ      method: req.method,
   450ŌåÆ      headers: { ...req.headers, host: `localhost:${backendPort}` },
   451ŌåÆ    },
   452ŌåÆ    (proxyRes) => {
   453ŌåÆ      res.writeHead(proxyRes.statusCode || 502, proxyRes.headers);
   454ŌåÆ      proxyRes.pipe(res);
   455ŌåÆ    }
   456ŌåÆ  );
   457ŌåÆ
   458ŌåÆ  proxyReq.on("error", () => {
   459ŌåÆ    res.writeHead(502, { "Content-Type": "application/json" });
   460ŌåÆ    res.end(JSON.stringify({ error: "Backend unavailable" }));
   461ŌåÆ  });
   462ŌåÆ
   463ŌåÆ  req.pipe(proxyReq);
   464ŌåÆ}
