   466ŌåÆfunction serveStaticFile(
   467ŌåÆ  req: import("node:http").IncomingMessage,
   468ŌåÆ  res: import("node:http").ServerResponse,
   469ŌåÆ  frontendDir: string
   470ŌåÆ) {
   471ŌåÆ  let pathname = (req.url || "/").split("?")[0];
   472ŌåÆ  if (pathname === "/") pathname = "/index.html";
   473ŌåÆ
   474ŌåÆ  let filePath = join(frontendDir, pathname);
   475ŌåÆ
   476ŌåÆ  if (!existsSync(filePath) || statSync(filePath).isDirectory()) {
   477ŌåÆ    filePath = join(frontendDir, "index.html");
   478ŌåÆ  }
   479ŌåÆ
   480ŌåÆ  if (!existsSync(filePath)) {
   481ŌåÆ    res.writeHead(404);
   482ŌåÆ    res.end("Not found");
   483ŌåÆ    return;
   484ŌåÆ  }
   485ŌåÆ
   486ŌåÆ  const ext = extname(filePath);
   487ŌåÆ  const contentType = MIME_TYPES[ext] || "application/octet-stream";
   488ŌåÆ
   489ŌåÆ  try {
   490ŌåÆ    const content = readFileSync(filePath);
   491ŌåÆ    res.writeHead(200, {
   492ŌåÆ      "Content-Type": contentType,
   493ŌåÆ      "Cache-Control": ext === ".html" ? "no-cache" : "public, max-age=31536000, immutable",
   494ŌåÆ    });
   495ŌåÆ    res.end(content);
   496ŌåÆ  } catch {
   497ŌåÆ    res.writeHead(500);
   498ŌåÆ    res.end("Internal server error");
   499ŌåÆ  }
   500ŌåÆ}
