   505ŌåÆ  const nets = networkInterfaces();
   506ŌåÆ  for (const ifaces of Object.values(nets)) {
   507ŌåÆ    for (const iface of ifaces ?? []) {
   508ŌåÆ      if (iface.family === "IPv4" && !iface.internal) {
   509ŌåÆ        return iface.address;
   510ŌåÆ      }
   511ŌåÆ    }
   512ŌåÆ  }
   513ŌåÆ  return null;
   514ŌåÆ}
