/**
 * Auth setup ŌĆö detects Claude Code CLI and configures AI agent authentication.
 *
 * Detection order:
 * 1. ANTHROPIC_API_KEY already in environment ŌåÆ done
 * 2. Claude Code CLI installed + authenticated ŌåÆ done
 * 3. Interactive prompt: install CLI / enter API key / skip
 */

import { execSync, spawnSync, spawn } from "node:child_process";
import { existsSync } from "node:fs";
import { join } from "node:path";
import { homedir, platform } from "node:os";
import { select, input } from "./prompt.js";
import { loadConfig, saveConfig } from "./config.js";
import {
  spinner as createSpinner,
  c,
  sym,
  blank,
  success,
  error,
  warn,
  hint,
} from "./ui.js";

// ŌöĆŌöĆ Types ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

export interface AuthResult {
  method: "claude_cli" | "api_key" | "env" | "skipped";
  apiKey?: string;
}

interface ClaudeCliInfo {
  installed: boolean;
  path?: string;
  version?: string;
}

// ŌöĆŌöĆ Claude CLI Discovery ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

// Candidate paths to check (mirrors agent-server/agents/claude/claude-discovery.ts)
function getClaudeCliCandidates(): string[] {
  const candidates: string[] = [];

  // Env var override
  if (process.env.CLAUDE_CLI_PATH) {
    candidates.push(process.env.CLAUDE_CLI_PATH);
  }

  const os = platform();
  if (os === "darwin") {
    candidates.push(
      "/opt/homebrew/lib/node_modules/@anthropic-ai/claude-code/cli.js",
      "/usr/local/lib/node_modules/@anthropic-ai/claude-code/cli.js",
      join(homedir(), ".npm/lib/node_modules/@anthropic-ai/claude-code/cli.js"),
    );
  } else if (os === "linux") {
    candidates.push(
      "/usr/lib/node_modules/@anthropic-ai/claude-code/cli.js",
      "/usr/local/lib/node_modules/@anthropic-ai/claude-code/cli.js",
      join(homedir(), ".npm/lib/node_modules/@anthropic-ai/claude-code/cli.js"),
    );
  }

  return candidates;
}

export function detectClaudeCli(): ClaudeCliInfo {
  // Check candidate paths
  for (const candidate of getClaudeCliCandidates()) {
    if (existsSync(candidate)) {
      try {
        const version = execSync(`node "${candidate}" --version`, {
          encoding: "utf-8",
          timeout: 5000,
          stdio: ["pipe", "pipe", "pipe"],
        }).trim();
        return { installed: true, path: candidate, version };
      } catch {
        // File exists but doesn't run ŌĆö skip
      }
    }
  }

  // Try PATH discovery
  try {
    const shell = process.env.SHELL || "/bin/sh";
    const claudePath = execSync(`${shell} -lc "command -v claude"`, {
      encoding: "utf-8",
      timeout: 5000,
      stdio: ["pipe", "pipe", "pipe"],
    }).trim();

    if (claudePath) {
      try {
        const version = execSync(`"${claudePath}" --version`, {
          encoding: "utf-8",
          timeout: 5000,
          stdio: ["pipe", "pipe", "pipe"],
        }).trim();
        return { installed: true, path: claudePath, version };
      } catch {
        return { installed: true, path: claudePath };
      }
    }
  } catch {
    // Not in PATH
  }

  return { installed: false };
}

/** Check if Claude CLI has stored credentials */
function isClaudeAuthenticated(): boolean {
  // Claude Code stores credentials in ~/.claude/
  const credPaths = [
    join(homedir(), ".claude", ".credentials.json"),
    join(homedir(), ".claude", "credentials.json"),
  ];

  for (const p of credPaths) {
    if (existsSync(p)) return true;
  }

  return false;
}

