 85ŌåÆexport async function installDesktop(options: DesktopOptions): Promise<void> {
 86ŌåÆ  const { version } = options;
 87ŌåÆ  const os = platform();
 88ŌåÆ  const cpuArch = arch();
 89ŌåÆ
 90ŌåÆ  // Determine which asset to download
 91ŌåÆ  const assetPattern = getAssetPattern(os, cpuArch);
 92ŌåÆ  if (!assetPattern) {
 93ŌåÆ    error(`Unsupported platform: ${os} ${cpuArch}`);
 94ŌåÆ    blank();
 95ŌåÆ    hint("Supported: macOS (arm64/x64), Windows (x64), Linux (x64)");
 96ŌåÆ    hint(`Or run ${c.cyan("deus serve")} to use the web version instead.`);
 97ŌåÆ    blank();
 98ŌåÆ    process.exit(1);
 99ŌåÆ  }
100ŌåÆ
101ŌåÆ  kv("Platform", `${os} ${cpuArch}`, 10);
102ŌåÆ  kv("Package", c.dim(assetPattern.description), 10);
103ŌåÆ  blank();
104ŌåÆ
105ŌåÆ  // Fetch release info
106ŌåÆ  const s1 = createSpinner("Fetching latest release...");
107ŌåÆ  const release = await fetchRelease(version);
108ŌåÆ
109ŌåÆ  if (!release) {
110ŌåÆ    s1.fail("Could not find a release on GitHub");
111ŌåÆ    blank();
112ŌåÆ    hint(`Repo: ${c.dim(GITHUB_REPO)}`);
113ŌåÆ    hint("Make sure the repository has published releases.");
114ŌåÆ    hint(`Or run ${c.cyan("deus serve")} to use the web version.`);
115ŌåÆ    blank();
116ŌåÆ    process.exit(1);
117ŌåÆ  }
118ŌåÆ
119ŌåÆ  s1.succeed(`Found release ${c.cyan(release.tag_name)}`);
120ŌåÆ
121ŌåÆ  // Find matching asset
122ŌåÆ  const asset = release.assets.find((a) => assetPattern.matcher(a.name));
123ŌåÆ  if (!asset) {
124ŌåÆ    error(`No matching installer for ${os} ${cpuArch}`);
125ŌåÆ    blank();
126ŌåÆ    hint("Available downloads:");
127ŌåÆ    for (const a of release.assets) {
128ŌåÆ      hint(`  ${a.name}`);
129ŌåÆ    }
130ŌåÆ    blank();
131ŌåÆ    process.exit(1);
132ŌåÆ  }
133ŌåÆ
134ŌåÆ  // Download
135ŌåÆ  const downloadDir = join(tmpdir(), "deus-installer");
136ŌåÆ  mkdirSync(downloadDir, { recursive: true });
137ŌåÆ  const downloadPath = join(downloadDir, asset.name);
138ŌåÆ
139ŌåÆ  await downloadFile(asset.browser_download_url, downloadPath);
140ŌåÆ
141ŌåÆ  // Install
142ŌåÆ  const s3 = createSpinner("Installing...");
143ŌåÆ  const installed = await installForPlatform(os, downloadPath, s3);
144ŌåÆ
145ŌåÆ  // Cleanup temp file
146ŌåÆ  try {
147ŌåÆ    unlinkSync(downloadPath);
148ŌåÆ  } catch {}
149ŌåÆ
150ŌåÆ  if (installed) {
151ŌåÆ    blank();
152ŌåÆ    success("Deus is ready!");
153ŌåÆ    blank();
154ŌåÆ  }
155ŌåÆ}
