157ŌåÆfunction getAssetPattern(
158ŌåÆ  os: string,
159ŌåÆ  cpuArch: string
160ŌåÆ): { matcher: (name: string) => boolean; description: string } | null {
161ŌåÆ  switch (os) {
162ŌåÆ    case "darwin": {
163ŌåÆ      const archSuffix = cpuArch === "arm64" ? "arm64" : "x64";
164ŌåÆ      return {
165ŌåÆ        matcher: (name) => name.endsWith(".dmg") && name.includes(archSuffix),
166ŌåÆ        description: `macOS DMG (${archSuffix})`,
167ŌåÆ      };
168ŌåÆ    }
169ŌåÆ    case "win32":
170ŌåÆ      return {
171ŌåÆ        matcher: (name) => name.endsWith(".exe") && !name.includes("blockmap"),
172ŌåÆ        description: "Windows installer (exe)",
173ŌåÆ      };
174ŌåÆ    case "linux":
175ŌåÆ      return {
176ŌåÆ        matcher: (name) => name.endsWith(".AppImage"),
177ŌåÆ        description: "Linux AppImage",
178ŌåÆ      };
179ŌåÆ    default:
180ŌåÆ      return null;
181ŌåÆ  }
182ŌåÆ}
