184ŌåÆasync function fetchRelease(version: string): Promise<GithubRelease | null> {
185ŌåÆ  const endpoint =
186ŌåÆ    version === "latest"
187ŌåÆ      ? `https://api.github.com/repos/${GITHUB_REPO}/releases/latest`
188ŌåÆ      : `https://api.github.com/repos/${GITHUB_REPO}/releases/tags/${version}`;
189ŌåÆ
190ŌåÆ  return new Promise((resolve) => {
191ŌåÆ    get(
192ŌåÆ      endpoint,
193ŌåÆ      { headers: { "User-Agent": "deus-cli", Accept: "application/vnd.github.v3+json" } },
194ŌåÆ      (res) => {
195ŌåÆ        if (res.statusCode === 302 || res.statusCode === 301) {
196ŌåÆ          const loc = res.headers.location;
197ŌåÆ          if (loc) {
198ŌåÆ            get(loc, { headers: { "User-Agent": "deus-cli" } }, (r) => {
199ŌåÆ              collectBody(r).then((b) => {
200ŌåÆ                try { resolve(JSON.parse(b)); } catch { resolve(null); }
201ŌåÆ              });
202ŌåÆ            }).on("error", () => resolve(null));
203ŌåÆ            return;
204ŌåÆ          }
205ŌåÆ        }
206ŌåÆ        if (res.statusCode !== 200) { resolve(null); return; }
207ŌåÆ        collectBody(res).then((b) => {
208ŌåÆ          try { resolve(JSON.parse(b)); } catch { resolve(null); }
209ŌåÆ        });
210ŌåÆ      }
211ŌåÆ    ).on("error", () => resolve(null));
212ŌåÆ  });
213ŌåÆ}
214ŌåÆ
215ŌåÆfunction collectBody(res: IncomingMessage): Promise<string> {
216ŌåÆ  return new Promise((resolve) => {
217ŌåÆ    let body = "";
218ŌåÆ    res.on("data", (chunk: Buffer) => (body += chunk.toString()));
219ŌåÆ    res.on("end", () => resolve(body));
220ŌåÆ    res.on("error", () => resolve(""));
221ŌåÆ  });
222ŌåÆ}
223ŌåÆ
224ŌåÆasync function downloadFile(url: string, dest: string): Promise<void> {
225ŌåÆ  return new Promise((resolve, reject) => {
226ŌåÆ    const download = (downloadUrl: string) => {
227ŌåÆ      get(downloadUrl, { headers: { "User-Agent": "deus-cli" } }, (res) => {
228ŌåÆ        if (res.statusCode === 302 || res.statusCode === 301) {
229ŌåÆ          const loc = res.headers.location;
230ŌåÆ          if (loc) { download(loc); return; }
231ŌåÆ        }
232ŌåÆ
233ŌåÆ        if (res.statusCode !== 200) {
234ŌåÆ          reject(new Error(`Download failed with status ${res.statusCode}`));
235ŌåÆ          return;
236ŌåÆ        }
237ŌåÆ
238ŌåÆ        const totalSize = parseInt(res.headers["content-length"] || "0", 10);
239ŌåÆ        let downloaded = 0;
240ŌåÆ
241ŌåÆ        const file = createWriteStream(dest);
242ŌåÆ        res.on("data", (chunk: Buffer) => {
243ŌåÆ          downloaded += chunk.length;
244ŌåÆ          if (totalSize > 0) {
245ŌåÆ            progressBar(downloaded, totalSize, formatBytes(downloaded) + " / " + formatBytes(totalSize));
246ŌåÆ          }
247ŌåÆ        });
248ŌåÆ        res.pipe(file);
249ŌåÆ        file.on("finish", () => {
250ŌåÆ          file.close();
251ŌåÆ          progressBarDone(`Downloaded ${c.dim(formatBytes(totalSize))}`);
252ŌåÆ          resolve();
253ŌåÆ        });
254ŌåÆ        file.on("error", reject);
255ŌåÆ      }).on("error", reject);
256ŌåÆ    };
257ŌåÆ
258ŌåÆ    download(url);
259ŌåÆ  });
260ŌåÆ}
261ŌåÆ
262ŌåÆfunction formatBytes(bytes: number): string {
263ŌåÆ  if (bytes < 1024) return `${bytes} B`;
264ŌåÆ  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
265ŌåÆ  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
266ŌåÆ}
