268ŌåÆasync function installForPlatform(
269ŌåÆ  os: string,
270ŌåÆ  filePath: string,
271ŌåÆ  s: ReturnType<typeof createSpinner>
272ŌåÆ): Promise<boolean> {
273ŌåÆ  switch (os) {
274ŌåÆ    case "darwin": {
275ŌåÆ      try {
276ŌåÆ        const mountOutput = execSync(`hdiutil attach "${filePath}" -nobrowse`, {
277ŌåÆ          encoding: "utf-8",
278ŌåÆ        });
279ŌåÆ
280ŌåÆ        const mountPoint = mountOutput
281ŌåÆ          .split("\n")
282ŌåÆ          .filter((line) => line.includes("/Volumes/"))
283ŌåÆ          .map((line) => line.trim().split("\t").pop()?.trim())
284ŌåÆ          .find(Boolean);
285ŌåÆ
286ŌåÆ        if (!mountPoint) {
287ŌåÆ          s.fail("Could not mount disk image");
288ŌåÆ          return false;
289ŌåÆ        }
290ŌåÆ
291ŌåÆ        const appName = "Deus.app";
292ŌåÆ        const appPath = `${mountPoint}/${appName}`;
293ŌåÆ        const destPath = `/Applications/${appName}`;
294ŌåÆ
295ŌåÆ        if (existsSync(appPath)) {
296ŌåÆ          execSync(`cp -R "${appPath}" "${destPath}"`, { stdio: "pipe" });
297ŌåÆ          s.succeed(`Installed to ${c.dim("/Applications/Deus.app")}`);
298ŌåÆ
299ŌåÆ          launchDesktop(destPath);
300ŌåÆ        } else {
301ŌåÆ          s.warn("DMG mounted ŌĆö drag Deus to Applications to finish");
302ŌåÆ        }
303ŌåÆ
304ŌåÆ        execSync(`hdiutil detach "${mountPoint}" -quiet`, { stdio: "pipe" });
305ŌåÆ        return true;
306ŌåÆ      } catch {
307ŌåÆ        s.fail("Auto-install failed ŌĆö opening DMG manually");
308ŌåÆ        execSync(`open "${filePath}"`);
309ŌåÆ        return false;
310ŌåÆ      }
311ŌåÆ    }
312ŌåÆ
313ŌåÆ    case "win32": {
314ŌåÆ      s.succeed("Launching installer...");
315ŌåÆ      spawn(filePath, [], { detached: true, stdio: "ignore" }).unref();
316ŌåÆ      hint("Follow the on-screen instructions to complete installation.");
317ŌåÆ      return true;
318ŌåÆ    }
319ŌåÆ
320ŌåÆ    case "linux": {
321ŌåÆ      execSync(`chmod +x "${filePath}"`);
322ŌåÆ      const installDir = join(homedir(), ".local", "bin");
323ŌåÆ      mkdirSync(installDir, { recursive: true });
324ŌåÆ      const destPath = join(installDir, "Deus.AppImage");
325ŌåÆ      execSync(`cp "${filePath}" "${destPath}"`);
326ŌåÆ      s.succeed(`Installed to ${c.dim(destPath)}`);
327ŌåÆ
328ŌåÆ      launchDesktop(destPath);
329ŌåÆ      return true;
330ŌåÆ    }
331ŌåÆ
332ŌåÆ    default:
333ŌåÆ      s.fail("Unsupported platform");
334ŌåÆ      return false;
335ŌåÆ  }
336ŌåÆ}
