 20ŌåÆ
 21ŌåÆconst __filename = fileURLToPath(import.meta.url);
 22ŌåÆconst cliDir = dirname(__filename);
 23ŌåÆconst monorepoRoot = resolve(cliDir, "../..");
 24ŌåÆ
 25ŌåÆasync function main() {
 26ŌåÆ  console.log("Building deus-machine CLI...\n");
 27ŌåÆ
 28ŌåÆ  // Step 1: Bundle CLI TypeScript
 29ŌåÆ  console.log("1. Bundling CLI...");
 30ŌåÆ  await build({
 31ŌåÆ    entryPoints: [join(cliDir, "src/cli.ts")],
 32ŌåÆ    bundle: true,
 33ŌåÆ    platform: "node",
 34ŌåÆ    target: "node20",
 35ŌåÆ    format: "esm",
 36ŌåÆ    outfile: join(cliDir, "dist/cli.js"),
 37ŌåÆ    external: [
 38ŌåÆ      // Native modules resolved at runtime
 39ŌåÆ      "better-sqlite3",
 40ŌåÆ      "node-pty",
 41ŌåÆ      "ws",
 42ŌåÆ    ],
 43ŌåÆ    packages: "external",
 44ŌåÆ    minify: false,
 45ŌåÆ    sourcemap: false,
 46ŌåÆ    logLevel: "info",
 47ŌåÆ  });
 48ŌåÆ
 49ŌåÆ  // Step 2: Create bin/ entry point
 50ŌåÆ  console.log("\n2. Creating bin/deus.js...");
 51ŌåÆ  mkdirSync(join(cliDir, "bin"), { recursive: true });
 52ŌåÆ  writeFileSync(
 53ŌåÆ    join(cliDir, "bin/deus.js"),
 54ŌåÆ    `#!/usr/bin/env node\nimport "../dist/cli.js";\n`,
 55ŌåÆ    { mode: 0o755 }
 56ŌåÆ  );
 57ŌåÆ
 58ŌåÆ  // Step 3: Copy bundles for distribution
 59ŌåÆ  console.log("\n3. Copying bundles...");
 60ŌåÆ  const bundlesDir = join(cliDir, "bundles");
 61ŌåÆ  mkdirSync(bundlesDir, { recursive: true });
 62ŌåÆ
 63ŌåÆ  const copies: { src: string; dest: string; name: string; required: boolean }[] = [
 64ŌåÆ    {
 65ŌåÆ      src: join(monorepoRoot, "apps/agent-server/dist/index.bundled.cjs"),
 66ŌåÆ      dest: join(bundlesDir, "agent-server.bundled.cjs"),
 67ŌåÆ      name: "agent-server bundle",
 68ŌåÆ      required: true,
 69ŌåÆ    },
 70ŌåÆ    {
 71ŌåÆ      src: join(monorepoRoot, "apps/backend/dist/server.bundled.cjs"),
 72ŌåÆ      dest: join(bundlesDir, "server.bundled.cjs"),
 73ŌåÆ      name: "backend bundle",
 74ŌåÆ      required: true,
 75ŌåÆ    },
 76ŌåÆ    {
 77ŌåÆ      src: join(monorepoRoot, "apps/web/dist/web"),
 78ŌåÆ      dest: join(bundlesDir, "web"),
 79ŌåÆ      name: "frontend build",
 80ŌåÆ      required: false,
 81ŌåÆ    },
 82ŌåÆ  ];
 83ŌåÆ
 84ŌåÆ  let hasErrors = false;
 85ŌåÆ  for (const copy of copies) {
 86ŌåÆ    if (existsSync(copy.src)) {
 87ŌåÆ      cpSync(copy.src, copy.dest, { recursive: true });
 88ŌåÆ      console.log(`   Ō£ō ${copy.name}`);
 89ŌåÆ    } else if (copy.required) {
 90ŌåÆ      console.error(`   Ō£Ś ${copy.name} not found: ${copy.src}`);
 91ŌåÆ      hasErrors = true;
 92ŌåÆ    } else {
 93ŌåÆ      console.log(`   - ${copy.name} not found (optional, server will work without UI)`);
 94ŌåÆ    }
 95ŌåÆ  }
 96ŌåÆ
 97ŌåÆ  if (hasErrors) {
 98ŌåÆ    console.error("\nMissing required bundles. Run these first:");
 99ŌåÆ    console.error("  bun run build:agent-server");
100ŌåÆ    console.error("  bun run build:backend");
101ŌåÆ    console.error("  bun run build:web  (optional, for web UI)");
102ŌåÆ    process.exit(1);
103ŌåÆ  }
104ŌåÆ
105ŌåÆ  // Step 4: Generate a standalone package.json for the published CLI
106ŌåÆ  console.log("\n4. Generating publish-ready package.json...");
107ŌåÆ  const pkg = JSON.parse(readFileSync(join(cliDir, "package.json"), "utf-8"));
108ŌåÆ  // Ensure we don't ship "private: true" or monorepo-specific fields
109ŌåÆ  delete pkg.scripts;
110ŌåÆ  pkg.main = "dist/cli.js";
111ŌåÆ  pkg.type = "module";
112ŌåÆ  // Note: we don't overwrite ŌĆö the original is fine for publishing
113ŌåÆ
114ŌåÆ  console.log("\nŌ£ō Build complete!");
115ŌåÆ  console.log(`  CLI: ${join(cliDir, "dist/cli.js")}`);
116ŌåÆ  console.log(`  Bin: ${join(cliDir, "bin/deus.js")}`);
117ŌåÆ  console.log(`  Bundles: ${bundlesDir}`);
118ŌåÆ  console.log("\nTo test locally:");
119ŌåÆ  console.log("  node apps/cli/bin/deus.js serve");
120ŌåÆ  console.log("\nTo publish:");
121ŌåÆ  console.log("  cd apps/cli && npm publish");
122ŌåÆ}
123ŌåÆ
124ŌåÆmain().catch((err) => {
125ŌåÆ  console.error("Build failed:", err);
126ŌåÆ  process.exit(1);
127ŌåÆ});
