 11ŌåÆconst ESC = "\x1b[";
 12ŌåÆconst RESET = `${ESC}0m`;
 13ŌåÆ
 14ŌåÆ// Check NO_COLOR / FORCE_COLOR env vars (respect user preference)
 15ŌåÆconst noColor = !!process.env.NO_COLOR || process.argv.includes("--no-color");
