151ŌåÆ/** Color a logo row: block chars in main color, shadow chars in dim */
152ŌåÆfunction colorLogo(
153ŌåÆ  text: string,
154ŌåÆ  block: [number, number, number],
155ŌåÆ  shadow: [number, number, number]
156ŌåÆ): string {
157ŌåÆ  let result = "";
158ŌåÆ  let buf = "";
159ŌåÆ  let cur: "b" | "s" | " " | null = null;
160ŌåÆ
161ŌåÆ  function flush() {
162ŌåÆ    if (!buf) return;
163ŌåÆ    if (cur === "b") result += rgb(block[0], block[1], block[2], buf);
164ŌåÆ    else if (cur === "s") result += rgb(shadow[0], shadow[1], shadow[2], buf);
165ŌåÆ    else result += buf;
166ŌåÆ    buf = "";
167ŌåÆ  }
168ŌåÆ
169ŌåÆ  for (const ch of text) {
170ŌåÆ    const t = ch === " " ? " " : SHADOW_CHARS.has(ch) ? "s" : "b";
171ŌåÆ    if (t !== cur) {
172ŌåÆ      flush();
173ŌåÆ      cur = t;
174ŌåÆ    }
175ŌåÆ    buf += ch;
176ŌåÆ  }
177ŌåÆ  flush();
178ŌåÆ  return result;
179ŌåÆ}
