273ŌåÆconst SPINNER_FRAMES = isUnicode
274ŌåÆ  ? ["ŌĀŗ", "ŌĀÖ", "ŌĀ╣", "ŌĀĖ", "ŌĀ╝", "ŌĀ┤", "ŌĀ”", "ŌĀ¦", "ŌĀć", "ŌĀÅ"]
275ŌåÆ  : ["-", "\\", "|", "/"];
276ŌåÆ
277ŌåÆconst SPINNER_INTERVAL = 80;
