279ŌåÆexport interface Spinner {
280ŌåÆ  /** Update the spinner text while it's running */
281ŌåÆ  update(text: string): void;
282ŌåÆ  /** Stop with a success message */
283ŌåÆ  succeed(text?: string): void;
284ŌåÆ  /** Stop with a failure message */
285ŌåÆ  fail(text?: string): void;
286ŌåÆ  /** Stop with a warning message */
287ŌåÆ  warn(text?: string): void;
288ŌåÆ  /** Stop with an info message */
289ŌåÆ  info(text?: string): void;
290ŌåÆ  /** Stop and clear the line */
291ŌåÆ  stop(): void;
292ŌåÆ}
293ŌåÆ
294ŌåÆexport function spinner(text: string): Spinner {
295ŌåÆ  let frameIdx = 0;
296ŌåÆ  let currentText = text;
297ŌåÆ  let stopped = false;
298ŌåÆ
299ŌåÆ  const stream = process.stderr;
300ŌåÆ
301ŌåÆ  function render() {
302ŌåÆ    if (stopped) return;
303ŌåÆ    const frame = c.cyan(SPINNER_FRAMES[frameIdx % SPINNER_FRAMES.length]);
304ŌåÆ    stream.write(`\r${ESC}2K  ${frame} ${currentText}`);
305ŌåÆ    frameIdx++;
306ŌåÆ  }
307ŌåÆ
308ŌåÆ  const interval = setInterval(render, SPINNER_INTERVAL);
309ŌåÆ  render();
310ŌåÆ
311ŌåÆ  function stop(symbol: string, finalText: string) {
312ŌåÆ    if (stopped) return;
313ŌåÆ    stopped = true;
314ŌåÆ    clearInterval(interval);
315ŌåÆ    stream.write(`\r${ESC}2K  ${symbol} ${finalText}\n`);
316ŌåÆ  }
317ŌåÆ
318ŌåÆ  return {
319ŌåÆ    update(t: string) {
320ŌåÆ      currentText = t;
321ŌåÆ    },
322ŌåÆ    succeed(t?: string) {
323ŌåÆ      stop(c.green(sym.tick), t ?? currentText);
324ŌåÆ    },
325ŌåÆ    fail(t?: string) {
326ŌåÆ      stop(c.red(sym.cross), t ?? currentText);
327ŌåÆ    },
328ŌåÆ    warn(t?: string) {
329ŌåÆ      stop(c.yellow(sym.warning), t ?? currentText);
330ŌåÆ    },
331ŌåÆ    info(t?: string) {
332ŌåÆ      stop(c.blue(sym.info), t ?? currentText);
333ŌåÆ    },
334ŌåÆ    stop() {
335ŌåÆ      if (stopped) return;
336ŌåÆ      stopped = true;
337ŌåÆ      clearInterval(interval);
338ŌåÆ      stream.write(`\r${ESC}2K`);
339ŌåÆ    },
340ŌåÆ  };
341ŌåÆ}
