427ŌåÆ/** Apply a gradient across a text string (from ŌåÆ to RGB) */
428ŌåÆexport function gradientText(
429ŌåÆ  text: string,
430ŌåÆ  from: [number, number, number],
431ŌåÆ  to: [number, number, number]
432ŌåÆ): string {
433ŌåÆ  if (noColor) return text;
434ŌåÆ  let result = "";
435ŌåÆ  for (let i = 0; i < text.length; i++) {
436ŌåÆ    const t = text.length > 1 ? i / (text.length - 1) : 0;
437ŌåÆ    const r = Math.round(from[0] + (to[0] - from[0]) * t);
438ŌåÆ    const g = Math.round(from[1] + (to[1] - from[1]) * t);
439ŌåÆ    const b = Math.round(from[2] + (to[2] - from[2]) * t);
440ŌåÆ    result += rgb(r, g, b, text[i]);
441ŌåÆ  }
442ŌåÆ  return result;
443ŌåÆ}
