 1ŌåÆ// backend/src/routes/remote-auth.ts
 2ŌåÆ// Auth endpoints for remote access pairing and device management.
 3ŌåÆ// POST /remote-auth/pair ŌĆö public, rate-limited, exchanges code for token
 4ŌåÆ// POST /remote-auth/generate-pair-code ŌĆö localhost-only, creates a new code
 5ŌåÆ// GET /remote-auth/devices ŌĆö localhost-only, lists paired devices
 6ŌåÆ// DELETE /remote-auth/devices/:id ŌĆö localhost-only, revokes a device
 7ŌåÆ
 8ŌåÆimport { Hono } from "hono";
 9ŌåÆimport { createMiddleware } from "hono/factory";
10ŌåÆimport { parseBody, PairBody } from "../lib/schemas";
11ŌåÆimport {
12ŌåÆ  generatePairCode,
13ŌåÆ  validatePairCode,
14ŌåÆ  createDeviceToken,
15ŌåÆ  listDevices,
16ŌåÆ  revokeDevice,
17ŌåÆ  checkRateLimit,
18ŌåÆ  recordFailure,
19ŌåÆ  resetRateLimit,
20ŌåÆ} from "../services/remote-auth.service";
21ŌåÆimport { isLocalhost, getClientIp } from "../lib/network";
22ŌåÆ
23ŌåÆconst app = new Hono();
24ŌåÆ
25ŌåÆ/** Reject non-localhost requests with 403. Relay-bridged requests are trusted. */
26ŌåÆconst localhostOnly = createMiddleware(async (c, next) => {
27ŌåÆ  if (c.env?.relayBridged) {
28ŌåÆ    await next();
29ŌåÆ    return;
30ŌåÆ  }
31ŌåÆ  if (!isLocalhost(getClientIp(c))) {
32ŌåÆ    return c.json({ error: "This endpoint is only available from localhost" }, 403);
33ŌåÆ  }
34ŌåÆ  await next();
35ŌåÆ});
36ŌåÆ
37ŌåÆ// POST /remote-auth/pair ŌĆö public, exchanges pairing code for device token
38ŌåÆapp.post("/remote-auth/pair", async (c) => {
39ŌåÆ  const clientIp = getClientIp(c);
40ŌåÆ
41ŌåÆ  // Rate limit check
42ŌåÆ  if (clientIp) {
43ŌåÆ    const lockout = checkRateLimit(clientIp);
44ŌåÆ    if (lockout > 0) {
45ŌåÆ      return c.json({ error: "Too many failed attempts. Try again later." }, 429);
46ŌåÆ    }
47ŌåÆ  }
48ŌåÆ
49ŌåÆ  const { code, deviceName } = parseBody(PairBody, await c.req.json());
50ŌåÆ
51ŌåÆ  if (!validatePairCode(code)) {
52ŌåÆ    if (clientIp) recordFailure(clientIp);
53ŌåÆ    return c.json({ error: "Invalid or expired connection code" }, 401);
54ŌåÆ  }
55ŌåÆ
56ŌåÆ  // Successful pairing ŌĆö create device token
57ŌåÆ  if (clientIp) resetRateLimit(clientIp);
58ŌåÆ  const userAgent = c.req.header("user-agent") ?? null;
59ŌåÆ  const { token, device } = createDeviceToken(
60ŌåÆ    deviceName ?? "Unknown Device",
61ŌåÆ    clientIp ?? null,
62ŌåÆ    userAgent
63ŌåÆ  );
64ŌåÆ
65ŌåÆ  return c.json({
66ŌåÆ    token,
67ŌåÆ    device: {
68ŌåÆ      id: device.id,
69ŌåÆ      name: device.name,
70ŌåÆ      created_at: device.created_at,
71ŌåÆ    },
72ŌåÆ  });
73ŌåÆ});
74ŌåÆ
75ŌåÆ// POST /remote-auth/generate-pair-code ŌĆö localhost-only
76ŌåÆapp.post("/remote-auth/generate-pair-code", localhostOnly, (c) => {
77ŌåÆ  const { code, expiresAt } = generatePairCode();
78ŌåÆ  const expiresInSeconds = Math.round((expiresAt - Date.now()) / 1000);
79ŌåÆ
80ŌåÆ  return c.json({ code, expires_in_seconds: expiresInSeconds });
81ŌåÆ});
82ŌåÆ
83ŌåÆ// GET /remote-auth/devices ŌĆö localhost-only
84ŌåÆapp.get("/remote-auth/devices", localhostOnly, (c) => {
85ŌåÆ  return c.json({ devices: listDevices() });
86ŌåÆ});
87ŌåÆ
88ŌåÆ// DELETE /remote-auth/devices/:id ŌĆö localhost-only
89ŌåÆapp.delete("/remote-auth/devices/:id", localhostOnly, (c) => {
90ŌåÆ  const id = c.req.param("id");
91ŌåÆ  const deleted = revokeDevice(id);
92ŌåÆ  if (!deleted) {
93ŌåÆ    return c.json({ error: "Device not found" }, 404);
94ŌåÆ  }
95ŌåÆ  return c.json({ success: true });
96ŌåÆ});
97ŌåÆ
98ŌåÆexport default app;
