 51ŌåÆfunction unlinkClient(clientId: string): string | undefined {
 52ŌåÆ  const connectionId = clientToConn.get(clientId);
 53ŌåÆ  if (connectionId) connToClient.delete(connectionId);
 54ŌåÆ  clientToConn.delete(clientId);
