 68ŌåÆfunction getServerName(): string {
 69ŌåÆ  const custom = getSetting("server_name") as string | undefined;
 70ŌåÆ  if (custom) return custom;
 71ŌåÆ
 72ŌåÆ  if (platform() === "darwin") {
 73ŌåÆ    try {
