 75ŌåÆ        encoding: "utf-8",
 76ŌåÆ        timeout: 2000,
 77ŌåÆ      }).trim();
 78ŌåÆ      if (name) return name;
 79ŌåÆ    } catch {
 80ŌåÆ      /* fall through */
 81ŌåÆ    }
 82ŌåÆ  }
 83ŌåÆ
 84ŌåÆ  const host = hostname().replace(/\.local$/, "");
 85ŌåÆ  if (host && host !== "localhost") return host;
 86ŌåÆ
 87ŌåÆ  try {
 88ŌåÆ    return `${userInfo().username}'s computer`;
