109ŌåÆ  let creds = getRelayCredentials();
110ŌåÆ  if (!creds) {
111ŌåÆ    creds = generateRelayCredentials();
112ŌåÆ  }
113ŌåÆ  // Already connected or connecting with same credentials ŌĆö skip
114ŌåÆ  if (
115ŌåÆ    relayUrl === url &&
116ŌåÆ    serverId === creds.serverId &&
117ŌåÆ    relayToken === creds.relayToken &&
118ŌåÆ    tunnelWs &&
119ŌåÆ    (tunnelWs.readyState === WebSocket.OPEN || tunnelWs.readyState === WebSocket.CONNECTING)
120ŌåÆ  ) {
