172ŌåÆ// ---- Tunnel Lifecycle ----
173ŌåÆ
174ŌåÆfunction openTunnel(): void {
175ŌåÆ  if (!relayUrl || !serverId || !relayToken) return;
176ŌåÆ
177ŌåÆ  const wsUrl = `${relayUrl}/api/servers/${serverId}/tunnel?token=${encodeURIComponent(relayToken)}`;
178ŌåÆ  console.log(`[Relay] Connecting to ${relayUrl}/api/servers/${serverId}/tunnel...`);
179ŌåÆ
180ŌåÆ  try {
181ŌåÆ    tunnelWs = new WebSocket(wsUrl);
182ŌåÆ  } catch (err) {
183ŌåÆ    console.error("[Relay] Failed to create WebSocket:", err);
184ŌåÆ    scheduleReconnect();
185ŌåÆ    return;
186ŌåÆ  }
187ŌåÆ
188ŌåÆ  tunnelWs.on("open", () => {
189ŌåÆ    console.log("[Relay] Tunnel connected, registering...");
190ŌåÆ    reconnectAttempt = 0;
191ŌåÆ    sendToRelay({
192ŌåÆ      type: "register",
193ŌåÆ      serverId: serverId!,
194ŌåÆ      relayToken: relayToken!,
195ŌåÆ      serverName: getServerName(),
196ŌåÆ    });
197ŌåÆ  });
198ŌåÆ
199ŌåÆ  tunnelWs.on("message", (raw: Buffer | string) => {
200ŌåÆ    try {
201ŌåÆ      const frame = JSON.parse(typeof raw === "string" ? raw : raw.toString()) as RelayFrame;
202ŌåÆ      handleRelayFrame(frame);
203ŌåÆ    } catch {
204ŌåÆ      // Ignore malformed frames
205ŌåÆ    }
206ŌåÆ  });
207ŌåÆ
208ŌåÆ  tunnelWs.on("close", (code, reason) => {
209ŌåÆ    console.log(`[Relay] Tunnel closed: ${code} ${reason}`);
210ŌåÆ    tunnelWs = null;
211ŌåÆ    for (const [, connId] of clientToConn) {
212ŌåÆ      removeQuerySubs(connId);
213ŌåÆ      removeConnection(connId);
214ŌåÆ    }
215ŌåÆ    unlinkAll();
216ŌåÆ    if (relayUrl) scheduleReconnect();
217ŌåÆ  });
218ŌåÆ
219ŌåÆ  tunnelWs.on("error", (err) => {
220ŌåÆ    console.error("[Relay] Tunnel error:", err.message);
221ŌåÆ  });
222ŌåÆ}
223ŌåÆ
224ŌåÆfunction handleRelayFrame(frame: RelayFrame): void {
225ŌåÆ  match(frame)
226ŌåÆ    .with({ type: "registered" }, () => {
227ŌåÆ      console.log("[Relay] Registered with relay successfully");
228ŌåÆ    })
229ŌåÆ    .with({ type: "client_connected" }, (f) => {
230ŌåÆ      const device = validateDeviceToken(f.deviceToken);
231ŌåÆ      if (device) {
232ŌåÆ        // Clean up existing connection (idempotent on tunnel reconnect)
233ŌåÆ        const existingConnId = clientToConn.get(f.clientId);
234ŌåÆ        if (existingConnId) {
235ŌåÆ          removeQuerySubs(existingConnId);
236ŌåÆ          removeConnection(existingConnId);
237ŌåÆ        }
238ŌåÆ
239ŌåÆ        // Virtual WsSendable routes data back through the relay tunnel
240ŌåÆ        const virtualWs: WsSendable = {
241ŌåÆ          send(data: string | ArrayBuffer) {
242ŌåÆ            const payload =
243ŌåÆ              typeof data === "string" ? data : new TextDecoder().decode(data as ArrayBuffer);
244ŌåÆ            sendToRelay({ type: "data", clientId: f.clientId, payload });
245ŌåÆ          },
246ŌåÆ          close() {
247ŌåÆ            // No-op ŌĆö relay manages client disconnect
248ŌåÆ          },
249ŌåÆ        };
250ŌåÆ        const connId = addConnection(virtualWs, device.id, true);
251ŌåÆ        linkClient(f.clientId, connId);
252ŌåÆ        sendToRelay({ type: "auth_response", clientId: f.clientId, allowed: true });
253ŌåÆ        console.log(`[Relay] Client ${f.clientId} authenticated as device ${device.name}`);
254ŌåÆ      } else {
255ŌåÆ        sendToRelay({
256ŌåÆ          type: "auth_response",
257ŌåÆ          clientId: f.clientId,
258ŌåÆ          allowed: false,
259ŌåÆ          reason: "Invalid device token",
260ŌåÆ        });
261ŌåÆ        console.log(`[Relay] Client ${f.clientId} auth rejected`);
262ŌåÆ      }
263ŌåÆ    })
264ŌåÆ    .with({ type: "client_disconnected" }, (f) => {
265ŌåÆ      const connId = unlinkClient(f.clientId);
266ŌåÆ      if (connId) {
267ŌåÆ        removeQuerySubs(connId);
268ŌåÆ        removeConnection(connId);
269ŌåÆ        console.log(`[Relay] Client ${f.clientId} disconnected`);
270ŌåÆ      }
271ŌåÆ    })
272ŌåÆ    .with({ type: "data" }, (f) => {
273ŌåÆ      const connId = clientToConn.get(f.clientId);
274ŌåÆ      if (!connId) return;
275ŌåÆ      if (!getConnection(connId)) return;
276ŌåÆ
277ŌåÆ      try {
278ŌåÆ        const msg = JSON.parse(f.payload) as Record<string, unknown>;
279ŌåÆ        // Unified protocol handler ŌĆö same as local WS clients
280ŌåÆ        handleProtocolMessage(connId, msg);
281ŌåÆ      } catch {
282ŌåÆ        // Ignore malformed inner messages
283ŌåÆ      }
284ŌåÆ    })
285ŌåÆ    .with({ type: "pair_request" }, (f) => {
286ŌåÆ      handlePairRequest(f.pairId, f.code, f.deviceName);
287ŌåÆ    })
288ŌåÆ    .with({ type: "ping" }, () => {
289ŌåÆ      sendToRelay({ type: "pong" });
290ŌåÆ    })
291ŌåÆ    .with({ type: "error" }, (f) => {
292ŌåÆ      console.error(`[Relay] Error from relay: ${f.message}`);
293ŌåÆ    })
294ŌåÆ    .exhaustive();
295ŌåÆ}
296ŌåÆ
297ŌåÆ// ---- Pairing ----
298ŌåÆ
299ŌåÆfunction handlePairRequest(pairId: string, code: string, deviceName: string): void {
300ŌåÆ  if (!validatePairCode(code)) {
301ŌåÆ    sendToRelay({
302ŌåÆ      type: "pair_response",
303ŌåÆ      pairId,
304ŌåÆ      success: false,
305ŌåÆ      reason: "Invalid or expired pairing code",
306ŌåÆ    });
307ŌåÆ    console.log(`[Relay] Pair request ${pairId} rejected: invalid code`);
308ŌåÆ    return;
309ŌåÆ  }
310ŌåÆ
311ŌåÆ  const { token } = createDeviceToken(deviceName || "Web Portal", null, "relay-paired");
312ŌåÆ  sendToRelay({ type: "pair_response", pairId, success: true, deviceToken: token });
313ŌåÆ  console.log(`[Relay] Pair request ${pairId} succeeded, device "${deviceName}" paired`);
314ŌåÆ}
315ŌåÆ
316ŌåÆ// ---- Helpers ----
317ŌåÆ
318ŌåÆfunction sendToRelay(frame: ServerFrame): void {
319ŌåÆ  if (tunnelWs?.readyState === WebSocket.OPEN) {
320ŌåÆ    try {
321ŌåÆ      tunnelWs.send(JSON.stringify(frame));
322ŌåÆ    } catch {
323ŌåÆ      // Will be handled by close/error handlers
324ŌåÆ    }
325ŌåÆ  }
326ŌåÆ}
327ŌåÆ
328ŌåÆfunction scheduleReconnect(): void {
329ŌåÆ  if (reconnectTimer) return;
330ŌåÆ  const delay = Math.min(BASE_RECONNECT_DELAY * 2 ** reconnectAttempt, MAX_RECONNECT_DELAY);
331ŌåÆ  reconnectAttempt++;
332ŌåÆ  console.log(`[Relay] Reconnecting in ${delay}ms (attempt ${reconnectAttempt})...`);
333ŌåÆ  reconnectTimer = setTimeout(() => {
334ŌåÆ    reconnectTimer = null;
335ŌåÆ    openTunnel();
336ŌåÆ  }, delay);
337ŌåÆ}
