 5ŌåÆ
 6ŌåÆ// Co-locate with deus.db in the Electron app data directory.
 7ŌåÆ// Derived from DB_PATH so tests that set DATABASE_PATH get sandboxing for free.
 8ŌåÆconst PREFS_PATH = path.join(path.dirname(DB_PATH), "preferences.json");
 9ŌåÆ
10ŌåÆfunction readPreferences(): Record<string, any> {
11ŌåÆ  if (!fs.existsSync(PREFS_PATH)) {
12ŌåÆ    return {};
13ŌåÆ  }
14ŌåÆ
15ŌåÆ  try {
16ŌåÆ    const raw = JSON.parse(fs.readFileSync(PREFS_PATH, "utf8"));
17ŌåÆ    const parsed = PreferencesFile.safeParse(raw);
18ŌåÆ    if (!parsed.success) {
19ŌåÆ      console.error("[settings] Invalid preferences.json, returning raw:", parsed.error.issues);
20ŌåÆ      return typeof raw === "object" && raw !== null && !Array.isArray(raw) ? raw : {};
21ŌåÆ    }
22ŌåÆ    return parsed.data;
23ŌåÆ  } catch (error) {
24ŌåÆ    console.error("[settings] Error reading preferences.json:", error);
25ŌåÆ    return {};
26ŌåÆ  }
