28ŌåÆ
29ŌåÆfunction writePreferences(settings: Record<string, any>): void {
30ŌåÆ  const dir = path.dirname(PREFS_PATH);
31ŌåÆ  if (!fs.existsSync(dir)) {
32ŌåÆ    fs.mkdirSync(dir, { recursive: true });
33ŌåÆ  }
34ŌåÆ
35ŌåÆ  // Atomic write: write to temp file, then rename
36ŌåÆ  const tmpPath = PREFS_PATH + ".tmp";
37ŌåÆ  fs.writeFileSync(tmpPath, JSON.stringify(settings, null, 2));
38ŌåÆ  fs.renameSync(tmpPath, PREFS_PATH);
39ŌåÆ}
