41ŌåÆexport function getAllSettings(): Record<string, any> {
42ŌåÆ  return readPreferences();
43ŌåÆ}
44ŌåÆ
45ŌåÆ/** Get a single setting value by key. Returns the parsed value or null. */
46ŌåÆexport function getSetting(key: string): any {
47ŌåÆ  const prefs = readPreferences();
48ŌåÆ  return key in prefs ? prefs[key] : null;
49ŌåÆ}
50ŌåÆ
51ŌåÆexport function saveSetting(key: string, value: any): void {
52ŌåÆ  const current = readPreferences();
53ŌåÆ  // Guard against readPreferences returning a non-object (e.g. if Zod fails and raw is an array/string)
54ŌåÆ  const obj =
55ŌåÆ    typeof current === "object" && current !== null && !Array.isArray(current) ? current : {};
56ŌåÆ  obj[key] = value;
57ŌåÆ  writePreferences(obj);
58ŌåÆ}
